import React, { useState, useEffect } from 'react';
import { Question, QuizSession } from '../types';
import { MARKING_SCHEME } from '../constants';

interface QuizEngineProps {
  session: QuizSession;
  onComplete: (session: QuizSession) => void;
  onExit: () => void;
  isReview?: boolean;
}

const QuizEngine: React.FC<QuizEngineProps> = ({ session, onComplete, onExit, isReview = false }) => {
  const [currentIdx, setCurrentIdx] = useState(0);
  const [answers, setAnswers] = useState<Record<string, 'A' | 'B' | 'C' | 'D' | 'E' | null>>(session.userAnswers);
  const [timeLeft, setTimeLeft] = useState(session.durationInMinutes * 60);

  useEffect(() => {
    if (isReview) return;
    if (timeLeft <= 0) {
      handleSubmit();
      return;
    }
    const timer = setInterval(() => {
      setTimeLeft(prev => prev - 1);
    }, 1000);
    return () => clearInterval(timer);
  }, [timeLeft, isReview]);

  const handleSubmit = () => {
    onComplete({
      ...session,
      userAnswers: answers,
      completed: true
    });
  };

  const handleBackClick = () => {
    if (isReview) {
      onExit();
      return;
    }
    if (window.confirm("क्या आप टेस्ट से बाहर निकलना चाहते हैं? आपका वर्तमान प्रोग्रेस खो सकता है। (Are you sure you want to exit? Your progress may be lost.)")) {
      onExit();
    }
  };

  const handleSelect = (option: 'A' | 'B' | 'C' | 'D' | 'E') => {
    if (isReview) return;
    const qId = session.questions[currentIdx].id;
    setAnswers(prev => ({ ...prev, [qId]: option }));
  };

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m}:${s.toString().padStart(2, '0')}`;
  };

  const currentQ = session.questions[currentIdx];
  const userAns = answers[currentQ.id];

  return (
    <div className="flex flex-col lg:flex-row gap-6 max-w-[1400px] mx-auto animate-fadeIn">
      {/* Main Content Area */}
      <div className="flex-grow">
        <div className="glass sticky top-16 md:top-20 z-40 px-3 md:px-4 py-2 md:py-3 rounded-xl md:rounded-2xl shadow-sm border border-slate-200 mb-4 md:mb-6 flex items-center justify-between gap-2">
          <div className="flex items-center gap-2 md:gap-4">
            <button 
              onClick={handleBackClick}
              className="flex items-center gap-1.5 text-slate-500 hover:text-blue-600 font-bold transition-colors text-xs uppercase tracking-wider group"
            >
              <svg className="w-4 h-4 group-hover:-translate-x-1 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" />
              </svg>
              <span>Back</span>
            </button>
            <div className="h-4 w-px bg-slate-200"></div>
            <span className="bg-slate-100 text-slate-600 px-2 md:px-3 py-1 rounded-full font-bold text-[10px] md:text-xs whitespace-nowrap">
              Q {currentIdx + 1} / {session.questions.length}
            </span>
            {!isReview && (
              <div className={`flex items-center gap-1 font-mono text-base md:text-lg font-bold ${timeLeft < 120 ? 'text-rose-600 animate-pulse' : 'text-slate-700'}`}>
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                {formatTime(timeLeft)}
              </div>
            )}
            {isReview && (
              <span className="bg-amber-100 text-amber-700 px-2 md:px-3 py-1 rounded-full font-bold text-[10px] md:text-xs border border-amber-200">
                REVIEW
              </span>
            )}
          </div>

          <div className="flex gap-2">
             {isReview ? (
               <button onClick={onExit} className="bg-slate-800 text-white px-3 md:px-4 py-1 md:py-1.5 rounded-lg font-bold text-xs md:text-sm hover:bg-slate-900 transition-all">Exit Review</button>
             ) : (
               <button onClick={handleSubmit} className="bg-emerald-600 text-white px-3 md:px-4 py-1 md:py-1.5 rounded-lg font-bold text-xs md:text-sm hover:bg-emerald-700 transition-all shadow-md shadow-emerald-100">Submit Test</button>
             )}
          </div>
        </div>

        <div className="bg-white rounded-2xl md:rounded-3xl shadow-xl border border-slate-200 p-6 md:p-12 mb-6">
          <div className="flex flex-wrap items-center gap-2 md:gap-3 mb-6 md:mb-8">
            <span className="bg-blue-50 text-blue-700 text-[10px] md:text-xs font-extrabold px-2 md:px-3 py-1 md:py-1.5 rounded-md uppercase tracking-wider border border-blue-100">
              {currentQ.examName} • {currentQ.examYear}
            </span>
            <span className="bg-slate-50 text-slate-500 text-[10px] md:text-xs font-bold px-2 md:px-3 py-1 md:py-1.5 rounded-md border border-slate-100 uppercase">
              {currentQ.subject}
            </span>
          </div>

          <h2 className="text-xl md:text-3xl font-bold text-slate-900 mb-8 md:mb-10 leading-relaxed hindi-text">
            {currentQ.question}
          </h2>

          <div className="space-y-3 md:space-y-4">
            {(['A', 'B', 'C', 'D', 'E'] as const).map((key) => {
              const isSelected = userAns === key;
              const isCorrect = key === currentQ.correctAnswer;
              const isE = key === 'E';

              let bgColor = 'bg-white';
              let borderColor = 'border-slate-100';
              let iconColor = 'bg-slate-100 text-slate-400';

              if (isReview) {
                if (isCorrect) {
                  bgColor = 'bg-emerald-50';
                  borderColor = 'border-emerald-500';
                  iconColor = 'bg-emerald-500 text-white';
                } else if (isSelected && !isCorrect) {
                  bgColor = 'bg-rose-50';
                  borderColor = 'border-rose-500';
                  iconColor = 'bg-rose-500 text-white';
                }
              } else if (isSelected) {
                bgColor = 'bg-blue-50';
                borderColor = 'border-blue-600';
                iconColor = 'bg-blue-600 text-white';
              }

              return (
                <button
                  key={key}
                  disabled={isReview}
                  onClick={() => handleSelect(key)}
                  className={`group w-full flex items-center p-3 md:p-5 rounded-xl md:rounded-2xl border-2 transition-all text-left ${bgColor} ${borderColor} ${!isReview && 'hover:border-blue-200 hover:bg-slate-50'}`}
                >
                  <div className={`w-8 h-8 md:w-10 md:h-10 rounded-lg md:rounded-xl flex items-center justify-center font-bold mr-3 md:mr-5 transition-colors shrink-0 text-sm md:text-base ${iconColor}`}>
                    {key}
                  </div>
                  <div className="flex-grow">
                     <span className={`text-base md:text-lg font-semibold ${isSelected ? 'text-blue-900' : 'text-slate-700'} ${isE ? 'text-xs md:text-sm italic opacity-60' : 'hindi-text'}`}>
                        {currentQ.options[key]}
                     </span>
                  </div>
                  {isReview && isCorrect && (
                    <div className="text-emerald-600">
                      <svg className="w-5 h-5 md:w-6 md:h-6" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" /></svg>
                    </div>
                  )}
                  {isReview && isSelected && !isCorrect && (
                    <div className="text-rose-600">
                      <svg className="w-5 h-5 md:w-6 md:h-6" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" /></svg>
                    </div>
                  )}
                </button>
              );
            })}
          </div>
        </div>

        <div className="flex justify-between items-center bg-white p-3 md:p-4 rounded-xl md:rounded-2xl shadow-sm border border-slate-200">
          <button
            disabled={currentIdx === 0}
            onClick={() => setCurrentIdx(prev => prev - 1)}
            className="px-4 md:px-6 py-2 md:py-3 rounded-lg md:rounded-xl font-bold border-2 border-slate-200 text-slate-600 disabled:opacity-30 disabled:cursor-not-allowed hover:bg-slate-50 transition-all text-xs md:text-sm flex items-center gap-2"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" /></svg>
            Previous
          </button>

          <div className="hidden sm:flex gap-1">
             {session.questions.map((_, idx) => (
                <div key={idx} className={`w-1.5 h-1.5 rounded-full ${idx === currentIdx ? 'bg-blue-600' : 'bg-slate-200'}`}></div>
             ))}
          </div>

          <button
            onClick={() => {
              if (currentIdx < session.questions.length - 1) {
                setCurrentIdx(prev => prev + 1);
              } else if (!isReview) {
                handleSubmit();
              } else {
                onExit();
              }
            }}
            className="px-4 md:px-6 py-2 md:py-3 rounded-lg md:rounded-xl font-bold bg-slate-900 text-white hover:bg-blue-900 transition-all text-xs md:text-sm flex items-center gap-2"
          >
            {currentIdx === session.questions.length - 1 ? (isReview ? 'Exit' : 'Submit') : 'Next'}
            {currentIdx !== session.questions.length - 1 && <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" /></svg>}
          </button>
        </div>
      </div>

      {/* Question Palette Sidebar */}
      <div className="w-full lg:w-80 shrink-0">
        <div className="bg-white rounded-3xl p-6 border border-slate-200 sticky top-24">
          <h3 className="text-sm font-black text-slate-900 mb-4 uppercase tracking-wider">Question Navigator</h3>
          <div className="grid grid-cols-5 gap-2 max-h-[400px] overflow-y-auto pr-2 custom-scrollbar">
            {session.questions.map((q, idx) => {
              const isAnswered = !!answers[q.id];
              const isCurrent = idx === currentIdx;

              let statusColor = 'bg-slate-50 text-slate-400 border-slate-100';
              if (isCurrent) {
                statusColor = 'bg-blue-100 text-blue-700 border-blue-500';
              } else if (isAnswered) {
                statusColor = 'bg-emerald-100 text-emerald-700 border-emerald-500';
              }

              return (
                <button
                  key={idx}
                  onClick={() => setCurrentIdx(idx)}
                  className={`aspect-square rounded-lg border-2 flex items-center justify-center font-bold text-xs transition-all ${statusColor}`}
                >
                  {idx + 1}
                </button>
              );
            })}
          </div>

          <div className="mt-8 space-y-2">
             <div className="flex items-center gap-2 text-[10px] font-bold text-slate-500 uppercase">
                <div className="w-3 h-3 bg-emerald-100 border border-emerald-500 rounded"></div> Answered
             </div>
             <div className="flex items-center gap-2 text-[10px] font-bold text-slate-500 uppercase">
                <div className="w-3 h-3 bg-blue-100 border border-blue-500 rounded"></div> Current
             </div>
             <div className="flex items-center gap-2 text-[10px] font-bold text-slate-500 uppercase">
                <div className="w-3 h-3 bg-slate-50 border border-slate-100 rounded"></div> Not Visited
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default QuizEngine;

import React, { useState, useEffect, useCallback } from 'react';
import Layout from './components/Layout';
import QuizEngine from './components/QuizEngine';
import ScoreCard from './components/ScoreCard';
import { 
  AppView, 
  QuizSession, 
  QuizType, 
  QuizResults 
} from './types';
import { 
  TOPIC_GROUPS,
  TopicGroup,
  MARKING_SCHEME 
} from './constants';
import { fetchPYQs } from './services/geminiService';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.HOME);
  const [prevView, setPrevView] = useState<AppView>(AppView.HOME);
  const [activeSession, setActiveSession] = useState<QuizSession | null>(null);
  const [lastResults, setLastResults] = useState<QuizResults | null>(null);
  const [loading, setLoading] = useState(false);
  const [mixTestsPage, setMixTestsPage] = useState(1);
  const [selectedGroup, setSelectedGroup] = useState<TopicGroup | null>(null);
  const [completedTests, setCompletedTests] = useState<Set<string>>(new Set());
  const testsPerPage = 40;

  const navigateTo = (newView: AppView) => {
    setPrevView(view);
    setView(newView);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  useEffect(() => {
    const saved = localStorage.getItem('rajgkquiz_progress');
    if (saved) {
      try {
        setCompletedTests(new Set(JSON.parse(saved)));
      } catch (e) { console.error("Load fail", e); }
    }
  }, []);

  const markTestCompleted = (testId: string) => {
    setCompletedTests(prev => {
      const newSet = new Set(prev);
      newSet.add(testId);
      localStorage.setItem('rajgkquiz_progress', JSON.stringify(Array.from(newSet)));
      return newSet;
    });
  };

  const startQuiz = useCallback(async (type: QuizType, title: string, options: { 
    subject?: string; 
    topic?: string; 
    count?: number; 
    staticQs?: any[];
    testId?: string;
    testNumber?: number;
    examContext?: string;
  } = {}) => {
    const finalTestId = options.testId || `${type}-${options.topic || title}-${options.testNumber || 1}-${Date.now()}`;

    setLoading(true);
    try {
      const questions = await fetchPYQs({
        count: options.count || 25,
        subject: options.subject,
        topic: options.topic,
        isMix: type === QuizType.MIX || type === QuizType.AI,
        testNumber: options.testNumber,
        examContext: options.examContext
      });

      if (!questions || questions.length === 0) throw new Error("Empty pool");

      const session: QuizSession = {
        type,
        title: `${title} ${options.testNumber ? `- Test ${options.testNumber}` : ''}`,
        questions,
        currentQuestionIndex: 0,
        userAnswers: {},
        startTime: Date.now(),
        durationInMinutes: type === QuizType.AI ? 15 : (options.count && options.count > 50 ? 120 : 60),
        completed: false
      };

      (session as any).testId = finalTestId;
      setActiveSession(session);
      navigateTo(AppView.QUIZ_ACTIVE);
    } catch (error) {
      alert("Official database connection failed. Please check your internet and retry.");
    } finally {
      setLoading(false);
    }
  }, []);

  const onQuizComplete = (session: QuizSession) => {
    let score = 0, correct = 0, incorrect = 0, skipped = 0, unattempted = 0;
    session.questions.forEach(q => {
      const ans = session.userAnswers[q.id];
      if (!ans) { 
        score += MARKING_SCHEME.UNATTEMPTED; 
        unattempted++; 
      }
      else if (ans === 'E') {
        skipped++; 
      }
      else if (ans === q.correctAnswer) { 
        score += MARKING_SCHEME.CORRECT; 
        correct++; 
      }
      else { 
        score += MARKING_SCHEME.WRONG; 
        incorrect++; 
      }
    });

    setLastResults({ 
      score, 
      correctCount: correct, 
      incorrectCount: incorrect, 
      skippedCount: skipped, 
      unattemptedCount: unattempted, 
      totalQuestions: session.questions.length, 
      timeTaken: 'N/A', 
      session 
    });

    const tId = (session as any).testId;
    if (tId) markTestCompleted(tId);
    navigateTo(AppView.SCORECARD);
  };

  const renderHome = () => (
    <div className="animate-fadeIn max-w-6xl mx-auto space-y-12">
      <section className="text-center space-y-4">
        <h1 className="text-4xl md:text-6xl font-black text-slate-900 tracking-tight">
          Target <span className="text-blue-600">RSSB & RPSC</span> Exams
        </h1>
        <p className="text-slate-500 text-lg md:text-xl max-w-2xl mx-auto">
          Practice with 10,000+ real Previous Year Questions from 2015-2026. Official marking scheme included.
        </p>
      </section>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        <div onClick={() => navigateTo(AppView.QUIZ_MIX_MENU)} className="group bg-white p-8 rounded-3xl border border-slate-200 shadow-sm hover:shadow-xl hover:-translate-y-1 transition-all cursor-pointer">
          <div className="w-14 h-14 bg-indigo-50 text-indigo-600 rounded-2xl flex items-center justify-center mb-6 group-hover:scale-110 transition-transform">
            <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" /></svg>
          </div>
          <h3 className="text-2xl font-black text-slate-900 mb-2">Mixed Mock Tests</h3>
          <p className="text-slate-500 mb-6">40 Full-length mix subjects practice sets from recent RSSB papers.</p>
          <div className="text-blue-600 font-bold flex items-center gap-2 group-hover:gap-4 transition-all uppercase text-sm tracking-wider">
            Start Practice <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 7l5 5m0 0l-5 5m5-5H6" /></svg>
          </div>
        </div>

        <div onClick={() => navigateTo(AppView.QUIZ_TOPIC_MENU)} className="group bg-white p-8 rounded-3xl border border-slate-200 shadow-sm hover:shadow-xl hover:-translate-y-1 transition-all cursor-pointer">
          <div className="w-14 h-14 bg-emerald-50 text-emerald-600 rounded-2xl flex items-center justify-center mb-6 group-hover:scale-110 transition-transform">
            <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2" /></svg>
          </div>
          <h3 className="text-2xl font-black text-slate-900 mb-2">Topic-wise PYQs</h3>
          <p className="text-slate-500 mb-6">Master specific sections like History, Geography, Culture & Polity.</p>
          <div className="text-emerald-600 font-bold flex items-center gap-2 group-hover:gap-4 transition-all uppercase text-sm tracking-wider">
            Explore Topics <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 7l5 5m0 0l-5 5m5-5H6" /></svg>
          </div>
        </div>

        <div onClick={() => navigateTo(AppView.EXAM_MENU)} className="group bg-blue-900 p-8 rounded-3xl shadow-xl hover:-translate-y-1 transition-all cursor-pointer text-white">
          <div className="w-14 h-14 bg-white/10 text-white rounded-2xl flex items-center justify-center mb-6 group-hover:scale-110 transition-transform">
            <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 14l9-5-9-5-9 5 9 5z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 14l6.16-3.422a12.083 12.083 0 01.665 6.479A11.952 11.952 0 0012 20.055a11.952 11.952 0 00-6.824-2.998 12.078 12.078 0 01.665-6.479L12 14z" /></svg>
          </div>
          <h3 className="text-2xl font-black mb-2">Exam Portal</h3>
          <p className="text-blue-200 mb-6">Access official full papers: Lab Assistant, CET, RAS, and more.</p>
          <div className="text-amber-400 font-bold flex items-center gap-2 group-hover:gap-4 transition-all uppercase text-sm tracking-wider">
            View Exams <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 7l5 5m0 0l-5 5m5-5H6" /></svg>
          </div>
        </div>
      </div>

      <div className="bg-amber-50 rounded-[2.5rem] p-8 md:p-12 border border-amber-100 flex flex-col md:flex-row items-center gap-8 md:gap-16">
        <div className="shrink-0 relative">
           <div className="absolute -inset-4 bg-amber-200 rounded-full blur-2xl opacity-40 animate-pulse"></div>
           <img src="https://images.unsplash.com/photo-1517842645767-c639042777db?auto=format&fit=crop&q=80&w=200&h=200" className="relative w-48 h-48 rounded-full border-8 border-white object-cover shadow-xl" alt="Lab Assistant" />
        </div>
        <div>
          <span className="bg-amber-600 text-white px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest mb-4 inline-block">Specialized Pack</span>
          <h2 className="text-3xl md:text-5xl font-black text-slate-900 mb-4">Lab Assistant 2022</h2>
          <p className="text-slate-600 text-lg mb-8 leading-relaxed">
            Direct access to official 2022 papers. We have cataloged both <strong className="text-slate-900">General Knowledge (Paper 1)</strong> and <strong className="text-slate-900">Science (Paper 2)</strong>. Practice exactly as the exam was held.
          </p>
          <div className="flex flex-wrap gap-4">
             <button onClick={() => startQuiz(QuizType.EXAM, "Lab Assistant 2022 - GK", { examContext: "Lab Assistant 2022 Paper 1 (GK)", count: 100 })} className="bg-slate-900 text-white px-6 py-3 rounded-xl font-bold hover:bg-blue-900 transition-all">GK Paper 1</button>
             <button onClick={() => startQuiz(QuizType.EXAM, "Lab Assistant 2022 - Science", { examContext: "Lab Assistant 2022 Paper 2 (Science)", count: 100 })} className="bg-white text-slate-900 border-2 border-slate-900 px-6 py-3 rounded-xl font-bold hover:bg-slate-50 transition-all">Science Paper 2</button>
          </div>
        </div>
      </div>
    </div>
  );

  const renderMixMenu = () => (
    <div className="animate-fadeIn">
      <div className="flex items-center gap-4 mb-12">
        <button onClick={() => navigateTo(AppView.HOME)} className="p-3 bg-white border border-slate-200 rounded-2xl hover:bg-slate-50 transition-all text-slate-500">
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" /></svg>
        </button>
        <div>
          <h2 className="text-3xl font-black text-slate-900">Mix Subjects Mock</h2>
          <p className="text-slate-500 font-medium">Full Syllabus Practice (Set 1-40)</p>
        </div>
      </div>

      <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4">
        {Array.from({ length: testsPerPage }).map((_, i) => {
          const testNum = i + 1;
          const testId = `mix-test-${testNum}`;
          const isDone = completedTests.has(testId);
          return (
            <button
              key={testNum}
              onClick={() => startQuiz(QuizType.MIX, "Mixed Subjects", { testNumber: testNum, testId, count: 25 })}
              className={`group p-6 rounded-3xl border-2 transition-all text-center relative overflow-hidden ${isDone ? 'bg-emerald-50 border-emerald-100 text-emerald-900' : 'bg-white border-slate-100 hover:border-blue-600 hover:shadow-xl'}`}
            >
              {isDone && (
                <div className="absolute top-2 right-2 text-emerald-500">
                  <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" /></svg>
                </div>
              )}
              <span className="text-xs font-black uppercase tracking-widest block mb-2 opacity-50">Set</span>
              <span className="text-4xl font-black block group-hover:scale-110 transition-transform">{testNum}</span>
              <div className={`mt-4 text-[10px] font-bold uppercase tracking-widest ${isDone ? 'text-emerald-600' : 'text-slate-400 group-hover:text-blue-600'}`}>
                {isDone ? 'Revision Mode' : 'Start Test'}
              </div>
            </button>
          );
        })}
      </div>
    </div>
  );

  const renderTopicMenu = () => (
    <div className="animate-fadeIn space-y-8">
      <div className="flex items-center gap-4 mb-4">
        <button onClick={() => navigateTo(AppView.HOME)} className="p-3 bg-white border border-slate-200 rounded-2xl text-slate-500">
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" /></svg>
        </button>
        <div>
          <h2 className="text-3xl font-black text-slate-900">Topic-wise PYQs</h2>
          <p className="text-slate-500">Official questions categorized by subject matter.</p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {TOPIC_GROUPS.map((group) => (
          <div key={group.id} className="bg-white rounded-3xl border border-slate-200 p-8 hover:shadow-lg transition-all">
            <h3 className="text-2xl font-black text-slate-900 mb-6 flex items-center justify-between">
              {group.name}
              <span className="text-xs bg-slate-100 text-slate-500 px-3 py-1 rounded-full">{group.subtopics.length} Units</span>
            </h3>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
              {group.subtopics.slice(0, 6).map((sub, i) => (
                <button 
                  key={i} 
                  onClick={() => startQuiz(QuizType.TOPIC, sub, { topic: sub, count: 20 })}
                  className="text-left text-sm font-semibold p-3 rounded-xl border border-transparent hover:border-emerald-200 hover:bg-emerald-50 text-slate-600 hover:text-emerald-700 transition-all hindi-text"
                >
                  {sub}
                </button>
              ))}
            </div>
            {group.subtopics.length > 6 && (
               <button 
                onClick={() => { setSelectedGroup(group); navigateTo(AppView.QUIZ_SUBTOPIC_MENU); }}
                className="mt-6 w-full py-3 rounded-xl bg-slate-50 text-slate-500 font-bold hover:bg-slate-100 transition-all text-sm uppercase tracking-wider"
               >
                 View All {group.subtopics.length} Units
               </button>
            )}
          </div>
        ))}
      </div>
    </div>
  );

  const renderSubtopicMenu = () => (
    <div className="animate-fadeIn max-w-4xl mx-auto">
      <div className="flex items-center gap-4 mb-12">
        <button onClick={() => navigateTo(AppView.QUIZ_TOPIC_MENU)} className="p-3 bg-white border border-slate-200 rounded-2xl text-slate-500">
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" /></svg>
        </button>
        <div>
          <h2 className="text-3xl font-black text-slate-900">{selectedGroup?.name}</h2>
          <p className="text-slate-500">Select a specific unit for practice.</p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {selectedGroup?.subtopics.map((sub, i) => (
          <button
            key={i}
            onClick={() => startQuiz(QuizType.TOPIC, sub, { topic: sub, count: 25 })}
            className="flex items-center justify-between p-6 bg-white border border-slate-200 rounded-3xl hover:border-blue-600 hover:bg-blue-50/50 transition-all text-left"
          >
            <span className="font-bold text-slate-800 text-lg hindi-text">{sub}</span>
            <div className="bg-white p-2 rounded-lg border border-slate-100 text-blue-600 group-hover:scale-110">
               <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>
            </div>
          </button>
        ))}
      </div>
    </div>
  );

  const renderExamMenu = () => (
    <div className="animate-fadeIn space-y-12">
      <div className="flex items-center gap-4 mb-4">
        <button onClick={() => navigateTo(AppView.HOME)} className="p-3 bg-white border border-slate-200 rounded-2xl text-slate-500">
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" /></svg>
        </button>
        <div>
          <h2 className="text-3xl font-black text-slate-900">Official Exam Portal</h2>
          <p className="text-slate-500">Complete papers as conducted by RSSB and RPSC.</p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {[
          { name: "RSSB CET Graduate Level", year: 2024, context: "CET Graduate Level 2024" },
          { name: "RSSB CET Senior Secondary", year: 2024, context: "CET Senior Secondary 2024" },
          { name: "RSSB LDC Exam", year: 2024, context: "LDC 2024 Exam" },
          { name: "RPSC RAS Prelims", year: 2023, context: "RAS Prelims 2023" },
          { name: "Lab Assistant (GK)", year: 2022, context: "Lab Assistant 2022 GK Paper" },
          { name: "Lab Assistant (Science)", year: 2022, context: "Lab Assistant 2022 Science Paper" },
          { name: "RSSB Patwar Exam", year: 2021, context: "Patwar 2021 Exam" },
          { name: "RSSB REET Exam L-1", year: 2023, context: "REET 2023 Level 1" },
          { name: "RSSB Junior Accountant", year: 2024, context: "Junior Accountant 2024" }
        ].map((exam, i) => (
          <div key={i} className="bg-white rounded-[2rem] border border-slate-200 p-8 hover:shadow-2xl transition-all group">
            <div className="text-[10px] font-black uppercase tracking-widest text-slate-400 mb-2">{exam.year} Edition</div>
            <h3 className="text-2xl font-black text-slate-900 mb-6 group-hover:text-blue-600 transition-colors">{exam.name}</h3>
            <button 
              onClick={() => startQuiz(QuizType.EXAM, exam.name, { examContext: exam.context, count: 100 })}
              className="w-full py-4 bg-slate-900 text-white rounded-2xl font-extrabold hover:bg-blue-600 transition-all flex items-center justify-center gap-2"
            >
              Start Official Mock
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14 5l7 7m0 0l-7 7m7-7H3" /></svg>
            </button>
          </div>
        ))}
      </div>
    </div>
  );

  return (
    <Layout onHomeClick={() => navigateTo(AppView.HOME)}>
      {loading ? (
        <div className="flex flex-col items-center justify-center min-h-[60vh] animate-pulse">
          <div className="w-20 h-20 border-8 border-blue-600 border-t-transparent rounded-full animate-spin mb-8"></div>
          <h2 className="text-2xl font-black text-slate-900 mb-2">Connecting to Official Database...</h2>
          <p className="text-slate-500 font-medium">Fetching authentic PYQs and setting up marking scheme.</p>
        </div>
      ) : (
        <>
          {view === AppView.HOME && renderHome()}
          {view === AppView.QUIZ_MIX_MENU && renderMixMenu()}
          {view === AppView.QUIZ_TOPIC_MENU && renderTopicMenu()}
          {view === AppView.QUIZ_SUBTOPIC_MENU && renderSubtopicMenu()}
          {view === AppView.EXAM_MENU && renderExamMenu()}

          {view === AppView.QUIZ_ACTIVE && activeSession && (
            <QuizEngine 
              session={activeSession} 
              onComplete={onQuizComplete}
              onExit={() => navigateTo(AppView.HOME)}
            />
          )}

          {view === AppView.SCORECARD && lastResults && (
            <ScoreCard 
              results={lastResults} 
              onReview={() => navigateTo(AppView.REVIEW)}
              onNextTest={() => navigateTo(AppView.HOME)}
              onBackHome={() => navigateTo(AppView.HOME)}
            />
          )}

          {view === AppView.REVIEW && lastResults && (
            <QuizEngine 
              session={lastResults.session} 
              onComplete={() => {}}
              onExit={() => navigateTo(AppView.SCORECARD)}
              isReview={true}
            />
          )}
        </>
      )}
    </Layout>
  );
};

export default App;

export enum AppView {
  AUTH = 'auth',
  HOME = 'home',
  QUIZ_MENU = 'quiz_menu',
  QUIZ_MIX_MENU = 'quiz_mix_menu',
  QUIZ_TOPIC_MENU = 'quiz_topic_menu',
  QUIZ_SUBTOPIC_MENU = 'quiz_subtopic_menu',
  EXAM_MENU = 'exam_menu',
  AI_TEST = 'ai_test',
  QUIZ_ACTIVE = 'quiz_active',
  SCORECARD = 'scorecard',
  REVIEW = 'review'
}

export enum QuizType {
  MIX = 'mix',
  TOPIC = 'topic',
  EXAM = 'exam',
  AI = 'ai'
}

export interface Question {
  id: string;
  question: string;
  options: {
    A: string;
    B: string;
    C: string;
    D: string;
    E: string;
  };
  correctAnswer: 'A' | 'B' | 'C' | 'D' | 'E';
  examName: string;
  examYear: number;
  subject: string;
  topic?: string;
}

export interface QuizSession {
  type: QuizType;
  title: string;
  questions: Question[];
  currentQuestionIndex: number;
  userAnswers: Record<string, 'A' | 'B' | 'C' | 'D' | 'E' | null>;
  startTime: number;
  durationInMinutes: number;
  completed: boolean;
}

export interface QuizResults {
  score: number;
  correctCount: number;
  incorrectCount: number;
  skippedCount: number;
  unattemptedCount: number;
  totalQuestions: number;
  timeTaken: string;
  session: QuizSession;
}

import React, { useState, useEffect, useCallback } from 'react';
import Layout from './components/Layout';
import QuizEngine from './components/QuizEngine';
import ScoreCard from './components/ScoreCard';
import { 
  AppView, 
  QuizSession, 
  QuizType, 
  QuizResults 
} from './types';
import { 
  TOPIC_GROUPS,
  TopicGroup,
  MARKING_SCHEME 
} from './constants';
import { fetchPYQs } from './services/geminiService';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.AUTH);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [phone, setPhone] = useState('');
  const [password, setPassword] = useState('');
  const [activeSession, setActiveSession] = useState<QuizSession | null>(null);
  const [lastResults, setLastResults] = useState<QuizResults | null>(null);
  const [loading, setLoading] = useState(false);
  const [selectedGroup, setSelectedGroup] = useState<TopicGroup | null>(null);
  const [completedTests, setCompletedTests] = useState<Set<string>>(new Set());
  const testsPerPage = 40;

  // Initialize session and progress from localStorage
  useEffect(() => {
    const savedSession = localStorage.getItem('rajgkquiz_session');
    if (savedSession) {
      setIsLoggedIn(true);
      setView(AppView.HOME);
    }

    const savedProgress = localStorage.getItem('rajgkquiz_progress');
    if (savedProgress) {
      try {
        setCompletedTests(new Set(JSON.parse(savedProgress)));
      } catch (e) { 
        console.error("Failed to load progress", e); 
      }
    }
  }, []);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (phone.length === 10 && password.length >= 4) {
      localStorage.setItem('rajgkquiz_session', JSON.stringify({ phone }));
      setIsLoggedIn(true);
      setView(AppView.HOME);
    } else {
      alert("कृपया सही 10-अंकों का मोबाइल नंबर और कम से कम 4 अक्षरों का पासवर्ड डालें।");
    }
  };

  const handleLogout = () => {
    if (window.confirm("क्या आप लॉगआउट करना चाहते हैं?")) {
      localStorage.removeItem('rajgkquiz_session');
      setIsLoggedIn(false);
      setPhone('');
      setPassword('');
      setView(AppView.AUTH);
    }
  };

  const navigateTo = (newView: AppView) => {
    setView(newView);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const markTestCompleted = (testId: string) => {
    setCompletedTests(prev => {
      const newSet = new Set(prev);
      newSet.add(testId);
      localStorage.setItem('rajgkquiz_progress', JSON.stringify(Array.from(newSet)));
      return newSet;
    });
  };

  const startQuiz = useCallback(async (type: QuizType, title: string, options: { 
    subject?: string; 
    topic?: string; 
    count?: number; 
    testId?: string;
    testNumber?: number;
    examContext?: string;
  } = {}) => {
    // Generate unique ID for tracking progress if not provided
    const finalTestId = options.testId || `${type}-${(options.topic || title).replace(/\s+/g, '_')}-${options.testNumber || 0}`;

    setLoading(true);
    try {
      const questions = await fetchPYQs({
        count: options.count || 25,
        subject: options.subject,
        topic: options.topic,
        isMix: type === QuizType.MIX || type === QuizType.AI,
        testNumber: options.testNumber,
        examContext: options.examContext
      });

      if (!questions || questions.length === 0) throw new Error("Database pool empty");

      const session: QuizSession = {
        type,
        title: `${title} ${options.testNumber ? `- Test ${options.testNumber}` : ''}`,
        questions,
        currentQuestionIndex: 0,
        userAnswers: {},
        startTime: Date.now(),
        durationInMinutes: type === QuizType.AI ? 15 : (options.count && options.count > 50 ? 120 : 60),
        completed: false
      };

      // Store ID in session temporarily for completion marking
      (session as any).testId = finalTestId;
      setActiveSession(session);
      navigateTo(AppView.QUIZ_ACTIVE);
    } catch (error) {
      alert("सर्वर से जुड़ने में विफल। कृपया इंटरनेट चेक करें और पुनः प्रयास करें।");
    } finally {
      setLoading(false);
    }
  }, []);

  const onQuizComplete = (session: QuizSession) => {
    let score = 0, correct = 0, incorrect = 0, skipped = 0, unattempted = 0;
    session.questions.forEach(q => {
      const ans = session.userAnswers[q.id];
      if (!ans) { 
        score += MARKING_SCHEME.UNATTEMPTED; 
        unattempted++; 
      }
      else if (ans === 'E') {
        skipped++; 
      }
      else if (ans === q.correctAnswer) { 
        score += MARKING_SCHEME.CORRECT; 
        correct++; 
      }
      else { 
        score += MARKING_SCHEME.WRONG; 
        incorrect++; 
      }
    });

    setLastResults({ 
      score, 
      correctCount: correct, 
      incorrectCount: incorrect, 
      skippedCount: skipped, 
      unattemptedCount: unattempted, 
      totalQuestions: session.questions.length, 
      timeTaken: 'N/A', 
      session 
    });

    const tId = (session as any).testId;
    if (tId) markTestCompleted(tId);
    navigateTo(AppView.SCORECARD);
  };

  const renderAuth = () => (
    <div className="min-h-[70vh] flex items-center justify-center animate-fadeIn">
      <div className="bg-white p-8 md:p-12 rounded-[2.5rem] shadow-2xl border border-slate-100 w-full max-w-md">
        <div className="text-center mb-10">
          <div className="w-20 h-20 bg-blue-600 rounded-3xl flex items-center justify-center mx-auto mb-6 shadow-xl shadow-blue-100">
            <svg className="w-10 h-10 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" />
            </svg>
          </div>
          <h2 className="text-3xl font-black text-slate-900 mb-2 tracking-tight">RajGKPortal Login</h2>
          <p className="text-slate-400 font-medium">Track your progress & practice tests</p>
        </div>

        <form onSubmit={handleLogin} className="space-y-6">
          <div className="space-y-2">
            <label className="text-xs font-black uppercase tracking-widest text-slate-500 ml-1">Phone Number</label>
            <input 
              type="tel" 
              value={phone}
              onChange={(e) => setPhone(e.target.value.replace(/\D/g, '').slice(0, 10))}
              placeholder="9876543210"
              className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-6 py-4 outline-none focus:border-blue-600 focus:bg-white transition-all font-bold text-lg"
              required
            />
          </div>
          <div className="space-y-2">
            <label className="text-xs font-black uppercase tracking-widest text-slate-500 ml-1">Password</label>
            <input 
              type="password" 
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="••••••••"
              className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-6 py-4 outline-none focus:border-blue-600 focus:bg-white transition-all font-bold text-lg"
              required
            />
          </div>
          <button 
            type="submit"
            className="w-full bg-blue-600 text-white py-5 rounded-2xl font-black text-lg shadow-xl shadow-blue-100 hover:bg-blue-700 hover:-translate-y-1 transition-all active:scale-95 flex items-center justify-center gap-3"
          >
            Access Portal
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M14 5l7 7m0 0l-7 7m7-7H3" /></svg>
          </button>
        </form>
        <p className="mt-8 text-center text-slate-400 text-[10px] font-black uppercase tracking-[0.2em]">
          Secure Session Tracking V2.0
        </p>
      </div>
    </div>
  );

  const renderHome = () => (
    <div className="animate-fadeIn max-w-6xl mx-auto space-y-12">
      <section className="text-center space-y-4">
        <div className="inline-flex items-center gap-2 bg-blue-50 text-blue-700 px-4 py-1.5 rounded-full text-xs font-black uppercase tracking-widest mb-2">
          <span className="w-2 h-2 bg-blue-600 rounded-full animate-pulse"></span>
          Preparation Status: Active
        </div>
        <h1 className="text-4xl md:text-6xl font-black text-slate-900 tracking-tight">
          Target <span className="text-blue-600">RSSB & RPSC</span> Exams
        </h1>
        <p className="text-slate-500 text-lg md:text-xl max-w-2xl mx-auto">
          You have completed <span className="text-blue-600 font-bold">{completedTests.size} tests</span>. Continue your preparation to reach 100%.
        </p>
      </section>

      {/* Main Feature Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        <div onClick={() => navigateTo(AppView.QUIZ_MIX_MENU)} className="group bg-white p-8 rounded-3xl border border-slate-200 shadow-sm hover:shadow-xl hover:-translate-y-1 transition-all cursor-pointer">
          <div className="w-14 h-14 bg-indigo-50 text-indigo-600 rounded-2xl flex items-center justify-center mb-6 group-hover:scale-110 transition-transform">
            <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" /></svg>
          </div>
          <h3 className="text-2xl font-black text-slate-900 mb-2">Mixed Mock Tests</h3>
          <p className="text-slate-500 mb-6">40 Full-length practice sets covering the entire syllabus.</p>
          <div className="text-blue-600 font-bold flex items-center gap-2 group-hover:gap-4 transition-all uppercase text-sm tracking-wider">
            Start Practice <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 7l5 5m0 0l-5 5m5-5H6" /></svg>
          </div>
        </div>

        <div onClick={() => navigateTo(AppView.QUIZ_TOPIC_MENU)} className="group bg-white p-8 rounded-3xl border border-slate-200 shadow-sm hover:shadow-xl hover:-translate-y-1 transition-all cursor-pointer">
          <div className="w-14 h-14 bg-emerald-50 text-emerald-600 rounded-2xl flex items-center justify-center mb-6 group-hover:scale-110 transition-transform">
            <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2" /></svg>
          </div>
          <h3 className="text-2xl font-black text-slate-900 mb-2">Topic-wise PYQs</h3>
          <p className="text-slate-500 mb-6">Master specific sections like History, Geography & Culture.</p>
          <div className="text-emerald-600 font-bold flex items-center gap-2 group-hover:gap-4 transition-all uppercase text-sm tracking-wider">
            Explore Topics <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 7l5 5m0 0l-5 5m5-5H6" /></svg>
          </div>
        </div>

        <div onClick={() => navigateTo(AppView.EXAM_MENU)} className="group bg-blue-900 p-8 rounded-3xl shadow-xl hover:-translate-y-1 transition-all cursor-pointer text-white">
          <div className="w-14 h-14 bg-white/10 text-white rounded-2xl flex items-center justify-center mb-6 group-hover:scale-110 transition-transform">
            <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 14l9-5-9-5-9 5 9 5z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 14l6.16-3.422a12.083 12.083 0 01.665 6.479A11.952 11.952 0 0012 20.055a11.952 11.952 0 00-6.824-2.998 12.078 12.078 0 01.665-6.479L12 14z" /></svg>
          </div>
          <h3 className="text-2xl font-black mb-2">Exam Portal</h3>
          <p className="text-blue-200 mb-6">Access official full papers: Lab Assistant, CET, RAS, etc.</p>
          <div className="text-amber-400 font-bold flex items-center gap-2 group-hover:gap-4 transition-all uppercase text-sm tracking-wider">
            View Exams <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 7l5 5m0 0l-5 5m5-5H6" /></svg>
          </div>
        </div>
      </div>

      {/* Lab Assistant Specialized Pack - Preserved Section */}
      <div className="bg-slate-900 rounded-[2.5rem] p-8 md:p-12 border border-slate-800 flex flex-col md:flex-row items-center gap-8 md:gap-16 relative overflow-hidden text-white">
        <div className="absolute top-0 right-0 w-64 h-64 bg-blue-600/10 rounded-full blur-3xl -mr-32 -mt-32"></div>
        <div className="shrink-0 relative">
           {completedTests.has('exam-Lab_Assistant_2022_GK_Paper-0') && completedTests.has('exam-Lab_Assistant_2022_Science_Paper-0') && (
              <div className="absolute -top-4 -right-4 bg-emerald-500 text-white p-2.5 rounded-full shadow-lg z-10 border-4 border-slate-900">
                 <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" /></svg>
              </div>
           )}
           <img src="https://images.unsplash.com/photo-1532094349884-543bc11b234d?auto=format&fit=crop&q=80&w=300&h=300" className="relative w-48 h-48 rounded-full border-8 border-slate-800 object-cover shadow-2xl" alt="Lab Assistant" />
        </div>
        <div className="relative z-10">
          <div className="flex items-center gap-3 mb-4">
            <span className="bg-amber-500 text-slate-900 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest">Official 2022 Pack</span>
            <span className="text-slate-400 text-[10px] font-black uppercase tracking-widest">RSSB Exam</span>
          </div>
          <h2 className="text-3xl md:text-5xl font-black mb-4">Lab Assistant 2022</h2>
          <p className="text-slate-400 text-lg mb-8 leading-relaxed max-w-2xl">
            Complete preparation with both General Knowledge (GK) and Science papers. Practice the actual questions exactly as they appeared in the 2022 exam.
          </p>
          <div className="flex flex-wrap gap-4">
             <button 
              onClick={() => startQuiz(QuizType.EXAM, "Lab Assistant 2022 - GK", { testId: 'exam-Lab_Assistant_2022_GK_Paper-0', examContext: "Lab Assistant 2022 Paper 1 (GK)", count: 100 })} 
              className="bg-white text-slate-900 px-8 py-4 rounded-2xl font-black hover:bg-blue-600 hover:text-white transition-all flex items-center gap-3"
             >
                Practice GK Paper 1
                {completedTests.has('exam-Lab_Assistant_2022_GK_Paper-0') && (
                  <div className="bg-emerald-500 rounded-full p-1">
                    <svg className="w-3 h-3 text-white" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" /></svg>
                  </div>
                )}
             </button>
             <button 
              onClick={() => startQuiz(QuizType.EXAM, "Lab Assistant 2022 - Science", { testId: 'exam-Lab_Assistant_2022_Science_Paper-0', examContext: "Lab Assistant 2022 Paper 2 (Science)", count: 100 })} 
              className="bg-slate-800 text-slate-300 border border-slate-700 px-8 py-4 rounded-2xl font-black hover:bg-slate-700 transition-all flex items-center gap-3"
             >
                Science Paper 2
                {completedTests.has('exam-Lab_Assistant_2022_Science_Paper-0') && (
                   <div className="bg-emerald-500 rounded-full p-1">
                    <svg className="w-3 h-3 text-white" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" /></svg>
                  </div>
                )}
             </button>
          </div>
        </div>
      </div>
    </div>
  );

  const renderMixMenu = () => (
    <div className="animate-fadeIn">
      <div className="flex items-center gap-4 mb-12">
        <button onClick={() => navigateTo(AppView.HOME)} className="p-3 bg-white border border-slate-200 rounded-2xl hover:bg-slate-50 transition-all text-slate-500">
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" /></svg>
        </button>
        <div>
          <h2 className="text-3xl font-black text-slate-900">Mixed subjects Mock</h2>
          <p className="text-slate-500 font-medium">Full Syllabus Practice (Set 1-40)</p>
        </div>
      </div>

      <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4">
        {Array.from({ length: testsPerPage }).map((_, i) => {
          const testNum = i + 1;
          const testId = `mix-Mixed_Subjects-${testNum}`;
          const isDone = completedTests.has(testId);
          return (
            <button
              key={testNum}
              onClick={() => startQuiz(QuizType.MIX, "Mixed Subjects", { testNumber: testNum, testId, count: 25 })}
              className={`group p-6 rounded-3xl border-2 transition-all text-center relative overflow-hidden ${isDone ? 'bg-emerald-50 border-emerald-500 text-emerald-900' : 'bg-white border-slate-100 hover:border-blue-600 hover:shadow-xl'}`}
            >
              {isDone && (
                <div className="absolute top-2 right-2 text-emerald-500">
                  <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" /></svg>
                </div>
