      <div className="flex items-center gap-4 mb-12">
        <button onClick={() => navigateTo(AppView.QUIZ_TOPIC_MENU)} className="p-3 bg-white border border-slate-200 rounded-2xl text-slate-500 hover:bg-slate-50">
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" /></svg>
        </button>
        <div>
          <h2 className="text-3xl font-black text-slate-900 tracking-tight">{selectedGroup?.name}</h2>
          <p className="text-slate-500 font-medium">Explore all units in this category</p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {selectedGroup?.subtopics.map((sub, i) => {
          const testId = `topic-${sub.replace(/\s+/g, '_')}-0`;
          const isDone = completedTests.has(testId);
          return (
            <button
              key={i}
              onClick={() => startQuiz(QuizType.TOPIC, sub, { testId, topic: sub, count: 25 })}
              className={`flex items-center justify-between p-6 rounded-[2rem] border transition-all text-left group ${isDone ? 'bg-emerald-50 border-emerald-500 text-emerald-900 shadow-sm' : 'bg-white border-slate-200 hover:border-blue-600 hover:bg-blue-50/50'}`}
            >
              <span className="font-bold text-lg hindi-text pr-4 leading-relaxed">{sub}</span>
              {isDone ? (
                <div className="bg-emerald-500 p-2 rounded-xl text-white shadow-lg shadow-emerald-100">
                  <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" /></svg>
                </div>
              ) : (
                <div className="bg-white p-2 rounded-xl border border-slate-100 text-blue-600 group-hover:scale-110 transition-transform">
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>
                </div>
              )}
            </button>
          );
        })}
      </div>
    </div>
  );

  const renderExamMenu = () => (
    <div className="animate-fadeIn space-y-12">
      <div className="flex items-center gap-4 mb-4">
        <button onClick={() => navigateTo(AppView.HOME)} className="p-3 bg-white border border-slate-200 rounded-2xl text-slate-500 hover:bg-slate-50 transition-all">
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" /></svg>
        </button>
        <div>
          <h2 className="text-3xl font-black text-slate-900 tracking-tight">Official Exam Portal</h2>
          <p className="text-slate-500 font-medium">Full papers as held by RSSB & RPSC boards.</p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {[
          { name: "RSSB CET Graduate Level", year: 2024, context: "CET Graduate Level 2024" },
          { name: "RSSB CET Senior Secondary", year: 2024, context: "CET Senior Secondary 2024" },
          { name: "RSSB LDC Exam", year: 2024, context: "LDC 2024 Exam" },
          { name: "RPSC RAS Prelims", year: 2023, context: "RAS Prelims 2023" },
          { name: "Lab Assistant (GK)", year: 2022, context: "Lab Assistant 2022 GK Paper" },
          { name: "Lab Assistant (Science)", year: 2022, context: "Lab Assistant 2022 Science Paper" },
          { name: "RSSB Patwar Exam", year: 2021, context: "Patwar 2021 Exam" },
          { name: "RSSB REET Exam L-1", year: 2023, context: "REET 2023 Level 1" },
          { name: "RSSB Junior Accountant", year: 2024, context: "Junior Accountant 2024" }
        ].map((exam, i) => {
          const testId = `exam-${exam.name.replace(/\s+/g, '_')}-0`;
          const isDone = completedTests.has(testId);
          return (
            <div key={i} className={`bg-white rounded-[2rem] border p-8 hover:shadow-2xl transition-all group relative ${isDone ? 'border-emerald-500 shadow-emerald-50' : 'border-slate-200'}`}>
              {isDone && (
                <div className="absolute top-6 right-6 bg-emerald-500 text-white p-2 rounded-xl shadow-lg shadow-emerald-100 z-10">
                  <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" /></svg>
                </div>
              )}
              <div className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400 mb-2">{exam.year} Edition</div>
              <h3 className="text-2xl font-black text-slate-900 mb-6 group-hover:text-blue-600 transition-colors leading-tight">{exam.name}</h3>
              <button 
                onClick={() => startQuiz(QuizType.EXAM, exam.name, { testId, examContext: exam.context, count: 100 })}
                className={`w-full py-4 rounded-2xl font-black transition-all flex items-center justify-center gap-2 shadow-lg ${isDone ? 'bg-emerald-100 text-emerald-800 hover:bg-emerald-200 shadow-emerald-50' : 'bg-slate-900 text-white hover:bg-blue-600 shadow-slate-200'}`}
              >
                {isDone ? 'Revision Mode' : 'Start Official Mock'}
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M14 5l7 7m0 0l-7 7m7-7H3" /></svg>
              </button>
            </div>
          );
        })}
      </div>
    </div>
  );

  return (
    <Layout 
      onHomeClick={() => navigateTo(AppView.HOME)} 
      onLogout={handleLogout} 
      isLoggedIn={isLoggedIn}
    >
      {loading ? (
        <div className="flex flex-col items-center justify-center min-h-[60vh] animate-pulse">
          <div className="w-20 h-20 border-[10px] border-blue-600 border-t-transparent rounded-full animate-spin mb-8 shadow-xl shadow-blue-50"></div>
          <h2 className="text-2xl font-black text-slate-900 mb-2">Connecting to RPSC/RSSB Server...</h2>
          <p className="text-slate-500 font-medium tracking-wide">Fetching authentic PYQs & setting up marking scheme.</p>
        </div>
      ) : (
        <>
          {view === AppView.AUTH && renderAuth()}
          {view === AppView.HOME && renderHome()}
          {view === AppView.QUIZ_MIX_MENU && renderMixMenu()}
          {view === AppView.QUIZ_TOPIC_MENU && renderTopicMenu()}
          {view === AppView.QUIZ_SUBTOPIC_MENU && renderSubtopicMenu()}
          {view === AppView.EXAM_MENU && renderExamMenu()}

          {view === AppView.QUIZ_ACTIVE && activeSession && (
            <QuizEngine 
              session={activeSession} 
              onComplete={onQuizComplete}
              onExit={() => navigateTo(AppView.HOME)}
            />
          )}

          {view === AppView.SCORECARD && lastResults && (
            <ScoreCard 
              results={lastResults} 
              onReview={() => navigateTo(AppView.REVIEW)}
              onNextTest={() => navigateTo(AppView.HOME)}
              onBackHome={() => navigateTo(AppView.HOME)}
            />
          )}

          {view === AppView.REVIEW && lastResults && (
            <QuizEngine 
              session={lastResults.session} 
              onComplete={() => {}}
              onExit={() => navigateTo(AppView.SCORECARD)}
              isReview={true}
            />
          )}
        </>
      )}
    </Layout>
  );
};

export default App;

{
  "name": "RAJGKQUIZER",
  "description": "Premium Rajasthan Exam Preparation Portal featuring 10,000+ real RSSB & RPSC Previous Year Questions (2015-2026). Specialized Lab Assistant tests and AI-powered mock exams.",
  "requestFramePermissions": []
}

import React, { useState, useEffect, useCallback } from 'react';
import Layout from './components/Layout';
import QuizEngine from './components/QuizEngine';
import ScoreCard from './components/ScoreCard';
import { 
  AppView, 
  QuizSession, 
  QuizType, 
  QuizResults 
} from './types';
import { 
  TOPIC_GROUPS,
  TopicGroup,
  MARKING_SCHEME 
} from './constants';
import { fetchPYQs } from './services/geminiService';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.AUTH);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [phone, setPhone] = useState('');
  const [password, setPassword] = useState('');
  const [activeSession, setActiveSession] = useState<QuizSession | null>(null);
  const [lastResults, setLastResults] = useState<QuizResults | null>(null);
  const [loading, setLoading] = useState(false);
  const [selectedGroup, setSelectedGroup] = useState<TopicGroup | null>(null);
  const [completedTests, setCompletedTests] = useState<Set<string>>(new Set());
  const testsPerPage = 40;

  // Initialize session and progress from localStorage
  useEffect(() => {
    const savedSession = localStorage.getItem('rajgkquiz_session');
    if (savedSession) {
      setIsLoggedIn(true);
      setView(AppView.HOME);
    }

    const savedProgress = localStorage.getItem('rajgkquiz_progress');
    if (savedProgress) {
      try {
        setCompletedTests(new Set(JSON.parse(savedProgress)));
      } catch (e) { 
        console.error("Failed to load progress", e); 
      }
    }
  }, []);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (phone.length === 10 && password.length >= 4) {
      localStorage.setItem('rajgkquiz_session', JSON.stringify({ phone }));
      setIsLoggedIn(true);
      setView(AppView.HOME);
    } else {
      alert("कृपया सही 10-अंकों का मोबाइल नंबर और कम से कम 4 अक्षरों का पासवर्ड डालें।");
    }
  };

  const handleLogout = () => {
    if (window.confirm("क्या आप लॉगआउट करना चाहते हैं?")) {
      localStorage.removeItem('rajgkquiz_session');
      setIsLoggedIn(false);
      setPhone('');
      setPassword('');
      setView(AppView.AUTH);
    }
  };

  const navigateTo = (newView: AppView) => {
    setView(newView);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const markTestCompleted = (testId: string) => {
    setCompletedTests(prev => {
      const newSet = new Set(prev);
      newSet.add(testId);
      localStorage.setItem('rajgkquiz_progress', JSON.stringify(Array.from(newSet)));
      return newSet;
    });
  };

  const startQuiz = useCallback(async (type: QuizType, title: string, options: { 
    subject?: string; 
    topic?: string; 
    count?: number; 
    testId?: string;
    testNumber?: number;
    examContext?: string;
  } = {}) => {
    // Generate unique ID for tracking progress if not provided
    const finalTestId = options.testId || `${type}-${(options.topic || title).replace(/\s+/g, '_')}-${options.testNumber || 0}`;

    setLoading(true);
    try {
      const questions = await fetchPYQs({
        count: options.count || 25,
        subject: options.subject,
        topic: options.topic,
        isMix: type === QuizType.MIX || type === QuizType.AI,
        testNumber: options.testNumber,
        examContext: options.examContext
      });

      if (!questions || questions.length === 0) throw new Error("Database pool empty");

      const session: QuizSession = {
        type,
        title: `${title} ${options.testNumber ? `- Test ${options.testNumber}` : ''}`,
        questions,
        currentQuestionIndex: 0,
        userAnswers: {},
        startTime: Date.now(),
        durationInMinutes: type === QuizType.AI ? 15 : (options.count && options.count > 50 ? 120 : 60),
        completed: false
      };

      // Store ID in session temporarily for completion marking
      (session as any).testId = finalTestId;
      setActiveSession(session);
      navigateTo(AppView.QUIZ_ACTIVE);
    } catch (error) {
      alert("सर्वर से जुड़ने में विफल। कृपया इंटरनेट चेक करें और पुनः प्रयास करें।");
    } finally {
      setLoading(false);
    }
  }, []);

  const onQuizComplete = (session: QuizSession) => {
    let score = 0, correct = 0, incorrect = 0, skipped = 0, unattempted = 0;
    session.questions.forEach(q => {
      const ans = session.userAnswers[q.id];
      if (!ans) { 
        score += MARKING_SCHEME.UNATTEMPTED; 
        unattempted++; 
      }
      else if (ans === 'E') {
        skipped++; 
      }
      else if (ans === q.correctAnswer) { 
        score += MARKING_SCHEME.CORRECT; 
        correct++; 
      }
      else { 
        score += MARKING_SCHEME.WRONG; 
        incorrect++; 
      }
    });

    setLastResults({ 
      score, 
      correctCount: correct, 
      incorrectCount: incorrect, 
      skippedCount: skipped, 
      unattemptedCount: unattempted, 
