          )}

          {view === AppView.REVIEW && lastResults && (
            <QuizEngine 
              session={lastResults.session} 
              onComplete={() => {}}
              onExit={() => navigateTo(AppView.SCORECARD)}
              isReview={true}
            />
          )}
        </>
      )}
    </Layout>
