export default App;

export enum AppView {
  AUTH = 'auth',
  HOME = 'home',
  QUIZ_MENU = 'quiz_menu',
  QUIZ_MIX_MENU = 'quiz_mix_menu',
  QUIZ_TOPIC_MENU = 'quiz_topic_menu',
  QUIZ_SUBTOPIC_MENU = 'quiz_subtopic_menu',
  EXAM_MENU = 'exam_menu',
  AI_TEST = 'ai_test',
  QUIZ_ACTIVE = 'quiz_active',
  SCORECARD = 'scorecard',
  REVIEW = 'review'
}

export enum AuthSubView {
  LOGIN = 'login',
  SIGNUP_PHONE = 'signup_phone',
  SIGNUP_OTP = 'signup_otp',
  SIGNUP_PASSWORD = 'signup_password',
  FORGOT_PHONE = 'forgot_phone',
  FORGOT_OTP = 'forgot_otp',
  RESET_PASSWORD = 'reset_password'
}

export enum QuizType {
  MIX = 'mix',
  TOPIC = 'topic',
  EXAM = 'exam',
  AI = 'ai'
}

export interface Question {
  id: string;
  question: string;
  options: {
    A: string;
    B: string;
    C: string;
    D: string;
    E: string;
  };
  correctAnswer: 'A' | 'B' | 'C' | 'D' | 'E';
  examName: string;
  examYear: number;
  subject: string;
  topic?: string;
}

export interface QuizSession {
  type: QuizType;
  title: string;
  questions: Question[];
  currentQuestionIndex: number;
  userAnswers: Record<string, 'A' | 'B' | 'C' | 'D' | 'E' | null>;
  startTime: number;
  durationInMinutes: number;
  completed: boolean;
}

export interface QuizResults {
  score: number;
  correctCount: number;
  incorrectCount: number;
  skippedCount: number;
  unattemptedCount: number;
  totalQuestions: number;
  timeTaken: string;
  session: QuizSession;
}

import React, { useState, useEffect, useCallback } from 'react';
import Layout from './components/Layout';
import QuizEngine from './components/QuizEngine';
import ScoreCard from './components/ScoreCard';
import { 
  AppView, 
  AuthSubView,
  QuizSession, 
  QuizType, 
  QuizResults 
} from './types';
import { 
  TOPIC_GROUPS,
  TopicGroup,
  MARKING_SCHEME 
} from './constants';
import { fetchPYQs } from './services/geminiService';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.AUTH);
  const [authStep, setAuthStep] = useState<AuthSubView>(AuthSubView.LOGIN);
  const [isLoggedIn, setIsLoggedIn] = useState(false);

  // Auth Form State
  const [phone, setPhone] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [otp, setOtp] = useState('');

  const [activeSession, setActiveSession] = useState<QuizSession | null>(null);
  const [lastResults, setLastResults] = useState<QuizResults | null>(null);
  const [loading, setLoading] = useState(false);
  const [selectedGroup, setSelectedGroup] = useState<TopicGroup | null>(null);
  const [completedTests, setCompletedTests] = useState<Set<string>>(new Set());
  const testsPerPage = 40;

  // Initialize session and progress from localStorage
  useEffect(() => {
    const savedUser = localStorage.getItem('rajgkquiz_currentUser');
    if (savedUser) {
      setIsLoggedIn(true);
      setView(AppView.HOME);
    }

    const savedProgress = localStorage.getItem('rajgkquiz_progress');
    if (savedProgress) {
      try {
        setCompletedTests(new Set(JSON.parse(savedProgress)));
      } catch (e) { 
        console.error("Failed to load progress", e); 
      }
    }
  }, []);

  // --- Auth Logic ---
  const getUsers = () => {
    const users = localStorage.getItem('rajgkquiz_users');
    return users ? JSON.parse(users) : {};
  };

  const saveUser = (phone: string, pass: string) => {
    const users = getUsers();
    users[phone] = { password: pass };
    localStorage.setItem('rajgkquiz_users', JSON.stringify(users));
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const users = getUsers();
    if (users[phone] && users[phone].password === password) {
      localStorage.setItem('rajgkquiz_currentUser', phone);
      setIsLoggedIn(true);
      setView(AppView.HOME);
    } else {
      alert("गलत फोन नंबर या पासवर्ड। (Incorrect phone or password)");
    }
  };

  const handleSignupPhone = (e: React.FormEvent) => {
    e.preventDefault();
    if (phone.length !== 10) return alert("कृपया 10 अंकों का नंबर डालें");
    setAuthStep(AuthSubView.SIGNUP_OTP);
    alert("OTP (1234) आपके नंबर पर भेजा गया है (Simulated)");
  };

  const handleVerifyOtp = (e: React.FormEvent, isReset = false) => {
    e.preventDefault();
    if (otp === '1234') {
      setAuthStep(isReset ? AuthSubView.RESET_PASSWORD : AuthSubView.SIGNUP_PASSWORD);
      setOtp('');
    } else {
      alert("गलत OTP। सही OTP '1234' है।");
    }
  };

  const handleSetPassword = (e: React.FormEvent, isReset = false) => {
    e.preventDefault();
    if (password.length < 4) return alert("पासवर्ड कम से कम 4 अक्षरों का होना चाहिए");
    if (password !== confirmPassword) return alert("पासवर्ड मैच नहीं कर रहे हैं");
    saveUser(phone, password);
    alert(isReset ? "पासवर्ड सफलतापूर्वक बदल दिया गया है!" : "अकाउंट सफलतापूर्वक बन गया है!");
    setAuthStep(AuthSubView.LOGIN);
    setPassword('');
    setConfirmPassword('');
  };

  const handleForgotPhone = (e: React.FormEvent) => {
    e.preventDefault();
    const users = getUsers();
    if (!users[phone]) return alert("यह नंबर रजिस्टर्ड नहीं है।");
    setAuthStep(AuthSubView.FORGOT_OTP);
    alert("OTP (1234) आपके नंबर पर भेजा गया है (Simulated)");
  };

  const handleLogout = () => {
    if (window.confirm("क्या आप लॉगआउट करना चाहते हैं?")) {
      localStorage.removeItem('rajgkquiz_currentUser');
      setIsLoggedIn(false);
      setPhone('');
      setPassword('');
      setAuthStep(AuthSubView.LOGIN);
      setView(AppView.AUTH);
    }
  };

  // --- Navigation & Quiz Logic ---
  const navigateTo = (newView: AppView) => {
    setView(newView);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const markTestCompleted = (testId: string) => {
    setCompletedTests(prev => {
      const newSet = new Set(prev);
      newSet.add(testId);
      localStorage.setItem('rajgkquiz_progress', JSON.stringify(Array.from(newSet)));
      return newSet;
    });
  };

  const startQuiz = useCallback(async (type: QuizType, title: string, options: { 
    subject?: string; 
    topic?: string; 
    count?: number; 
    testId?: string;
    testNumber?: number;
    examContext?: string;
  } = {}) => {
    const finalTestId = options.testId || `${type}-${(options.topic || title).replace(/\s+/g, '_')}-${options.testNumber || 0}`;
    setLoading(true);
    try {
      const questions = await fetchPYQs({
        count: options.count || 25,
        subject: options.subject,
        topic: options.topic,
        isMix: type === QuizType.MIX || type === QuizType.AI,
        testNumber: options.testNumber,
        examContext: options.examContext
      });
      if (!questions || questions.length === 0) throw new Error("Database pool empty");
      const session: QuizSession = {
        type,
        title: `${title} ${options.testNumber ? `- Test ${options.testNumber}` : ''}`,
        questions,
        currentQuestionIndex: 0,
        userAnswers: {},
        startTime: Date.now(),
        durationInMinutes: type === QuizType.AI ? 15 : (options.count && options.count > 50 ? 120 : 60),
        completed: false
      };
      (session as any).testId = finalTestId;
      setActiveSession(session);
      navigateTo(AppView.QUIZ_ACTIVE);
    } catch (error) {
      alert("सर्वर से जुड़ने में विफल।");
    } finally {
      setLoading(false);
    }
  }, []);

  const onQuizComplete = (session: QuizSession) => {
    let score = 0, correct = 0, incorrect = 0, skipped = 0, unattempted = 0;
    session.questions.forEach(q => {
      const ans = session.userAnswers[q.id];
      if (!ans) { score += MARKING_SCHEME.UNATTEMPTED; unattempted++; }
      else if (ans === 'E') skipped++;
      else if (ans === q.correctAnswer) { score += MARKING_SCHEME.CORRECT; correct++; }
      else { score += MARKING_SCHEME.WRONG; incorrect++; }
    });
    setLastResults({ score, correctCount: correct, incorrectCount: incorrect, skippedCount: skipped, unattemptedCount: unattempted, totalQuestions: session.questions.length, timeTaken: 'N/A', session });
    const tId = (session as any).testId;
    if (tId) markTestCompleted(tId);
    navigateTo(AppView.SCORECARD);
  };

