              </div>
              <div className="space-y-2">
                <label className={labelClass}>Password</label>
                <input type="password" value={password} onChange={e => setPassword(e.target.value)} placeholder="••••••••" className={inputClass} required />
              </div>
              <button type="submit" className={buttonClass}>Login <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M14 5l7 7m0 0l-7 7m7-7H3" /></svg></button>
            </form>
            <div className="mt-6 flex flex-col gap-3 text-center">
              <button onClick={() => { setAuthStep(AuthSubView.FORGOT_PHONE); setPhone(''); }} className="text-blue-600 font-bold text-sm hover:underline">Forgot Password?</button>
              <div className="h-px bg-slate-100 w-full"></div>
