            </div>
            <form onSubmit={handleSignupPhone} className="space-y-4">
              <div className="space-y-2">
                <label className={labelClass}>Phone Number</label>
                <input type="tel" value={phone} onChange={e => setPhone(e.target.value.replace(/\D/g, '').slice(0, 10))} placeholder="9876543210" className={inputClass} required />
              </div>
              <button type="submit" className={buttonClass}>Send OTP</button>
            </form>
          </div>
        )}

        {(authStep === AuthSubView.SIGNUP_OTP || authStep === AuthSubView.FORGOT_OTP) && (
          <div className={cardClass}>
            <div className="text-center mb-10">
              <h2 className="text-3xl font-black text-slate-900 mb-2 uppercase">Verify OTP</h2>
