                <input type="text" value={otp} onChange={e => setOtp(e.target.value.replace(/\D/g, '').slice(0, 4))} placeholder="1234" className={`${inputClass} text-center tracking-[1em] text-2xl`} required />
              </div>
              <button type="submit" className={buttonClass}>Verify OTP</button>
            </form>
          </div>
        )}

        {(authStep === AuthSubView.SIGNUP_PASSWORD || authStep === AuthSubView.RESET_PASSWORD) && (
          <div className={cardClass}>
            <div className="text-center mb-10">
              <h2 className="text-3xl font-black text-slate-900 mb-2 uppercase">{authStep === AuthSubView.RESET_PASSWORD ? "Reset" : "Set"} Password</h2>
              <p className="text-slate-400 font-medium text-sm">Ensure your account security</p>
            </div>
            <form onSubmit={(e) => handleSetPassword(e, authStep === AuthSubView.RESET_PASSWORD)} className="space-y-4">
              <div className="space-y-2">
                <label className={labelClass}>New Password</label>
                <input type="password" value={password} onChange={e => setPassword(e.target.value)} placeholder="••••••••" className={inputClass} required />
              </div>
              <div className="space-y-2">
                <label className={labelClass}>Confirm Password</label>
                <input type="password" value={confirmPassword} onChange={e => setConfirmPassword(e.target.value)} placeholder="••••••••" className={inputClass} required />
              </div>
              <button type="submit" className={buttonClass}>Secure Account</button>
            </form>
          </div>
        )}

        {authStep === AuthSubView.FORGOT_PHONE && (
          <div className={cardClass}>
            <button onClick={() => setAuthStep(AuthSubView.LOGIN)} className="mb-6 text-slate-400 font-bold text-sm flex items-center gap-1 hover:text-blue-600 transition-colors"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" /></svg> Back</button>
