      <div className="flex items-center gap-4 mb-4">
        <button onClick={() => navigateTo(AppView.HOME)} className="p-3 bg-white border border-slate-200 rounded-2xl text-slate-500"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" /></svg></button>
