                  <button key={i} onClick={() => startQuiz(QuizType.TOPIC, sub, { testId, topic: sub, count: 20 })} className={`text-left text-sm font-semibold p-3.5 rounded-xl border flex items-center justify-between transition-all hindi-text group/item ${isDone ? 'bg-emerald-50 border-emerald-500 text-emerald-800' : 'border-slate-100 hover:border-emerald-200 hover:bg-emerald-50 text-slate-600 hover:text-emerald-700'}`}>
