            {group.subtopics.length > 6 && <button onClick={() => { setSelectedGroup(group); navigateTo(AppView.QUIZ_SUBTOPIC_MENU); }} className="mt-6 w-full py-3.5 rounded-xl bg-slate-50 text-slate-500 font-black hover:bg-slate-100 transition-all text-xs uppercase tracking-widest">View All {group.subtopics.length} Units</button>}
