    return (
      <div className="animate-fadeIn space-y-12">
        <div className="flex items-center gap-4 mb-4">
          <button onClick={() => navigateTo(AppView.HOME)} className="p-3 bg-white border border-slate-200 rounded-2xl text-slate-500 hover:bg-slate-50 transition-all">
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" /></svg>
          </button>
          <div>
            <h2 className="text-3xl font-black text-slate-900 tracking-tight uppercase">Official Exam Portal</h2>
            <p className="text-slate-500 font-medium">Full papers as held by RSSB & RPSC boards.</p>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {exams.map((exam, i) => {
            const testId = exam.testId || `exam-${exam.name.replace(/\s+/g, '_')}-0`;
            const isDone = completedTests.has(testId);
            return (
              <div key={i} className={`bg-white rounded-[2.5rem] border p-8 hover:shadow-2xl transition-all group relative ${isDone ? 'border-emerald-500 shadow-emerald-50' : 'border-slate-200'}`}>
                {isDone && (
                  <div className="absolute top-6 right-6 bg-emerald-500 text-white p-2 rounded-xl shadow-lg shadow-emerald-100 z-10">
                    <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" /></svg>
                  </div>
                )}
                <div className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400 mb-2">{exam.year} Edition</div>
                <h3 className="text-2xl font-black text-slate-900 mb-6 group-hover:text-blue-600 transition-colors leading-tight">{exam.name}</h3>
                <button 
                  onClick={() => startQuiz(QuizType.EXAM, exam.name, { testId, examContext: exam.context, count: 100 })}
