                  {isDone ? 'Revision Mode' : 'Start Official Mock'}
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M14 5l7 7m0 0l-7 7m7-7H3" /></svg>
                </button>
              </div>
            );
          })}
        </div>
      </div>
    );
  };

  return (
    <Layout 
      onHomeClick={() => navigateTo(AppView.HOME)} 
      onLogout={handleLogout} 
      isLoggedIn={isLoggedIn}
    >
      {loading ? (
        <div className="flex flex-col items-center justify-center min-h-[60vh] animate-pulse">
          <div className="w-20 h-20 border-[10px] border-blue-600 border-t-transparent rounded-full animate-spin mb-8 shadow-xl shadow-blue-50"></div>
          <h2 className="text-2xl font-black text-slate-900 mb-2 uppercase tracking-tighter">Connecting RAJQUIZER...</h2>
          <p className="text-slate-500 font-medium tracking-wide uppercase text-[10px]">Fetching original board PYQs securely.</p>
        </div>
      ) : (
        <>
          {view === AppView.AUTH && renderAuth()}
          {view === AppView.HOME && renderHome()}
          {view === AppView.QUIZ_MIX_MENU && renderMixMenu()}
          {view === AppView.QUIZ_TOPIC_MENU && renderTopicMenu()}
          {view === AppView.QUIZ_SUBTOPIC_MENU && renderSubtopicMenu()}
          {view === AppView.EXAM_MENU && renderExamMenu()}

          {view === AppView.QUIZ_ACTIVE && activeSession && (
            <QuizEngine 
              session={activeSession} 
              onComplete={onQuizComplete}
              onExit={() => navigateTo(AppView.HOME)}
            />
          )}

          {view === AppView.SCORECARD && lastResults && (
            <ScoreCard 
              results={lastResults} 
              onReview={() => navigateTo(AppView.REVIEW)}
              onNextTest={() => navigateTo(AppView.HOME)}
              onBackHome={() => navigateTo(AppView.HOME)}
            />
          )}

          {view === AppView.REVIEW && lastResults && (
            <QuizEngine 
              session={lastResults.session} 
              onComplete={() => {}}
              onExit={() => navigateTo(AppView.SCORECARD)}
              isReview={true}
            />
          )}
        </>
      )}
    </Layout>
  );
};

export default App;

export enum AppView {
  AUTH = 'auth',
  HOME = 'home',
  QUIZ_MENU = 'quiz_menu',
  QUIZ_MIX_MENU = 'quiz_mix_menu',
  QUIZ_TOPIC_MENU = 'quiz_topic_menu',
  QUIZ_SUBTOPIC_MENU = 'quiz_subtopic_menu',
  EXAM_MENU = 'exam_menu',
  AI_TEST = 'ai_test',
  QUIZ_ACTIVE = 'quiz_active',
  SCORECARD = 'scorecard',
  REVIEW = 'review'
}

export enum AuthSubView {
  CHOICE = 'choice',
  LOGIN = 'login',
  SIGNUP = 'signup',
  FORGOT_PHONE = 'forgot_phone',
  FORGOT_OTP = 'forgot_otp',
  RESET_PASSWORD = 'reset_password'
}

export enum QuizType {
  MIX = 'mix',
  TOPIC = 'topic',
  EXAM = 'exam',
  AI = 'ai'
}

export interface Question {
  id: string;
  question: string;
  options: {
    A: string;
    B: string;
    C: string;
    D: string;
    E: string;
  };
  correctAnswer: 'A' | 'B' | 'C' | 'D' | 'E';
  examName: string;
  examYear: number;
  subject: string;
  topic?: string;
}

export interface QuizSession {
  type: QuizType;
  title: string;
  questions: Question[];
  currentQuestionIndex: number;
  userAnswers: Record<string, 'A' | 'B' | 'C' | 'D' | 'E' | null>;
  startTime: number;
  durationInMinutes: number;
  completed: boolean;
}

export interface QuizResults {
  score: number;
  correctCount: number;
  incorrectCount: number;
  skippedCount: number;
  unattemptedCount: number;
  totalQuestions: number;
  timeTaken: string;
  session: QuizSession;
}

