          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" /></svg>
        </button>
        <div>
          <h2 className="text-3xl font-black text-slate-900">Mixed subjects Mock</h2>
          <p className="text-slate-500 font-medium">Full Syllabus Practice (Set 1-40)</p>
        </div>
      </div>
      <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4">
        {Array.from({ length: testsPerPage }).map((_, i) => {
          const testNum = i + 1;
          const testId = `mix-Mixed_Subjects-${testNum}`;
          const isDone = completedTests.has(testId);
          return (
            <button key={testNum} onClick={() => startQuiz(QuizType.MIX, "Mixed Subjects", { testNumber: testNum, testId, count: 25 })} className={`group p-6 rounded-3xl border-2 transition-all text-center relative overflow-hidden ${isDone ? 'bg-emerald-50 border-emerald-500 text-emerald-900' : 'bg-white border-slate-100 hover:border-blue-600 hover:shadow-xl'}`}>
              {isDone && <div className="absolute top-2 right-2 text-emerald-500"><svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" /></svg></div>}
              <span className="text-xs font-black uppercase tracking-widest block mb-2 opacity-50">Set</span>
              <span className="text-4xl font-black block group-hover:scale-110 transition-transform">{testNum}</span>
              <div className={`mt-4 text-[10px] font-bold uppercase tracking-widest ${isDone ? 'text-emerald-600' : 'text-slate-400 group-hover:text-blue-600'}`}>{isDone ? 'Completed' : 'Start Test'}</div>
            </button>
          );
        })}
      </div>
    </div>
  );

  const renderTopicMenu = () => (
    <div className="animate-fadeIn space-y-8">
      <div className="flex items-center gap-4 mb-4">
        <button onClick={() => navigateTo(AppView.HOME)} className="p-3 bg-white border border-slate-200 rounded-2xl text-slate-500"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" /></svg></button>
        <div>
          <h2 className="text-3xl font-black text-slate-900 uppercase tracking-tight">Topic-wise PYQs</h2>
          <p className="text-slate-500">Official board questions categorized by subject.</p>
        </div>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {TOPIC_GROUPS.map((group) => (
          <div key={group.id} className="bg-white rounded-[2.5rem] border border-slate-200 p-8 hover:shadow-xl transition-all">
            <h3 className="text-2xl font-black text-slate-900 mb-6 flex items-center justify-between">{group.name}<span className="text-xs bg-slate-100 text-slate-500 px-3 py-1 rounded-full">{group.subtopics.length} Units</span></h3>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
              {group.subtopics.slice(0, 6).map((sub, i) => {
                const testId = `topic-${sub.replace(/\s+/g, '_')}-0`;
                const isDone = completedTests.has(testId);
                return (
                  <button key={i} onClick={() => startQuiz(QuizType.TOPIC, sub, { testId, topic: sub, count: 20 })} className={`text-left text-sm font-semibold p-3.5 rounded-xl border flex items-center justify-between transition-all hindi-text group/item ${isDone ? 'bg-emerald-50 border-emerald-500 text-emerald-800' : 'border-slate-100 hover:border-emerald-200 hover:bg-emerald-50 text-slate-600 hover:text-emerald-700'}`}>
                    <span>{sub}</span>
                    {isDone ? <svg className="w-5 h-5 text-emerald-600 shrink-0" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" /></svg> : <svg className="w-4 h-4 opacity-0 group-hover/item:opacity-100 transition-opacity" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M13 7l5 5m0 0l-5 5m5-5H6" /></svg>}
                  </button>
                );
              })}
            </div>
            {group.subtopics.length > 6 && <button onClick={() => { setSelectedGroup(group); navigateTo(AppView.QUIZ_SUBTOPIC_MENU); }} className="mt-6 w-full py-3.5 rounded-xl bg-slate-50 text-slate-500 font-black hover:bg-slate-100 transition-all text-xs uppercase tracking-widest">View All {group.subtopics.length} Units</button>}
          </div>
        ))}
      </div>
    </div>
  );

  const renderSubtopicMenu = () => (
    <div className="animate-fadeIn max-w-4xl mx-auto">
      <div className="flex items-center gap-4 mb-12">
        <button onClick={() => navigateTo(AppView.QUIZ_TOPIC_MENU)} className="p-3 bg-white border border-slate-200 rounded-2xl text-slate-500 hover:bg-slate-50"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" /></svg></button>
        <div>
          <h2 className="text-3xl font-black text-slate-900 tracking-tight">{selectedGroup?.name}</h2>
          <p className="text-slate-500 font-medium">Explore all units in this category</p>
        </div>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {selectedGroup?.subtopics.map((sub, i) => {
          const testId = `topic-${sub.replace(/\s+/g, '_')}-0`;
          const isDone = completedTests.has(testId);
          return (
            <button key={i} onClick={() => startQuiz(QuizType.TOPIC, sub, { testId, topic: sub, count: 25 })} className={`flex items-center justify-between p-6 rounded-[2.5rem] border transition-all text-left group ${isDone ? 'bg-emerald-50 border-emerald-500 text-emerald-900 shadow-sm' : 'bg-white border-slate-200 hover:border-blue-600 hover:bg-blue-50/50'}`}>
              <span className="font-bold text-lg hindi-text pr-4 leading-relaxed">{sub}</span>
              {isDone ? <div className="bg-emerald-500 p-2 rounded-xl text-white shadow-lg shadow-emerald-100"><svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" /></svg></div> : <div className="bg-white p-2 rounded-xl border border-slate-100 text-blue-600 group-hover:scale-110 transition-transform"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg></div>}
            </button>
          );
        })}
      </div>
    </div>
  );

  const renderExamMenu = () => {
    const exams = [
      { name: "Lab Assistant 2022 (GK)", year: 2022, context: "Lab Assistant 2022 GK Paper", testId: 'exam-Lab_Assistant_2022_GK_Paper-0' },
      { name: "Lab Assistant 2022 (Science)", year: 2022, context: "Lab Assistant 2022 Science Paper", testId: 'exam-Lab_Assistant_2022_Science_Paper-0' },
      { name: "RSSB CET Graduate Level", year: 2024, context: "CET Graduate Level 2024" },
      { name: "RSSB CET Senior Secondary", year: 2024, context: "CET Senior Secondary 2024" },
      { name: "RSSB LDC Exam", year: 2024, context: "LDC 2024 Exam" },
      { name: "RPSC RAS Prelims", year: 2023, context: "RAS Prelims 2023" },
      { name: "RSSB Patwar Exam", year: 2021, context: "Patwar 2021 Exam" },
      { name: "RSSB REET Exam L-1", year: 2023, context: "REET 2023 Level 1" },
      { name: "RSSB Junior Accountant", year: 2024, context: "Junior Accountant 2024" }
    ];

    return (
      <div className="animate-fadeIn space-y-12">
        <div className="flex items-center gap-4 mb-4">
          <button onClick={() => navigateTo(AppView.HOME)} className="p-3 bg-white border border-slate-200 rounded-2xl text-slate-500 hover:bg-slate-50 transition-all">
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" /></svg>
          </button>
          <div>
            <h2 className="text-3xl font-black text-slate-900 tracking-tight uppercase">Official Exam Portal</h2>
            <p className="text-slate-500 font-medium">Full papers as held by RSSB & RPSC boards.</p>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {exams.map((exam, i) => {
            const testId = exam.testId || `exam-${exam.name.replace(/\s+/g, '_')}-0`;
            const isDone = completedTests.has(testId);
            return (
              <div key={i} className={`bg-white rounded-[2.5rem] border p-8 hover:shadow-2xl transition-all group relative ${isDone ? 'border-emerald-500 shadow-emerald-50' : 'border-slate-200'}`}>
                {isDone && (
                  <div className="absolute top-6 right-6 bg-emerald-500 text-white p-2 rounded-xl shadow-lg shadow-emerald-100 z-10">
                    <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" /></svg>
                  </div>
                )}
                <div className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400 mb-2">{exam.year} Edition</div>
                <h3 className="text-2xl font-black text-slate-900 mb-6 group-hover:text-blue-600 transition-colors leading-tight">{exam.name}</h3>
                <button 
                  onClick={() => startQuiz(QuizType.EXAM, exam.name, { testId, examContext: exam.context, count: 100 })}
                  className={`w-full py-4 rounded-2xl font-black transition-all flex items-center justify-center gap-2 shadow-lg ${isDone ? 'bg-emerald-100 text-emerald-800 hover:bg-emerald-200 shadow-emerald-50' : 'bg-slate-900 text-white hover:bg-blue-600 shadow-slate-200'}`}
                >
                  {isDone ? 'Revision Mode' : 'Start Official Mock'}
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M14 5l7 7m0 0l-7 7m7-7H3" /></svg>
                </button>
              </div>
            );
          })}
        </div>
      </div>
    );
  };

  return (
    <Layout 
      onHomeClick={() => navigateTo(AppView.HOME)} 
      onLogout={handleLogout} 
      isLoggedIn={isLoggedIn}
    >
      {loading ? (
        <div className="flex flex-col items-center justify-center min-h-[60vh] animate-pulse">
          <div className="w-20 h-20 border-[10px] border-blue-600 border-t-transparent rounded-full animate-spin mb-8 shadow-xl shadow-blue-50"></div>
          <h2 className="text-2xl font-black text-slate-900 mb-2 uppercase tracking-tighter text-center">Connecting RAJQUIZER...</h2>
          <p className="text-slate-500 font-medium tracking-wide uppercase text-[10px] text-center">Fetching original board PYQs securely. Please wait.</p>
        </div>
      ) : (
        <>
          {view === AppView.AUTH && renderAuth()}
          {view === AppView.HOME && renderHome()}
          {view === AppView.QUIZ_MIX_MENU && renderMixMenu()}
          {view === AppView.QUIZ_TOPIC_MENU && renderTopicMenu()}
          {view === AppView.QUIZ_SUBTOPIC_MENU && renderSubtopicMenu()}
          {view === AppView.EXAM_MENU && renderExamMenu()}

          {view === AppView.QUIZ_ACTIVE && activeSession && (
            <QuizEngine 
              session={activeSession} 
              onComplete={onQuizComplete}
              onExit={() => navigateTo(AppView.HOME)}
            />
          )}

          {view === AppView.SCORECARD && lastResults && (
            <ScoreCard 
              results={lastResults} 
              onReview={() => navigateTo(AppView.REVIEW)}
              onNextTest={() => navigateTo(AppView.HOME)}
              onBackHome={() => navigateTo(AppView.HOME)}
            />
          )}

          {view === AppView.REVIEW && lastResults && (
            <QuizEngine 
              session={lastResults.session} 
              onComplete={() => {}}
              onExit={() => navigateTo(AppView.SCORECARD)}
              isReview={true}
            />
          )}
        </>
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect, useCallback } from 'react';
import Layout from './components/Layout';
import QuizEngine from './components/QuizEngine';
import ScoreCard from './components/ScoreCard';
import { 
  AppView, 
  AuthSubView,
  QuizSession, 
  QuizType, 
  QuizResults 
} from './types';
import { 
  TOPIC_GROUPS,
  TopicGroup,
  MARKING_SCHEME 
} from './constants';
import { fetchPYQs } from './services/geminiService';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.AUTH);
  const [authStep, setAuthStep] = useState<AuthSubView>(AuthSubView.CHOICE);
  const [isLoggedIn, setIsLoggedIn] = useState(false);

  const [phone, setPhone] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [otp, setOtp] = useState('');

  const [activeSession, setActiveSession] = useState<QuizSession | null>(null);
  const [lastResults, setLastResults] = useState<QuizResults | null>(null);
  const [loading, setLoading] = useState(false);
  const [selectedGroup, setSelectedGroup] = useState<TopicGroup | null>(null);
  const [completedTests, setCompletedTests] = useState<Set<string>>(new Set());
  const [isSynced, setIsSynced] = useState(false);

  const testsPerPage = 40;

  // --- Persistence & Sync Logic ---
  useEffect(() => {
    const savedUser = localStorage.getItem('rajquiz_currentUser');
    if (savedUser) {
      setIsLoggedIn(true);
      setView(AppView.HOME);
    }
    const savedProgress = localStorage.getItem('rajquiz_progress');
    if (savedProgress) {
      try {
        setCompletedTests(new Set(JSON.parse(savedProgress)));
      } catch (e) { 
        console.error("Failed to load progress", e); 
      }
    }

    // Check if we have cached questions
    const cacheCount = Object.keys(localStorage).filter(k => k.startsWith('qcache_')).length;
    if (cacheCount > 5) setIsSynced(true);
  }, []);

  const prefetchQuestions = async () => {
    if (!isLoggedIn) return;
    try {
      // Prefetch a mix set and one topic set as a background priority
      const mixData = await fetchPYQs({ count: 30, isMix: true });
      if (mixData.length > 0) {
        localStorage.setItem('qcache_mix_default', JSON.stringify(mixData));
        setIsSynced(true);
      }
    } catch (e) {
      console.warn("Background sync failed", e);
    }
  };

  useEffect(() => {
    if (isLoggedIn) {
      prefetchQuestions();
    }
  }, [isLoggedIn]);

  const getUsers = () => {
    const users = localStorage.getItem('rajquiz_users');
    return users ? JSON.parse(users) : {};
  };

  const saveUser = (phone: string, pass: string) => {
    const users = getUsers();
    users[phone] = { password: pass };
    localStorage.setItem('rajquiz_users', JSON.stringify(users));
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const users = getUsers();
    if (users[phone] && users[phone].password === password) {
      localStorage.setItem('rajquiz_currentUser', phone);
      setIsLoggedIn(true);
      setView(AppView.HOME);
    } else {
      alert("गलत फोन नंबर या पासवर्ड।");
    }
  };

  const handleSignup = (e: React.FormEvent) => {
    e.preventDefault();
    if (phone.length !== 10) return alert("कृपया 10 अंकों का नंबर डालें");
    if (password.length < 4) return alert("पासवर्ड कम से कम 4 अक्षरों का होना चाहिए");
    if (password !== confirmPassword) return alert("पासवर्ड मैच नहीं कर रहे हैं");
    const users = getUsers();
    if (users[phone]) return alert("यह नंबर पहले से ही रजिस्टर्ड है।");
    saveUser(phone, password);
    alert("अकाउंट बन गया है! अब लॉगिन करें।");
    setAuthStep(AuthSubView.LOGIN);
    setPassword('');
    setConfirmPassword('');
  };

  const handleForgotPhone = (e: React.FormEvent) => {
    e.preventDefault();
    const users = getUsers();
    if (!users[phone]) return alert("यह नंबर रजिस्टर्ड नहीं है।");
    setAuthStep(AuthSubView.FORGOT_OTP);
    alert("OTP '1234' भेज दिया गया है (सिमुलेशन)");
  };

  const handleVerifyOtp = (e: React.FormEvent) => {
    e.preventDefault();
    if (otp === '1234') {
      setAuthStep(AuthSubView.RESET_PASSWORD);
      setOtp('');
    } else {
      alert("गलत OTP।");
    }
  };

  const handleResetPassword = (e: React.FormEvent) => {
    e.preventDefault();
    if (password.length < 4) return alert("पासवर्ड कम से कम 4 अक्षरों का होना चाहिए");
    if (password !== confirmPassword) return alert("पासवर्ड मैच नहीं कर रहे हैं");
    saveUser(phone, password);
    alert("पासवर्ड बदल दिया गया है!");
    setAuthStep(AuthSubView.LOGIN);
    setPassword('');
    setConfirmPassword('');
  };

  const handleLogout = () => {
    if (window.confirm("लॉगआउट करना चाहते हैं?")) {
      localStorage.removeItem('rajquiz_currentUser');
      setIsLoggedIn(false);
      setAuthStep(AuthSubView.CHOICE);
      setView(AppView.AUTH);
    }
  };

  const navigateTo = (newView: AppView) => {
    setView(newView);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const markTestCompleted = (testId: string) => {
    setCompletedTests(prev => {
      const newSet = new Set(prev);
      newSet.add(testId);
      localStorage.setItem('rajquiz_progress', JSON.stringify(Array.from(newSet)));
      return newSet;
    });
  };

  const startQuiz = useCallback(async (type: QuizType, title: string, options: { 
    subject?: string; 
    topic?: string; 
    count?: number; 
    testId?: string;
    testNumber?: number;
    examContext?: string;
  } = {}) => {
    const finalTestId = options.testId || `${type}-${(options.topic || title).replace(/\s+/g, '_')}-${options.testNumber || 0}`;

    // Check local cache first for instant opening
    const cacheKey = `qcache_${finalTestId}`;
    const cached = localStorage.getItem(cacheKey);

    if (cached) {
      const questions = JSON.parse(cached);
      const session: QuizSession = {
        type, title: `${title} ${options.testNumber ? `- Set ${options.testNumber}` : ''}`,
        questions, currentQuestionIndex: 0, userAnswers: {}, startTime: Date.now(),
        durationInMinutes: type === QuizType.AI ? 15 : (options.count && options.count > 50 ? 120 : 60),
        completed: false
      };
      (session as any).testId = finalTestId;
      setActiveSession(session);
      navigateTo(AppView.QUIZ_ACTIVE);
      return;
    }

    setLoading(true);
    try {
      const questions = await fetchPYQs({
        count: options.count || 25,
        subject: options.subject,
        topic: options.topic,
        isMix: type === QuizType.MIX || type === QuizType.AI,
        testNumber: options.testNumber,
        examContext: options.examContext
      });

      if (!questions || questions.length === 0) throw new Error("No questions returned");

      // Save to cache for next time or offline use
      localStorage.setItem(cacheKey, JSON.stringify(questions));

      const session: QuizSession = {
        type, title: `${title} ${options.testNumber ? `- Set ${options.testNumber}` : ''}`,
        questions, currentQuestionIndex: 0, userAnswers: {}, startTime: Date.now(),
        durationInMinutes: type === QuizType.AI ? 15 : (options.count && options.count > 50 ? 120 : 60),
        completed: false
      };
      (session as any).testId = finalTestId;
      setActiveSession(session);
      navigateTo(AppView.QUIZ_ACTIVE);
    } catch (error) {
      console.error("Quiz Start Error:", error);
      alert("सर्वर से लोड करने में विफल। अगर आपने इसे पहले खेला है तो ये बिना इंटरनेट के भी चल सकता है।");
    } finally {
      setLoading(false);
    }
  }, []);

  const onQuizComplete = (session: QuizSession) => {
    let score = 0, correct = 0, incorrect = 0, skipped = 0, unattempted = 0;
    session.questions.forEach(q => {
      const ans = session.userAnswers[q.id];
      if (!ans) { score += MARKING_SCHEME.UNATTEMPTED; unattempted++; }
      else if (ans === 'E') skipped++;
      else if (ans === q.correctAnswer) { score += MARKING_SCHEME.CORRECT; correct++; }
      else { score += MARKING_SCHEME.WRONG; incorrect++; }
    });
    setLastResults({ score, correctCount: correct, incorrectCount: incorrect, skippedCount: skipped, unattemptedCount: unattempted, totalQuestions: session.questions.length, timeTaken: 'N/A', session });
    const tId = (session as any).testId;
    if (tId) markTestCompleted(tId);
    navigateTo(AppView.SCORECARD);
  };

  const renderAuth = () => {
    const cardClass = "bg-white p-10 md:p-14 rounded-[4rem] shadow-2xl border border-slate-100 w-full max-w-lg animate-fadeIn";
    const labelClass = "text-xs font-black uppercase tracking-widest text-slate-500 ml-1";
    const inputClass = "w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-6 py-5 outline-none focus:border-blue-600 focus:bg-white transition-all font-bold text-lg";

    // LOGIN BUTTON: Standard Large
    const loginBtnClass = "w-full bg-slate-100 text-slate-900 py-6 rounded-2xl font-black text-xl hover:bg-slate-200 hover:-translate-y-1 transition-all active:scale-95 flex items-center justify-center gap-4 mt-4 border-2 border-slate-200";

    // SIGNUP BUTTON: Massive & Extra High-Impact
    const signupBtnClass = "w-full bg-gradient-to-r from-blue-600 to-indigo-700 text-white py-10 rounded-3xl font-black text-3xl shadow-2xl shadow-blue-200 hover:scale-[1.02] hover:-translate-y-2 transition-all active:scale-95 flex flex-col items-center justify-center gap-2 relative overflow-hidden group";

    return (
      <div className="min-h-[85vh] flex items-center justify-center px-4">
        {authStep === AuthSubView.CHOICE && (
          <div className={cardClass}>
            <div className="text-center mb-12">
              <div className="w-20 h-20 bg-blue-600 rounded-3xl flex items-center justify-center mx-auto mb-6 shadow-xl shadow-blue-100">
