            const testId = exam.testId || `exam-${exam.name.replace(/\s+/g, '_')}-0`;
            const isDone = completedTests.has(testId);
            const isCached = !!localStorage.getItem(`qcache_${testId}`);
            return (
              <div key={i} className={`bg-white rounded-[2.5rem] border p-10 hover:shadow-2xl transition-all group relative ${isDone ? 'border-emerald-500 shadow-emerald-50' : 'border-slate-200'}`}>
                {isDone && (
                  <div className="absolute top-8 right-8 bg-emerald-500 text-white p-2 rounded-xl shadow-lg shadow-emerald-100 z-10">
                    <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" /></svg>
                  </div>
                )}
                <div className="text-[10px] font-black uppercase tracking-[0.3em] text-slate-400 mb-2">{exam.year} EDITION</div>
                <h3 className="text-2xl font-black text-slate-900 mb-8 group-hover:text-blue-600 transition-colors leading-tight">{exam.name}</h3>
                <button 
                  onClick={() => startQuiz(QuizType.EXAM, exam.name, { testId, examContext: exam.context, count: 100 })}
                  className={`w-full py-5 rounded-2xl font-black transition-all flex items-center justify-center gap-2 shadow-lg ${isDone ? 'bg-emerald-100 text-emerald-800 hover:bg-emerald-200 shadow-emerald-50' : 'bg-slate-900 text-white hover:bg-blue-600 shadow-slate-200'}`}
                >
                  {isDone ? 'Revision Mode' : 'Start Official Mock'}
                </button>
                {isCached && <div className="mt-4 text-center text-[10px] font-black text-blue-500 uppercase tracking-widest">Cached for Offline</div>}
              </div>
            );
          })}
        </div>
      </div>
    );
  };

  return (
    <Layout 
      onHomeClick={() => navigateTo(AppView.HOME)} 
      onLogout={handleLogout} 
      isLoggedIn={isLoggedIn}
    >
      {loading ? (
        <div className="flex flex-col items-center justify-center min-h-[60vh] animate-pulse">
          <div className="w-20 h-20 border-[10px] border-blue-600 border-t-transparent rounded-full animate-spin mb-8 shadow-xl shadow-blue-50"></div>
          <h2 className="text-2xl font-black text-slate-900 mb-2 uppercase tracking-tighter text-center">Connecting RAJQUIZER...</h2>
          <p className="text-slate-500 font-bold tracking-widest uppercase text-[10px] text-center">Opening question pool. This is instant if cached.</p>
        </div>
      ) : (
        <>
          {view === AppView.AUTH && renderAuth()}
          {view === AppView.HOME && renderHome()}
          {view === AppView.QUIZ_MIX_MENU && renderMixMenu()}
          {view === AppView.QUIZ_TOPIC_MENU && renderTopicMenu()}
          {view === AppView.QUIZ_SUBTOPIC_MENU && renderSubtopicMenu()}
          {view === AppView.EXAM_MENU && renderExamMenu()}

          {view === AppView.QUIZ_ACTIVE && activeSession && (
            <QuizEngine 
              session={activeSession} 
              onComplete={onQuizComplete}
              onExit={() => navigateTo(AppView.HOME)}
            />
          )}

          {view === AppView.SCORECARD && lastResults && (
            <ScoreCard 
              results={lastResults} 
              onReview={() => navigateTo(AppView.REVIEW)}
              onNextTest={() => navigateTo(AppView.HOME)}
              onBackHome={() => navigateTo(AppView.HOME)}
            />
          )}

          {view === AppView.REVIEW && lastResults && (
            <QuizEngine 
              session={lastResults.session} 
              onComplete={() => {}}
              onExit={() => navigateTo(AppView.SCORECARD)}
              isReview={true}
            />
          )}
        </>
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect, useCallback } from 'react';
import Layout from './components/Layout';
import QuizEngine from './components/QuizEngine';
import ScoreCard from './components/ScoreCard';
import { 
  AppView, 
  AuthSubView,
  QuizSession, 
  QuizType, 
  QuizResults 
} from './types';
import { 
  TOPIC_GROUPS,
  TopicGroup,
  MARKING_SCHEME 
} from './constants';
import { fetchPYQs } from './services/geminiService';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.AUTH);
  const [authStep, setAuthStep] = useState<AuthSubView>(AuthSubView.CHOICE);
  const [isLoggedIn, setIsLoggedIn] = useState(false);

  const [phone, setPhone] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [otp, setOtp] = useState('');

  const [activeSession, setActiveSession] = useState<QuizSession | null>(null);
  const [lastResults, setLastResults] = useState<QuizResults | null>(null);
  const [loading, setLoading] = useState(false);
  const [selectedGroup, setSelectedGroup] = useState<TopicGroup | null>(null);
  const [completedTests, setCompletedTests] = useState<Set<string>>(new Set());
  const [syncProgress, setSyncProgress] = useState<number>(0);
  const [isSyncing, setIsSyncing] = useState(false);

  const testsPerPage = 40;

  // --- Persistence & Sync Logic ---
  useEffect(() => {
    const savedUser = localStorage.getItem('rajquiz_currentUser');
    if (savedUser) {
      setIsLoggedIn(true);
      setView(AppView.HOME);
    }
    const savedProgress = localStorage.getItem('rajquiz_progress');
    if (savedProgress) {
      try {
        setCompletedTests(new Set(JSON.parse(savedProgress)));
      } catch (e) { 
        console.error("Failed to load progress", e); 
      }
    }
  }, []);

  const downloadFullDatabase = async () => {
    if (isSyncing) return;
    setIsSyncing(true);
    setSyncProgress(10);
    try {
      // Pre-fetch multiple sets to local storage for offline use
      const mixSet = await fetchPYQs({ count: 50, isMix: true, testNumber: 1 });
      localStorage.setItem('qcache_mix_default', JSON.stringify(mixSet));
      setSyncProgress(50);

      const topicSet = await fetchPYQs({ count: 50, subject: 'Rajasthan GK', topic: 'इतिहास' });
      localStorage.setItem('qcache_topic_hist_default', JSON.stringify(topicSet));
      setSyncProgress(100);

      setTimeout(() => setIsSyncing(false), 2000);
    } catch (e) {
      console.warn("Sync partially failed", e);
      setIsSyncing(false);
    }
  };

  useEffect(() => {
    if (isLoggedIn && !localStorage.getItem('qcache_mix_default')) {
      downloadFullDatabase();
    }
  }, [isLoggedIn]);

  const getUsers = () => {
    const users = localStorage.getItem('rajquiz_users');
    return users ? JSON.parse(users) : {};
  };

  const saveUser = (phone: string, pass: string) => {
    const users = getUsers();
    users[phone] = { password: pass };
    localStorage.setItem('rajquiz_users', JSON.stringify(users));
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const users = getUsers();
    if (users[phone] && users[phone].password === password) {
      localStorage.setItem('rajquiz_currentUser', phone);
      setIsLoggedIn(true);
      setView(AppView.HOME);
    } else {
      alert("गलत फोन नंबर या पासवर्ड।");
    }
  };

  const handleSignup = (e: React.FormEvent) => {
    e.preventDefault();
    if (phone.length !== 10) return alert("कृपया 10 अंकों का नंबर डालें");

    const users = getUsers();
    // UNIQUE REGISTRATION CHECK
    if (users[phone]) {
      alert("यह नंबर पहले से ही रजिस्टर्ड है। (This number is already registered). कृपया लॉगिन करें।");
      setAuthStep(AuthSubView.LOGIN);
      return;
    }

    if (password.length < 4) return alert("पासवर्ड कम से कम 4 अक्षरों का होना चाहिए");
    if (password !== confirmPassword) return alert("पासवर्ड मैच नहीं कर रहे हैं");

    saveUser(phone, password);
    alert("अकाउंट सफलतापूर्वक बन गया है! अब आप लॉगिन कर सकते हैं।");
    setAuthStep(AuthSubView.LOGIN);
    setPassword('');
    setConfirmPassword('');
  };

  const handleForgotPhone = (e: React.FormEvent) => {
    e.preventDefault();
    const users = getUsers();
    if (!users[phone]) return alert("यह नंबर रजिस्टर्ड नहीं है।");
    setAuthStep(AuthSubView.FORGOT_OTP);
    alert("OTP '1234' भेज दिया गया है (सिमुलेशन)");
  };

  const handleVerifyOtp = (e: React.FormEvent) => {
    e.preventDefault();
    if (otp === '1234') {
      setAuthStep(AuthSubView.RESET_PASSWORD);
      setOtp('');
    } else {
      alert("गलत OTP।");
    }
  };

  const handleResetPassword = (e: React.FormEvent) => {
    e.preventDefault();
    if (password.length < 4) return alert("पासवर्ड कम से कम 4 अक्षरों का होना चाहिए");
    if (password !== confirmPassword) return alert("पासवर्ड मैच नहीं कर रहे हैं");
    saveUser(phone, password);
    alert("पासवर्ड सफलतापूर्वक बदल दिया गया है!");
    setAuthStep(AuthSubView.LOGIN);
    setPassword('');
    setConfirmPassword('');
  };

  const handleLogout = () => {
    if (window.confirm("लॉगआउट करना चाहते हैं?")) {
      localStorage.removeItem('rajquiz_currentUser');
      setIsLoggedIn(false);
      setAuthStep(AuthSubView.CHOICE);
      setView(AppView.AUTH);
    }
  };

  const navigateTo = (newView: AppView) => {
    setView(newView);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const markTestCompleted = (testId: string) => {
    setCompletedTests(prev => {
      const newSet = new Set(prev);
      newSet.add(testId);
      localStorage.setItem('rajquiz_progress', JSON.stringify(Array.from(newSet)));
      return newSet;
    });
  };

  const startQuiz = useCallback(async (type: QuizType, title: string, options: { 
    subject?: string; 
    topic?: string; 
    count?: number; 
    testId?: string;
    testNumber?: number;
    examContext?: string;
  } = {}) => {
    const finalTestId = options.testId || `${type}-${(options.topic || title).replace(/\s+/g, '_')}-${options.testNumber || 0}`;

    // OFFLINE / CACHE FIRST LOGIC
    const cacheKey = `qcache_${finalTestId}`;
    const cached = localStorage.getItem(cacheKey) || (type === QuizType.MIX ? localStorage.getItem('qcache_mix_default') : null);

    if (cached) {
      const questions = JSON.parse(cached);
      const session: QuizSession = {
        type, title: `${title} ${options.testNumber ? `- Set ${options.testNumber}` : ''}`,
        questions, currentQuestionIndex: 0, userAnswers: {}, startTime: Date.now(),
        durationInMinutes: type === QuizType.AI ? 15 : (options.count && options.count > 50 ? 120 : 60),
        completed: false
      };
      (session as any).testId = finalTestId;
      setActiveSession(session);
      navigateTo(AppView.QUIZ_ACTIVE);
      return;
    }

    setLoading(true);
    try {
      const questions = await fetchPYQs({
        count: options.count || 25,
        subject: options.subject,
        topic: options.topic,
        isMix: type === QuizType.MIX || type === QuizType.AI,
        testNumber: options.testNumber,
        examContext: options.examContext
      });

      if (!questions || questions.length === 0) throw new Error("No questions returned");

      // Save for offline access
      localStorage.setItem(cacheKey, JSON.stringify(questions));

      const session: QuizSession = {
        type, title: `${title} ${options.testNumber ? `- Set ${options.testNumber}` : ''}`,
        questions, currentQuestionIndex: 0, userAnswers: {}, startTime: Date.now(),
        durationInMinutes: type === QuizType.AI ? 15 : (options.count && options.count > 50 ? 120 : 60),
        completed: false
      };
      (session as any).testId = finalTestId;
      setActiveSession(session);
      navigateTo(AppView.QUIZ_ACTIVE);
    } catch (error) {
      console.error("Quiz Start Error:", error);
      alert("सर्वर से कनेक्ट नहीं हो सका। ऑफलाइन मोड में केवल पहले खेले गए क्विज चलेंगे।");
    } finally {
      setLoading(false);
    }
  }, []);

  const onQuizComplete = (session: QuizSession) => {
    let score = 0, correct = 0, incorrect = 0, skipped = 0, unattempted = 0;
    session.questions.forEach(q => {
      const ans = session.userAnswers[q.id];
      if (!ans) { score += MARKING_SCHEME.UNATTEMPTED; unattempted++; }
      else if (ans === 'E') skipped++;
      else if (ans === q.correctAnswer) { score += MARKING_SCHEME.CORRECT; correct++; }
      else { score += MARKING_SCHEME.WRONG; incorrect++; }
    });
    setLastResults({ score, correctCount: correct, incorrectCount: incorrect, skippedCount: skipped, unattemptedCount: unattempted, totalQuestions: session.questions.length, timeTaken: 'N/A', session });
    const tId = (session as any).testId;
    if (tId) markTestCompleted(tId);
    navigateTo(AppView.SCORECARD);
  };

  const renderAuth = () => {
    const cardClass = "bg-white p-10 md:p-14 rounded-[4rem] shadow-2xl border border-slate-100 w-full max-w-lg animate-fadeIn";
    const labelClass = "text-xs font-black uppercase tracking-widest text-slate-500 ml-1";
    const inputClass = "w-full bg-slate-50 border-2 border-slate-100 rounded-3xl px-8 py-5 outline-none focus:border-blue-600 focus:bg-white transition-all font-bold text-xl";

    // MASSIVE SIGNUP BUTTON
    const bigSignupBtn = "w-full bg-gradient-to-r from-blue-700 to-indigo-800 text-white py-12 rounded-[2.5rem] font-black text-4xl shadow-2xl shadow-blue-200 hover:scale-[1.03] hover:-translate-y-2 transition-all active:scale-95 flex flex-col items-center justify-center gap-3 relative overflow-hidden group mb-8";
    const loginBtnClass = "w-full bg-slate-100 text-slate-700 py-6 rounded-[2rem] font-black text-xl border-2 border-slate-200 hover:bg-slate-200 transition-all flex items-center justify-center gap-3";

    return (
      <div className="min-h-[85vh] flex items-center justify-center px-4">
        {authStep === AuthSubView.CHOICE && (
          <div className={cardClass}>
            <div className="text-center mb-12">
              <h2 className="text-4xl font-black text-slate-900 mb-2 uppercase tracking-tighter">RAJQUIZER</h2>
              <p className="text-slate-400 font-bold tracking-[0.3em] text-[10px] uppercase opacity-70">Official PYQ Portal</p>
            </div>

            <button onClick={() => setAuthStep(AuthSubView.SIGNUP)} className={bigSignupBtn}>
               <span className="relative z-10">SIGN UP</span>
               <span className="text-xs font-bold opacity-60 tracking-widest relative z-10 uppercase">Create New Account</span>
               <div className="absolute inset-0 bg-white/10 -translate-x-full group-hover:translate-x-0 transition-transform duration-500"></div>
            </button>

            <div className="relative flex items-center justify-center mb-8">
               <div className="absolute inset-0 flex items-center"><div className="w-full border-t border-slate-100"></div></div>
               <span className="relative bg-white px-4 text-[10px] font-black text-slate-300 uppercase tracking-widest">OR</span>
            </div>

            <button onClick={() => setAuthStep(AuthSubView.LOGIN)} className={loginBtnClass}>
               LOGIN
               <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M11 16l-4-4m0 0l4-4m-4 4h14" /></svg>
            </button>
          </div>
        )}

        {authStep === AuthSubView.SIGNUP && (
          <div className={cardClass}>
            <button onClick={() => setAuthStep(AuthSubView.CHOICE)} className="mb-6 text-slate-400 font-bold text-sm flex items-center gap-1 hover:text-blue-600 transition-colors"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" /></svg> Back</button>
            <div className="text-center mb-10">
              <h2 className="text-3xl font-black text-slate-900 mb-2 uppercase">Register</h2>
              <p className="text-slate-400 font-medium">Join 10,000+ Students</p>
            </div>
            <form onSubmit={handleSignup} className="space-y-5">
              <div className="space-y-2">
                <label className={labelClass}>Mobile Number</label>
                <input type="tel" value={phone} onChange={e => setPhone(e.target.value.replace(/\D/g, '').slice(0, 10))} placeholder="10 Digit Number" className={inputClass} required />
              </div>
              <div className="space-y-2">
                <label className={labelClass}>Set Password</label>
                <input type="password" value={password} onChange={e => setPassword(e.target.value)} placeholder="Minimum 4 Chars" className={inputClass} required />
              </div>
              <div className="space-y-2">
                <label className={labelClass}>Confirm Password</label>
                <input type="password" value={confirmPassword} onChange={e => setConfirmPassword(e.target.value)} placeholder="Repeat Password" className={inputClass} required />
              </div>
              <button type="submit" className="w-full bg-slate-900 text-white py-6 rounded-[2rem] font-black text-xl shadow-2xl shadow-slate-200 mt-4">Register Now</button>
            </form>
          </div>
        )}

        {authStep === AuthSubView.LOGIN && (
          <div className={cardClass}>
             <button onClick={() => setAuthStep(AuthSubView.CHOICE)} className="mb-6 text-slate-400 font-bold text-sm flex items-center gap-1 hover:text-blue-600 transition-colors"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" /></svg> Back</button>
            <div className="text-center mb-10">
              <h2 className="text-3xl font-black text-slate-900 mb-2 uppercase">Login</h2>
            </div>
            <form onSubmit={handleLogin} className="space-y-5">
              <div className="space-y-2">
                <label className={labelClass}>Phone Number</label>
                <input type="tel" value={phone} onChange={e => setPhone(e.target.value.replace(/\D/g, '').slice(0, 10))} placeholder="9876543210" className={inputClass} required />
              </div>
              <div className="space-y-2">
                <label className={labelClass}>Password</label>
                <input type="password" value={password} onChange={e => setPassword(e.target.value)} placeholder="••••••••" className={inputClass} required />
              </div>
              <button type="submit" className="w-full bg-blue-600 text-white py-6 rounded-[2rem] font-black text-xl mt-4">Login</button>
            </form>
            <div className="mt-6 text-center">
              <button onClick={() => { setAuthStep(AuthSubView.FORGOT_PHONE); setPhone(''); }} className="text-blue-600 font-bold text-sm hover:underline">Forgot Password?</button>
            </div>
          </div>
        )}

        {/* Forgot Password Flow */}
        {authStep === AuthSubView.FORGOT_PHONE && (
          <div className={cardClass}>
            <button onClick={() => setAuthStep(AuthSubView.LOGIN)} className="mb-6 text-slate-400 font-bold text-sm flex items-center gap-1 hover:text-blue-600 transition-colors"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" /></svg> Back</button>
            <div className="text-center mb-10">
              <h2 className="text-3xl font-black text-slate-900 mb-2 uppercase tracking-tighter">Recover</h2>
            </div>
            <form onSubmit={handleForgotPhone} className="space-y-4">
              <input type="tel" value={phone} onChange={e => setPhone(e.target.value.replace(/\D/g, '').slice(0, 10))} placeholder="Registered Phone" className={inputClass} required />
              <button type="submit" className="w-full bg-blue-600 text-white py-6 rounded-[2rem] font-black text-xl">Send OTP</button>
            </form>
          </div>
        )}
        {authStep === AuthSubView.FORGOT_OTP && (
          <div className={cardClass}>
             <div className="text-center mb-10">
                <h2 className="text-3xl font-black text-slate-900 mb-2 uppercase">Verify</h2>
                <p className="text-slate-400 font-medium">Use '1234'</p>
             </div>
             <form onSubmit={handleVerifyOtp} className="space-y-4">
                <input type="text" value={otp} onChange={e => setOtp(e.target.value.replace(/\D/g, '').slice(0, 4))} placeholder="1234" className={`${inputClass} text-center tracking-[0.5em]`} required />
                <button type="submit" className="w-full bg-blue-600 text-white py-6 rounded-[2rem] font-black text-xl">Verify Code</button>
             </form>
          </div>
        )}
        {authStep === AuthSubView.RESET_PASSWORD && (
          <div className={cardClass}>
             <div className="text-center mb-10">
                <h2 className="text-3xl font-black text-slate-900 mb-2 uppercase">New Pass</h2>
             </div>
             <form onSubmit={handleResetPassword} className="space-y-4">
                <input type="password" value={password} onChange={e => setPassword(e.target.value)} placeholder="New Password" className={inputClass} required />
                <input type="password" value={confirmPassword} onChange={e => setConfirmPassword(e.target.value)} placeholder="Confirm" className={inputClass} required />
                <button type="submit" className="w-full bg-slate-900 text-white py-6 rounded-[2rem] font-black text-xl">Save</button>
             </form>
          </div>
        )}
      </div>
    );
  };

  const renderHome = () => (
    <div className="animate-fadeIn max-w-6xl mx-auto space-y-12">
      <section className="text-center space-y-4">
        <div className="inline-flex items-center gap-2 bg-blue-50 text-blue-700 px-5 py-2 rounded-full text-xs font-black uppercase tracking-widest mb-2 border border-blue-100">
          <span className={`w-2 h-2 rounded-full ${isSyncing ? 'bg-blue-600 animate-pulse' : 'bg-emerald-500 shadow-lg shadow-emerald-200'}`}></span>
          {isSyncing ? `Database Syncing... ${syncProgress}%` : 'Database Ready (Offline Sync Active)'}
        </div>
        <h1 className="text-5xl md:text-7xl font-black text-slate-900 tracking-tight">
          Target <span className="text-blue-600 uppercase">RSSB</span> Exams
        </h1>
        <p className="text-slate-500 text-lg md:text-xl max-w-2xl mx-auto font-medium">
          Prepare for CET, RAS, LDC and Patwar with 100% official board questions.
        </p>
      </section>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        <div onClick={() => navigateTo(AppView.QUIZ_MIX_MENU)} className="group bg-gradient-to-br from-indigo-950 to-slate-900 p-10 rounded-[4rem] shadow-2xl hover:-translate-y-2 transition-all cursor-pointer text-white border border-white/5 relative overflow-hidden">
          <div className="w-16 h-16 bg-white/5 text-indigo-400 rounded-3xl flex items-center justify-center mb-8 group-hover:scale-110 transition-transform backdrop-blur-md border border-white/10">
            <svg className="w-9 h-9" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" /></svg>
          </div>
