}

export interface Question {
  id: string;
  question: string;
  options: {
    A: string;
    B: string;
    C: string;
    D: string;
    E: string;
  };
  correctAnswer: 'A' | 'B' | 'C' | 'D' | 'E';
  examName: string;
  examYear: number;
  subject: string;
  topic?: string;
}

export interface QuizSession {
  type: QuizType;
  title: string;
  questions: Question[];
  currentQuestionIndex: number;
  userAnswers: Record<string, 'A' | 'B' | 'C' | 'D' | 'E' | null>;
  startTime: number;
  durationInMinutes: number;
  completed: boolean;
}

export interface QuizResults {
  score: number;
  correctCount: number;
  incorrectCount: number;
  skippedCount: number;
  unattemptedCount: number;
  totalQuestions: number;
  timeTaken: string;
  session: QuizSession;
}

export interface AttemptRecord {
  id: string;
  title: string;
  score: number;
  maxScore: number;
  date: number;
  correct: number;
  total: number;
}

