            </button>

            <div className="relative flex items-center justify-center mb-8">
               <div className="absolute inset-0 flex items-center"><div className="w-full border-t border-slate-100"></div></div>
               <span className="relative bg-white px-4 text-[10px] font-black text-slate-300 uppercase tracking-widest">Existing Member?</span>
            </div>

            <button onClick={() => setAuthStep(AuthSubView.LOGIN)} className={loginBtnClass}>
               LOGIN NOW
               <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M11 16l-4-4m0 0l4-4m-4 4h14" /></svg>
            </button>
          </div>
        )}

        {authStep === AuthSubView.SIGNUP && (
          <div className={cardClass}>
            <button onClick={() => setAuthStep(AuthSubView.CHOICE)} className="mb-6 text-slate-400 font-bold text-sm flex items-center gap-1 hover:text-blue-600 transition-colors">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" /></svg> Back
            </button>
            <h2 className="text-3xl font-black text-slate-900 mb-8 uppercase text-center tracking-tighter">Register</h2>
            <form onSubmit={handleSignup} className="space-y-5">
              <div>
                <label className={labelClass}>Mobile Number</label>
                <input type="tel" value={phone} onChange={e => setPhone(e.target.value.replace(/\D/g, '').slice(0, 10))} placeholder="10 अंकों का नंबर" className={inputClass} required />
              </div>
              <div>
                <label className={labelClass}>Set Password</label>
                <input type="password" value={password} onChange={e => setPassword(e.target.value)} placeholder="Minimum 4 अक्षर" className={inputClass} required />
              </div>
              <div>
                <label className={labelClass}>Confirm Password</label>
                <input type="password" value={confirmPassword} onChange={e => setConfirmPassword(e.target.value)} placeholder="पासवर्ड पुनः लिखें" className={inputClass} required />
              </div>
              <button type="submit" className="w-full bg-slate-900 text-white py-6 rounded-[2rem] font-black text-xl shadow-2xl shadow-slate-200 mt-4">Join Now</button>
            </form>
          </div>
        )}

        {authStep === AuthSubView.LOGIN && (
          <div className={cardClass}>
            <button onClick={() => setAuthStep(AuthSubView.CHOICE)} className="mb-6 text-slate-400 font-bold text-sm flex items-center gap-1 hover:text-blue-600 transition-colors">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" /></svg> Back
            </button>
            <h2 className="text-3xl font-black text-slate-900 mb-8 uppercase text-center tracking-tighter">Login</h2>
            <form onSubmit={handleLogin} className="space-y-5">
              <div>
                <label className={labelClass}>Phone Number</label>
                <input type="tel" value={phone} onChange={e => setPhone(e.target.value.replace(/\D/g, '').slice(0, 10))} placeholder="9876543210" className={inputClass} required />
              </div>
              <div>
                <label className={labelClass}>Password</label>
                <input type="password" value={password} onChange={e => setPassword(e.target.value)} placeholder="••••••••" className={inputClass} required />
              </div>
              <button type="submit" className="w-full bg-blue-600 text-white py-6 rounded-[2rem] font-black text-xl mt-4 hover:bg-blue-700 transition-colors">Log In Securely</button>
              <div className="text-center mt-4">
                <button type="button" onClick={() => setAuthStep(AuthSubView.FORGOT_PHONE)} className="text-blue-600 font-bold text-sm hover:underline">Forgot Password?</button>
              </div>
            </form>
          </div>
        )}

        {authStep === AuthSubView.FORGOT_PHONE && (
          <div className={cardClass}>
            <button onClick={() => setAuthStep(AuthSubView.LOGIN)} className="mb-6 text-slate-400 font-bold text-sm flex items-center gap-1 hover:text-blue-600 transition-colors">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" /></svg> Back
            </button>
            <h2 className="text-3xl font-black text-slate-900 mb-4 uppercase text-center tracking-tighter">Recovery</h2>
            <p className="text-slate-500 text-center mb-8 font-medium">अपना रजिस्टर्ड मोबाइल नंबर दर्ज करें।</p>
            <form onSubmit={handleForgotPhone} className="space-y-4">
              <input type="tel" value={phone} onChange={e => setPhone(e.target.value.replace(/\D/g, '').slice(0, 10))} placeholder="मोबाइल नंबर" className={inputClass} required />
              <button type="submit" className="w-full bg-blue-600 text-white py-6 rounded-[2rem] font-black text-xl mt-4">Send Recovery OTP</button>
            </form>
          </div>
        )}

        {authStep === AuthSubView.FORGOT_OTP && (
          <div className={cardClass}>
             <h2 className="text-3xl font-black text-slate-900 mb-2 uppercase text-center tracking-tighter">Verify</h2>
             <p className="text-slate-500 text-center mb-8 font-bold text-sm">सिमुलेशन: '1234' दर्ज करें।</p>
             <form onSubmit={handleVerifyOtp} className="space-y-4">
