  // --- Render Views ---
  const renderProfile = () => {
    const totalAttempted = testHistory.length;
    const totalCorrect = testHistory.reduce((acc, curr) => acc + curr.correct, 0);
    const totalQuestions = testHistory.reduce((acc, curr) => acc + curr.total, 0);
    const accuracy = totalQuestions > 0 ? Math.round((totalCorrect / totalQuestions) * 100) : 0;
    const avgScore = testHistory.length > 0 ? (testHistory.reduce((acc, curr) => acc + curr.score, 0) / testHistory.length).toFixed(2) : 0;

    return (
