              <div className="text-5xl font-black">{avgScore}</div>
           </div>
           <div className="bg-emerald-500 text-white p-8 rounded-[2.5rem] shadow-xl">
              <div className="text-xs font-black uppercase tracking-[0.2em] opacity-60 mb-2">Accuracy</div>
              <div className="text-5xl font-black">{accuracy}%</div>
           </div>
