                       <th className="px-8 py-4">Status</th>
                    </tr>
                 </thead>
                 <tbody className="divide-y divide-slate-50">
                    {testHistory.length === 0 ? (
                       <tr>
                          <td colSpan={4} className="px-8 py-20 text-center text-slate-400 font-bold uppercase tracking-widest text-xs">No records found.</td>
                       </tr>
                    ) : (
                       testHistory.map((h) => (
                          <tr key={h.id} className="hover:bg-slate-50 transition-colors">
                             <td className="px-8 py-6 font-bold text-slate-800 hindi-text">{h.title}</td>
                             <td className="px-8 py-6 text-sm text-slate-500 font-medium">{new Date(h.date).toLocaleDateString()}</td>
                             <td className="px-8 py-6 text-lg font-black text-slate-900">{h.score.toFixed(1)} <span className="text-xs font-bold text-slate-300">/ {h.maxScore}</span></td>
                             <td className="px-8 py-6">
                                <span className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest ${h.score >= (h.maxScore * 0.4) ? 'bg-emerald-100 text-emerald-700' : 'bg-rose-100 text-rose-700'}`}>
                                   {h.score >= (h.maxScore * 0.4) ? 'Pass' : 'Fail'}
