  );

  const renderSubtopicMenu = () => (
    <div className="animate-fadeIn max-w-4xl mx-auto">
      <div className="flex items-center gap-4 mb-12">
        <button onClick={() => navigateTo(AppView.QUIZ_TOPIC_MENU)} className="p-3 bg-white border border-slate-200 rounded-2xl text-slate-500 hover:bg-slate-50 transition-all"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" /></svg></button>
        <div><h2 className="text-3xl font-black text-slate-900 tracking-tighter">{selectedGroup?.name}</h2><p className="text-slate-500 font-medium">Detailed sub-topic list</p></div>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {selectedGroup?.subtopics.map((sub, i) => (
          <button key={i} onClick={() => startQuiz(QuizType.TOPIC, sub, { testId: `topic-${sub.replace(/\s+/g, '_')}-0`, topic: sub, count: 25 })} className="flex items-center justify-between p-8 rounded-[3rem] border bg-white border-slate-200 hover:border-blue-600 hover:bg-blue-50/50 transition-all text-left group shadow-sm">
            <span className="font-bold text-xl hindi-text pr-4 leading-relaxed text-slate-800">{sub}</span>
            <div className="bg-slate-50 p-3 rounded-2xl border border-slate-100 text-blue-600 group-hover:bg-blue-600 group-hover:text-white transition-all"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg></div>
          </button>
        ))}
      </div>
    </div>
  );

  const renderExamMenu = () => {
    const exams = [
      { name: "Lab Assistant 2022 (GK)", year: 2022, context: "Lab Assistant 2022 GK Paper" },
      { name: "RSSB CET Graduate Level", year: 2024, context: "CET Graduate Level 2024" },
      { name: "RSSB LDC Exam", year: 2024, context: "LDC 2024 Exam" },
      { name: "RPSC RAS Prelims", year: 2023, context: "RAS Prelims 2023" },
      { name: "RSSB Patwar Exam", year: 2021, context: "Patwar 2021 Exam" }
    ];
    return (
      <div className="animate-fadeIn space-y-12">
        <div className="flex items-center gap-4 mb-4">
          <button onClick={() => navigateTo(AppView.HOME)} className="p-3 bg-white border border-slate-200 rounded-2xl text-slate-500 hover:bg-slate-50 transition-all"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" /></svg></button>
          <div><h2 className="text-3xl font-black text-slate-900 uppercase tracking-tighter">Official Papers</h2><p className="text-slate-500 font-medium tracking-tight">Access original full board papers.</p></div>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {exams.map((exam, i) => (
            <div key={i} className="bg-white rounded-[3.5rem] border border-slate-200 p-12 hover:shadow-2xl transition-all group border-b-8 border-b-slate-50 hover:border-b-blue-600">
              <div className="text-[10px] font-black uppercase tracking-[0.3em] text-slate-400 mb-2">{exam.year} EDITION</div>
              <h3 className="text-2xl font-black text-slate-900 mb-8 group-hover:text-blue-600 transition-colors leading-tight">{exam.name}</h3>
              <button onClick={() => startQuiz(QuizType.EXAM, exam.name, { testId: `exam-${exam.name.replace(/\s+/g, '_')}-0`, examContext: exam.context, count: 100 })} className="w-full py-6 rounded-3xl font-black bg-slate-900 text-white hover:bg-blue-600 shadow-xl shadow-slate-200 transition-all">Download & Start</button>
            </div>
          ))}
        </div>
      </div>
    );
  };

  return (
    <Layout 
      onHomeClick={() => navigateTo(AppView.HOME)} 
      onProfileClick={() => navigateTo(AppView.PROFILE)}
      onLogout={handleLogout} 
      isLoggedIn={isLoggedIn}
    >
      {loading ? (
        <div className="flex flex-col items-center justify-center min-h-[60vh]">
          <div className="w-24 h-24 border-[12px] border-blue-600 border-t-transparent rounded-full animate-spin mb-10 shadow-2xl shadow-blue-50"></div>
          <h2 className="text-3xl font-black text-slate-900 mb-2 uppercase tracking-tighter text-center">Opening Database Pool</h2>
          <p className="text-slate-500 font-black tracking-widest uppercase text-[10px] text-center">Fetching Real PYQs...</p>
        </div>
      ) : (
        <>
          {view === AppView.AUTH && renderAuth()}
          {view === AppView.HOME && renderHome()}
          {view === AppView.PROFILE && renderProfile()}
          {view === AppView.QUIZ_MIX_MENU && renderMixMenu()}
          {view === AppView.QUIZ_TOPIC_MENU && renderTopicMenu()}
          {view === AppView.QUIZ_SUBTOPIC_MENU && renderSubtopicMenu()}
          {view === AppView.EXAM_MENU && renderExamMenu()}

          {view === AppView.QUIZ_ACTIVE && activeSession && (
            <QuizEngine 
              session={activeSession} 
              onComplete={onQuizComplete} 
              onExit={() => navigateTo(AppView.HOME)} 
            />
          )}

          {view === AppView.SCORECARD && lastResults && (
            <ScoreCard 
              results={lastResults} 
              onReview={() => navigateTo(AppView.REVIEW)} 
              onNextTest={() => navigateTo(AppView.HOME)} 
              onBackHome={() => navigateTo(AppView.HOME)} 
            />
          )}

          {view === AppView.REVIEW && lastResults && (
            <QuizEngine 
              session={lastResults.session} 
              onComplete={() => {}} 
              onExit={() => navigateTo(AppView.SCORECARD)} 
