                    <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">25 PYQs • 60 Mins • +2/-0.33</span>
                    {isCached && (
                      <span className="flex items-center gap-1 text-[8px] font-black text-blue-500 uppercase bg-blue-50 px-2 py-0.5 rounded border border-blue-100">
                        <svg className="w-2 h-2" fill="currentColor" viewBox="0 0 20 20"><path d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" /></svg>
                        Synced
                      </span>
                    )}
                  </div>
                </div>
              </div>

              <div className="hidden sm:flex items-center gap-4 shrink-0">
                {isDone ? (
                  <div className="bg-emerald-100 text-emerald-700 px-6 py-3 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center gap-2">
                    <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" /></svg>
                    Re-Attempt
                  </div>
                ) : (
                  <div className="bg-slate-900 text-white px-8 py-4 rounded-2xl font-black text-xs uppercase tracking-widest group-hover:bg-blue-600 transition-colors shadow-xl shadow-slate-200 group-hover:shadow-blue-200">
                    Start Test
                  </div>
                )}
              </div>
            </button>
          );
        })}
      </div>
    </div>
  );

  const renderTopicMenu = () => (
    <div className="animate-fadeIn space-y-8">
      <div className="flex items-center gap-4 mb-4">
        <button onClick={() => navigateTo(AppView.HOME)} className="p-3 bg-white border border-slate-200 rounded-2xl text-slate-500 hover:bg-slate-50 transition-all"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" /></svg></button>
        <div><h2 className="text-3xl font-black text-slate-900 uppercase tracking-tighter">Topic-wise PYQs</h2><p className="text-slate-500">Unit-wise questions for focused preparation.</p></div>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {TOPIC_GROUPS.map((group) => (
          <div key={group.id} className="bg-white rounded-[4rem] border border-slate-200 p-12 hover:shadow-2xl transition-all">
            <h3 className="text-2xl font-black text-slate-900 mb-8 flex items-center justify-between">{group.name}<span className="text-[10px] bg-slate-100 text-slate-500 px-4 py-1.5 rounded-full font-black uppercase tracking-widest">{group.subtopics.length} Units</span></h3>
            <div className="grid grid-cols-1 gap-2">
              {group.subtopics.slice(0, 5).map((sub, i) => (
                <button key={i} onClick={() => startQuiz(QuizType.TOPIC, sub, { testId: `topic-${sub.replace(/\s+/g, '_')}-0`, topic: sub, count: 20 })} className="text-left text-sm font-bold p-5 rounded-2xl border border-slate-50 bg-slate-50/50 hover:border-blue-200 hover:bg-blue-50 text-slate-600 hover:text-blue-700 transition-all hindi-text">
                  {sub}
                </button>
              ))}
            </div>
            {group.subtopics.length > 5 && <button onClick={() => { setSelectedGroup(group); navigateTo(AppView.QUIZ_SUBTOPIC_MENU); }} className="mt-8 w-full py-5 rounded-3xl bg-slate-900 text-white font-black hover:bg-blue-600 transition-all text-xs uppercase tracking-[0.2em] shadow-lg shadow-slate-200">View All Units</button>}
          </div>
        ))}
      </div>
    </div>
  );

  const renderSubtopicMenu = () => (
    <div className="animate-fadeIn max-w-4xl mx-auto">
      <div className="flex items-center gap-4 mb-12">
        <button onClick={() => navigateTo(AppView.QUIZ_TOPIC_MENU)} className="p-3 bg-white border border-slate-200 rounded-2xl text-slate-500 hover:bg-slate-50 transition-all"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" /></svg></button>
        <div><h2 className="text-3xl font-black text-slate-900 tracking-tighter">{selectedGroup?.name}</h2><p className="text-slate-500 font-medium">Detailed sub-topic list</p></div>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {selectedGroup?.subtopics.map((sub, i) => (
          <button key={i} onClick={() => startQuiz(QuizType.TOPIC, sub, { testId: `topic-${sub.replace(/\s+/g, '_')}-0`, topic: sub, count: 25 })} className="flex items-center justify-between p-8 rounded-[3rem] border bg-white border-slate-200 hover:border-blue-600 hover:bg-blue-50/50 transition-all text-left group shadow-sm">
            <span className="font-bold text-xl hindi-text pr-4 leading-relaxed text-slate-800">{sub}</span>
            <div className="bg-slate-50 p-3 rounded-2xl border border-slate-100 text-blue-600 group-hover:bg-blue-600 group-hover:text-white transition-all"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg></div>
          </button>
        ))}
      </div>
    </div>
  );

  const renderExamMenu = () => {
    const exams = [
      { name: "Lab Assistant 2022 (GK)", year: 2022, context: "Lab Assistant 2022 GK Paper" },
      { name: "RSSB CET Graduate Level", year: 2024, context: "CET Graduate Level 2024" },
      { name: "RSSB LDC Exam", year: 2024, context: "LDC 2024 Exam" },
      { name: "RPSC RAS Prelims", year: 2023, context: "RAS Prelims 2023" },
      { name: "RSSB Patwar Exam", year: 2021, context: "Patwar 2021 Exam" }
    ];
    return (
      <div className="animate-fadeIn space-y-12">
        <div className="flex items-center gap-4 mb-4">
          <button onClick={() => navigateTo(AppView.HOME)} className="p-3 bg-white border border-slate-200 rounded-2xl text-slate-500 hover:bg-slate-50 transition-all"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" /></svg></button>
          <div><h2 className="text-3xl font-black text-slate-900 uppercase tracking-tighter">Official Papers</h2><p className="text-slate-500 font-medium tracking-tight">Access original full board papers.</p></div>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {exams.map((exam, i) => (
            <div key={i} className="bg-white rounded-[3.5rem] border border-slate-200 p-12 hover:shadow-2xl transition-all group border-b-8 border-b-slate-50 hover:border-b-blue-600">
              <div className="text-[10px] font-black uppercase tracking-[0.3em] text-slate-400 mb-2">{exam.year} EDITION</div>
              <h3 className="text-2xl font-black text-slate-900 mb-8 group-hover:text-blue-600 transition-colors leading-tight">{exam.name}</h3>
              <button onClick={() => startQuiz(QuizType.EXAM, exam.name, { testId: `exam-${exam.name.replace(/\s+/g, '_')}-0`, examContext: exam.context, count: 100 })} className="w-full py-6 rounded-3xl font-black bg-slate-900 text-white hover:bg-blue-600 shadow-xl shadow-slate-200 transition-all">Download & Start</button>
            </div>
          ))}
        </div>
      </div>
    );
  };

  return (
    <Layout 
      onHomeClick={() => navigateTo(AppView.HOME)} 
      onProfileClick={() => navigateTo(AppView.PROFILE)}
      onLogout={handleLogout} 
      isLoggedIn={isLoggedIn}
    >
      {loading ? (
        <div className="flex flex-col items-center justify-center min-h-[60vh]">
          <div className="w-24 h-24 border-[12px] border-blue-600 border-t-transparent rounded-full animate-spin mb-10 shadow-2xl shadow-blue-50"></div>
          <h2 className="text-3xl font-black text-slate-900 mb-2 uppercase tracking-tighter text-center">Opening Database Pool</h2>
          <p className="text-slate-500 font-black tracking-widest uppercase text-[10px] text-center">Fetching Real PYQs...</p>
        </div>
      ) : (
        <>
          {view === AppView.AUTH && renderAuth()}
          {view === AppView.HOME && renderHome()}
          {view === AppView.PROFILE && renderProfile()}
          {view === AppView.QUIZ_MIX_MENU && renderMixMenu()}
          {view === AppView.QUIZ_TOPIC_MENU && renderTopicMenu()}
          {view === AppView.QUIZ_SUBTOPIC_MENU && renderSubtopicMenu()}
          {view === AppView.EXAM_MENU && renderExamMenu()}

          {view === AppView.QUIZ_ACTIVE && activeSession && (
            <QuizEngine 
              session={activeSession} 
              onComplete={onQuizComplete} 
              onExit={() => navigateTo(AppView.HOME)} 
            />
          )}

          {view === AppView.SCORECARD && lastResults && (
            <ScoreCard 
              results={lastResults} 
              onReview={() => navigateTo(AppView.REVIEW)} 
              onNextTest={() => navigateTo(AppView.HOME)} 
              onBackHome={() => navigateTo(AppView.HOME)} 
            />
          )}

          {view === AppView.REVIEW && lastResults && (
            <QuizEngine 
              session={lastResults.session} 
              onComplete={() => {}} 
              onExit={() => navigateTo(AppView.SCORECARD)} 
              isReview={true} 
            />
          )}
        </>
      )}
    </Layout>
  );
};

export default App;

export enum AppView {
  AUTH = 'auth',
  HOME = 'home',
  QUIZ_MENU = 'quiz_menu',
  QUIZ_MIX_MENU = 'quiz_mix_menu',
  QUIZ_TOPIC_MENU = 'quiz_topic_menu',
  QUIZ_SUBTOPIC_MENU = 'quiz_subtopic_menu',
  QUIZ_TOPIC_TESTS_MENU = 'quiz_topic_tests_menu',
  EXAM_MENU = 'exam_menu',
  AI_TEST = 'ai_test',
  QUIZ_ACTIVE = 'quiz_active',
  SCORECARD = 'scorecard',
  REVIEW = 'review',
  PROFILE = 'profile'
}

export enum AuthSubView {
  CHOICE = 'choice',
  LOGIN = 'login',
  SIGNUP = 'signup',
  FORGOT_PHONE = 'forgot_phone',
  FORGOT_OTP = 'forgot_otp',
  RESET_PASSWORD = 'reset_password'
}

export enum QuizType {
  MIX = 'mix',
  TOPIC = 'topic',
  EXAM = 'exam',
  AI = 'ai'
}

export interface Question {
  id: string;
  question: string;
  options: {
    A: string;
    B: string;
    C: string;
    D: string;
    E: string;
  };
  correctAnswer: 'A' | 'B' | 'C' | 'D' | 'E';
  examName: string;
  examYear: number;
  subject: string;
  topic?: string;
}

export interface QuizSession {
  type: QuizType;
  title: string;
  questions: Question[];
  currentQuestionIndex: number;
  userAnswers: Record<string, 'A' | 'B' | 'C' | 'D' | 'E' | null>;
  startTime: number;
  durationInMinutes: number;
  completed: boolean;
}

export interface QuizResults {
  score: number;
  correctCount: number;
  incorrectCount: number;
  skippedCount: number;
  unattemptedCount: number;
  totalQuestions: number;
  timeTaken: string;
  session: QuizSession;
}

export interface AttemptRecord {
  id: string;
  title: string;
  score: number;
  maxScore: number;
  date: number;
  correct: number;
  total: number;
}

import React, { useState, useEffect, useCallback } from 'react';
import Layout from './components/Layout';
import QuizEngine from './components/QuizEngine';
import ScoreCard from './components/ScoreCard';
import { 
  AppView, 
  AuthSubView,
  QuizSession, 
  QuizType, 
  QuizResults,
  AttemptRecord
} from './types';
import { 
  TOPIC_GROUPS,
  TopicGroup,
  MARKING_SCHEME 
} from './constants';
import { fetchPYQs } from './services/geminiService';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.AUTH);
  const [authStep, setAuthStep] = useState<AuthSubView>(AuthSubView.CHOICE);
  const [isLoggedIn, setIsLoggedIn] = useState(false);

  const [phone, setPhone] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [otp, setOtp] = useState('');

  const [activeSession, setActiveSession] = useState<QuizSession | null>(null);
  const [lastResults, setLastResults] = useState<QuizResults | null>(null);
  const [loading, setLoading] = useState(false);
  const [selectedGroup, setSelectedGroup] = useState<TopicGroup | null>(null);
  const [selectedSubtopic, setSelectedSubtopic] = useState<string | null>(null);
  const [completedTests, setCompletedTests] = useState<Set<string>>(new Set());
  const [testHistory, setTestHistory] = useState<AttemptRecord[]>([]);
  const [syncProgress, setSyncProgress] = useState<number>(0);
  const [isSyncing, setIsSyncing] = useState(false);

  const testsPerPage = 40;

  // --- Persistence & Initialization ---
  useEffect(() => {
    const savedUser = localStorage.getItem('rajquiz_currentUser');
    if (savedUser) {
      setIsLoggedIn(true);
      setView(AppView.HOME);
    }

    const savedProgress = localStorage.getItem('rajquiz_progress');
    if (savedProgress) {
      try {
        setCompletedTests(new Set(JSON.parse(savedProgress)));
      } catch (e) { 
        console.error("Failed to load progress", e); 
      }
    }

    const savedHistory = localStorage.getItem('rajquiz_history');
    if (savedHistory) {
      try {
        setTestHistory(JSON.parse(savedHistory));
      } catch (e) {
        console.error("Failed to load history", e);
      }
    }
  }, []);

  // --- Background Sync ---
  const downloadFullDatabase = async () => {
    if (isSyncing) return;
    setIsSyncing(true);
    setSyncProgress(10);
    try {
      const mixSet = await fetchPYQs({ count: 50, isMix: true, testNumber: 1 });
      localStorage.setItem('qcache_mix_default', JSON.stringify(mixSet));
      setSyncProgress(50);

      const topicSet = await fetchPYQs({ count: 50, subject: 'Rajasthan GK', topic: 'इतिहास' });
      localStorage.setItem('qcache_topic_hist_default', JSON.stringify(topicSet));
      setSyncProgress(100);

      setTimeout(() => setIsSyncing(false), 1500);
    } catch (e) {
      console.warn("Sync partially failed", e);
      setIsSyncing(false);
    }
  };

  useEffect(() => {
    if (isLoggedIn && !localStorage.getItem('qcache_mix_default')) {
      downloadFullDatabase();
    }
  }, [isLoggedIn]);

  // --- User Management Logic ---
  const getUsers = () => {
    const users = localStorage.getItem('rajquiz_users');
    return users ? JSON.parse(users) : {};
  };

  const saveUser = (phone: string, pass: string) => {
    const users = getUsers();
    users[phone] = { password: pass };
    localStorage.setItem('rajquiz_users', JSON.stringify(users));
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const users = getUsers();
    const user = users[phone];

    if (!user) {
      alert("यह नंबर रजिस्टर्ड नहीं है। (Number not registered.)");
      setAuthStep(AuthSubView.SIGNUP);
      return;
    }

    if (user.password === password) {
      localStorage.setItem('rajquiz_currentUser', phone);
      setIsLoggedIn(true);
      setView(AppView.HOME);
      setPassword('');
    } else {
      alert("गलत पासवर्ड! कृपया पुनः प्रयास करें। (WRONG PASSWORD! Please try again.)");
    }
  };

  const handleSignup = (e: React.FormEvent) => {
    e.preventDefault();
    if (phone.length !== 10) return alert("कृपया 10 अंकों का नंबर डालें");

    const users = getUsers();
    if (users[phone]) {
      alert("यह नंबर पहले से ही रजिस्टर्ड है। (Already Registered.)");
      setAuthStep(AuthSubView.LOGIN);
      return;
    }

    if (password.length < 4) return alert("पासवर्ड कम से कम 4 अक्षरों का होना चाहिए");
    if (password !== confirmPassword) return alert("पासवर्ड मैच नहीं कर रहे हैं");

    saveUser(phone, password);
    alert("अकाउंट बन गया है! अब लॉगिन करें।");
    setAuthStep(AuthSubView.LOGIN);
    setPassword('');
    setConfirmPassword('');
  };

  const handleForgotPhone = (e: React.FormEvent) => {
    e.preventDefault();
    const users = getUsers();
    if (!users[phone]) return alert("यह मोबाइल नंबर हमारे रिकॉर्ड में नहीं है।");
    setAuthStep(AuthSubView.FORGOT_OTP);
    alert("सिमुलेशन: OTP '1234' आपके नंबर पर भेजा गया है।");
  };

  const handleVerifyOtp = (e: React.FormEvent) => {
    e.preventDefault();
    if (otp === '1234') {
      setAuthStep(AuthSubView.RESET_PASSWORD);
      setOtp('');
    } else {
      alert("गलत OTP! कृपया '1234' का उपयोग करें।");
    }
  };

  const handleResetPassword = (e: React.FormEvent) => {
    e.preventDefault();
    if (password.length < 4) return alert("नया पासवर्ड कम से कम 4 अक्षरों का होना चाहिए");
    if (password !== confirmPassword) return alert("पासवर्ड मैच नहीं कर रहे हैं");
    saveUser(phone, password);
    alert("पासवर्ड सफलतापूर्वक बदल दिया गया है! अब लॉगिन करें।");
    setAuthStep(AuthSubView.LOGIN);
    setPassword('');
    setConfirmPassword('');
  };

  const handleLogout = () => {
    if (window.confirm("क्या आप लॉगआउट करना चाहते हैं?")) {
      localStorage.removeItem('rajquiz_currentUser');
      setIsLoggedIn(false);
      setAuthStep(AuthSubView.CHOICE);
      setView(AppView.AUTH);
    }
  };

  const navigateTo = (newView: AppView) => {
    setView(newView);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const markTestCompleted = (testId: string, results: QuizResults) => {
    setCompletedTests(prev => {
      const newSet = new Set(prev);
      newSet.add(testId);
      localStorage.setItem('rajquiz_progress', JSON.stringify(Array.from(newSet)));
      return newSet;
    });

    const attempt: AttemptRecord = {
      id: `${Date.now()}`,
      title: results.session.title,
      score: results.score,
      maxScore: results.totalQuestions * 2,
      date: Date.now(),
      correct: results.correctCount,
      total: results.totalQuestions
    };

    setTestHistory(prev => {
      const newHist = [attempt, ...prev].slice(0, 100);
      localStorage.setItem('rajquiz_history', JSON.stringify(newHist));
      return newHist;
    });
  };

  const startQuiz = useCallback(async (type: QuizType, title: string, options: { 
    subject?: string; 
    topic?: string; 
    count?: number; 
    testId?: string;
    testNumber?: number;
    examContext?: string;
  } = {}) => {
    const finalTestId = options.testId || `${type}-${(options.topic || title).replace(/\s+/g, '_')}-${options.testNumber || 0}`;
    const cacheKey = `qcache_${finalTestId}`;
    const cached = localStorage.getItem(cacheKey);

    if (cached) {
      const questions = JSON.parse(cached);
      const session: QuizSession = {
        type, title: `${title} ${options.testNumber ? `- Test ${options.testNumber.toString().padStart(2, '0')}` : ''}`,
        questions, currentQuestionIndex: 0, userAnswers: {}, startTime: Date.now(),
        durationInMinutes: type === QuizType.AI ? 15 : (options.count && options.count > 50 ? 120 : 60),
        completed: false
      };
      (session as any).testId = finalTestId;
      setActiveSession(session);
      navigateTo(AppView.QUIZ_ACTIVE);
      return;
    }

    setLoading(true);
    try {
      const questions = await fetchPYQs({
        count: options.count || 25,
        subject: options.subject,
        topic: options.topic,
        isMix: type === QuizType.MIX || type === QuizType.AI,
        testNumber: options.testNumber,
        examContext: options.examContext
      });

      if (!questions || questions.length === 0) throw new Error("No questions returned");
      localStorage.setItem(cacheKey, JSON.stringify(questions));

      const session: QuizSession = {
        type, title: `${title} ${options.testNumber ? `- Test ${options.testNumber.toString().padStart(2, '0')}` : ''}`,
        questions, currentQuestionIndex: 0, userAnswers: {}, startTime: Date.now(),
        durationInMinutes: type === QuizType.AI ? 15 : (options.count && options.count > 50 ? 120 : 60),
        completed: false
      };
      (session as any).testId = finalTestId;
      setActiveSession(session);
      navigateTo(AppView.QUIZ_ACTIVE);
    } catch (error) {
      console.error("Quiz Start Error:", error);
      alert("कनेक्शन एरर। कृपया इंटरनेट की जांच करें।");
    } finally {
      setLoading(false);
    }
  }, []);

  const onQuizComplete = (session: QuizSession) => {
    let score = 0, correct = 0, incorrect = 0, skipped = 0, unattempted = 0;
    session.questions.forEach(q => {
      const ans = session.userAnswers[q.id];
      if (!ans) { score += MARKING_SCHEME.UNATTEMPTED; unattempted++; }
      else if (ans === 'E') skipped++;
      else if (ans === q.correctAnswer) { score += MARKING_SCHEME.CORRECT; correct++; }
      else { score += MARKING_SCHEME.WRONG; incorrect++; }
    });
    const results: QuizResults = { score, correctCount: correct, incorrectCount: incorrect, skippedCount: skipped, unattemptedCount: unattempted, totalQuestions: session.questions.length, timeTaken: 'N/A', session };
    setLastResults(results);
    const tId = (session as any).testId;
    if (tId) markTestCompleted(tId, results);
    navigateTo(AppView.SCORECARD);
  };

  const renderAuth = () => {
    const cardClass = "bg-white p-8 md:p-12 rounded-[3.5rem] shadow-2xl border border-slate-100 w-full max-w-lg animate-fadeIn";
    const labelClass = "text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1 mb-1 block";
    const inputClass = "w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-8 py-5 outline-none focus:border-blue-600 focus:bg-white transition-all font-bold text-xl";
    const authBtnBase = "w-full py-6 rounded-3xl font-black text-xl flex items-center justify-center gap-3 transition-all hover:scale-[1.02] active:scale-95 shadow-lg";

    return (
      <div className="min-h-[85vh] flex items-center justify-center px-4">
        {authStep === AuthSubView.CHOICE && (
          <div className={cardClass}>
            <div className="text-center mb-12">
              <h2 className="text-4xl font-black text-slate-900 mb-2 uppercase tracking-tighter italic">RAJ<span className="text-blue-600">QUIZER</span></h2>
              <p className="text-slate-400 font-bold tracking-[0.2em] text-[10px] uppercase opacity-70">Authentic Board PYQs</p>
            </div>

            <div className="space-y-4">
              <button onClick={() => setAuthStep(AuthSubView.LOGIN)} className={`${authBtnBase} bg-blue-600 text-white shadow-blue-100 hover:bg-blue-700`}>
                 LOGIN
