  const renderMixMenu = () => (
    <div className="animate-fadeIn max-w-4xl mx-auto">
      <div className="flex items-center gap-4 mb-12">
        <button onClick={() => navigateTo(AppView.HOME)} className="p-3 bg-white border border-slate-200 rounded-2xl text-slate-500 hover:bg-slate-50"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" /></svg></button>
        <div><h2 className="text-3xl font-black text-slate-900 uppercase tracking-tighter">Mixed Mock Tests</h2><p className="text-slate-500 font-medium tracking-tight">Full length practice sets (Line-wise vertical list)</p></div>
      </div>
      <div className="flex flex-col gap-4">
        {Array.from({ length: testsPerPage }).map((_, i) => {
          const testNum = i + 1;
          const testId = `mix-Mixed_Subjects-${testNum}`;
          const isDone = completedTests.has(testId);
          return (
            <button key={testNum} onClick={() => startQuiz(QuizType.MIX, "Mixed Subjects", { testNumber: testNum, testId, count: 25 })} className={`group w-full flex items-center justify-between p-6 md:p-8 rounded-[2rem] border-2 transition-all relative overflow-hidden ${isDone ? 'bg-emerald-50 border-emerald-500 shadow-sm' : 'bg-white border-slate-100 hover:border-blue-600 hover:shadow-xl shadow-sm'}`}>
              <div className="flex items-center gap-6">
                <div className={`w-14 h-14 md:w-20 md:h-20 rounded-[1.5rem] flex flex-col items-center justify-center transition-all ${isDone ? 'bg-emerald-500 text-white' : 'bg-slate-100 text-slate-900 group-hover:bg-blue-600 group-hover:text-white'}`}><span className="text-[10px] font-black uppercase tracking-widest">SET</span><span className="text-2xl md:text-4xl font-black leading-none">{testNum}</span></div>
                <div className="text-left"><h3 className={`text-xl md:text-3xl font-black ${isDone ? 'text-emerald-900' : 'text-slate-900'} leading-tight`}>Mixed Practice Set {testNum}</h3><p className="text-slate-400 font-bold text-xs uppercase mt-1">25 PYQs • 60 Mins • Official Pattern</p></div>
              </div>
              <div className="bg-slate-900 text-white px-8 py-4 rounded-2xl font-black text-xs uppercase group-hover:bg-blue-600 transition-all">{isDone ? 'Re-Attempt' : 'Start Now'}</div>
            </button>
          );
        })}
      </div>
    </div>
  );

  const renderTopicMenu = () => (
    <div className="animate-fadeIn space-y-8">
      <div className="flex items-center gap-4 mb-4">
        <button onClick={() => navigateTo(AppView.HOME)} className="p-3 bg-white border border-slate-200 rounded-2xl text-slate-500 hover:bg-slate-50"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" /></svg></button>
        <div><h2 className="text-3xl font-black text-slate-900 uppercase tracking-tighter">Topic Wise (By Subject)</h2><p className="text-slate-500">Pick a subject to explore its topics.</p></div>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {TOPIC_GROUPS.map((group) => (
          <button key={group.id} onClick={() => { setSelectedGroup(group); navigateTo(AppView.QUIZ_SUBTOPIC_MENU); }} className="bg-white rounded-[4rem] border-2 border-slate-100 p-12 hover:border-blue-600 hover:shadow-2xl transition-all text-left group">
            <h3 className="text-2xl font-black text-slate-900 mb-2 uppercase tracking-tight group-hover:text-blue-600 transition-all">{group.name}</h3>
            <p className="text-slate-400 font-bold text-sm uppercase tracking-widest">{group.subtopics.length} Key Topics Found</p>
            <div className="mt-8 flex items-center gap-2 text-blue-600 font-black uppercase text-xs">Explore Topics <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M17 8l4 4m0 0l-4 4m4-4H3" /></svg></div>
          </button>
        ))}
      </div>
    </div>
  );

  const renderSubtopicMenu = () => (
    <div className="animate-fadeIn max-w-4xl mx-auto">
      <div className="flex items-center gap-4 mb-12">
        <button onClick={() => navigateTo(AppView.QUIZ_TOPIC_MENU)} className="p-3 bg-white border border-slate-200 rounded-2xl text-slate-500 hover:bg-slate-50"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" /></svg></button>
        <div><h2 className="text-3xl font-black text-slate-900 tracking-tighter">{selectedGroup?.name}</h2><p className="text-slate-500 font-medium italic">Select a topic.</p></div>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {selectedGroup?.subtopics.map((sub, i) => (
          <button key={i} onClick={() => { setSelectedSubtopic(sub); navigateTo(AppView.QUIZ_TOPIC_TESTS_MENU); }} className="flex items-center justify-between p-8 rounded-[3rem] border bg-white border-slate-200 hover:border-blue-600 hover:bg-blue-50/50 transition-all text-left group shadow-sm">
            <span className="font-bold text-xl hindi-text pr-4 leading-relaxed text-slate-800">{sub}</span>
            <div className="bg-slate-50 p-3 rounded-2xl border border-slate-100 text-blue-600 group-hover:bg-blue-600 group-hover:text-white transition-all"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg></div>
          </button>
        ))}
      </div>
    </div>
  );

  const renderTopicTestsMenu = () => (
    <div className="animate-fadeIn max-w-4xl mx-auto">
      <div className="flex items-center gap-4 mb-12">
        <button onClick={() => navigateTo(AppView.QUIZ_SUBTOPIC_MENU)} className="p-3 bg-white border border-slate-200 rounded-2xl text-slate-500 hover:bg-slate-50"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" /></svg></button>
        <div><h2 className="text-3xl font-black text-slate-900 tracking-tighter hindi-text">{selectedSubtopic}</h2><p className="text-slate-500 font-medium">Available tests for this topic.</p></div>
      </div>
      <div className="space-y-6">
        {[1, 2].map((num) => {
          const testId = `topic-${selectedSubtopic?.replace(/\s+/g, '_')}-test-${num}`;
          const isDone = completedTests.has(testId);
          return (
            <button key={num} onClick={() => startQuiz(QuizType.TOPIC, selectedSubtopic!, { testId, topic: selectedSubtopic!, testNumber: num, count: 25 })} className={`group w-full flex items-center justify-between p-8 md:p-10 rounded-[2.5rem] border-2 transition-all relative overflow-hidden ${isDone ? 'bg-emerald-50 border-emerald-500' : 'bg-white border-slate-100 hover:border-blue-600 hover:shadow-2xl shadow-sm'}`}>
              <div className="flex items-center gap-8">
                <div className={`w-16 h-16 md:w-24 md:h-24 rounded-3xl flex flex-col items-center justify-center transition-all ${isDone ? 'bg-emerald-500 text-white' : 'bg-slate-100 text-slate-900 group-hover:bg-blue-600 group-hover:text-white'}`}><span className="text-[10px] font-black uppercase opacity-60 tracking-tighter">TEST</span><span className="text-3xl md:text-5xl font-black leading-none">{num}</span></div>
                <div className="text-left"><h3 className={`text-2xl md:text-4xl font-black ${isDone ? 'text-emerald-900' : 'text-slate-900'} leading-tight mb-2 uppercase tracking-tighter`}>{selectedSubtopic} - Test {num}</h3></div>
              </div>
              <div className={`px-10 py-5 rounded-2xl font-black uppercase tracking-widest text-sm transition-all shadow-xl ${isDone ? 'bg-emerald-100 text-emerald-700' : 'bg-slate-900 text-white group-hover:bg-blue-600'}`}>{isDone ? 'Re-Attempt' : 'Start'}</div>
            </button>
          );
        })}
      </div>
    </div>
  );

  const renderExamMenu = () => {
    const exams = [{ name: "Lab Assistant 2022 (GK)", year: 2022, context: "Lab Assistant 2022 GK Paper" }, { name: "RSSB CET Graduate Level", year: 2024, context: "CET Graduate Level 2024" }, { name: "RSSB LDC Exam", year: 2024, context: "LDC 2024 Exam" }, { name: "RPSC RAS Prelims", year: 2023, context: "RAS Prelims 2023" }, { name: "RSSB Patwar Exam", year: 2021, context: "Patwar 2021 Exam" }];
    return (
      <div className="animate-fadeIn space-y-12">
        <div className="flex items-center gap-4 mb-4"><button onClick={() => navigateTo(AppView.HOME)} className="p-3 bg-white border border-slate-200 rounded-2xl text-slate-500 hover:bg-slate-50"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" /></svg></button><div><h2 className="text-3xl font-black text-slate-900 uppercase tracking-tighter">Official Full Papers</h2></div></div>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {exams.map((exam, i) => (
            <div key={i} className="bg-white rounded-[3.5rem] border border-slate-200 p-12 hover:shadow-2xl transition-all group border-b-8 border-b-slate-50 hover:border-b-blue-600">
              <div className="text-[10px] font-black uppercase tracking-[0.3em] text-slate-400 mb-2">{exam.year}</div><h3 className="text-2xl font-black text-slate-900 mb-8 leading-tight">{exam.name}</h3>
              <button onClick={() => startQuiz(QuizType.EXAM, exam.name, { testId: `exam-${exam.name.replace(/\s+/g, '_')}-0`, examContext: exam.context, count: 100 })} className="w-full py-6 rounded-3xl font-black bg-slate-900 text-white hover:bg-blue-600 transition-all">Start</button>
            </div>
          ))}
        </div>
      </div>
    );
  };

  return (
    <Layout onHomeClick={() => navigateTo(AppView.HOME)} onProfileClick={() => navigateTo(AppView.PROFILE)} onLogout={handleLogout} isLoggedIn={isLoggedIn}>
      {loading ? (
        <div className="flex flex-col items-center justify-center min-h-[60vh]"><div className="w-24 h-24 border-[12px] border-blue-600 border-t-transparent rounded-full animate-spin mb-10"></div><h2 className="text-3xl font-black text-slate-900 mb-2 uppercase tracking-tighter text-center">Loading</h2></div>
      ) : (
        <>
          {view === AppView.AUTH && renderAuth()}
          {view === AppView.HOME && renderHome()}
          {view === AppView.PROFILE && renderProfile()}
          {view === AppView.QUIZ_MIX_MENU && renderMixMenu()}
          {view === AppView.QUIZ_TOPIC_MENU && renderTopicMenu()}
          {view === AppView.QUIZ_SUBTOPIC_MENU && renderSubtopicMenu()}
          {view === AppView.QUIZ_TOPIC_TESTS_MENU && renderTopicTestsMenu()}
          {view === AppView.EXAM_MENU && renderExamMenu()}
          {view === AppView.QUIZ_ACTIVE && activeSession && (<QuizEngine session={activeSession} onComplete={onQuizComplete} onExit={() => navigateTo(AppView.HOME)} />)}
          {view === AppView.SCORECARD && lastResults && (<ScoreCard results={lastResults} onReview={() => navigateTo(AppView.REVIEW)} onNextTest={() => navigateTo(AppView.HOME)} onBackHome={() => navigateTo(AppView.HOME)} />)}
          {view === AppView.REVIEW && lastResults && (<QuizEngine session={lastResults.session} onComplete={() => {}} onExit={() => navigateTo(AppView.SCORECARD)} isReview={true} />)}
        </>
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect, useCallback } from 'react';
import Layout from './components/Layout';
import QuizEngine from './components/QuizEngine';
import ScoreCard from './components/ScoreCard';
import { 
  AppView, 
  AuthSubView,
  QuizSession, 
  QuizType, 
  QuizResults,
  AttemptRecord
} from './types';
import { 
  TOPIC_GROUPS,
  TopicGroup,
  MARKING_SCHEME 
} from './constants';
import { fetchPYQs } from './services/geminiService';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.AUTH);
  const [authStep, setAuthStep] = useState<AuthSubView>(AuthSubView.CHOICE);
  const [isLoggedIn, setIsLoggedIn] = useState(false);

  const [phone, setPhone] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [otp, setOtp] = useState('');

  const [activeSession, setActiveSession] = useState<QuizSession | null>(null);
  const [lastResults, setLastResults] = useState<QuizResults | null>(null);
  const [loading, setLoading] = useState(false);
  const [selectedGroup, setSelectedGroup] = useState<TopicGroup | null>(null);
  const [selectedSubtopic, setSelectedSubtopic] = useState<string | null>(null);
  const [completedTests, setCompletedTests] = useState<Set<string>>(new Set());
  const [testHistory, setTestHistory] = useState<AttemptRecord[]>([]);
  const [syncProgress, setSyncProgress] = useState<number>(0);
  const [isSyncing, setIsSyncing] = useState(false);

  const testsPerPage = 40;

  // --- Persistence & Initialization ---
  useEffect(() => {
    const savedUser = localStorage.getItem('rajquiz_currentUser');
    if (savedUser) {
      setIsLoggedIn(true);
      setView(AppView.HOME);
    }

    const savedProgress = localStorage.getItem('rajquiz_progress');
    if (savedProgress) {
      try {
        setCompletedTests(new Set(JSON.parse(savedProgress)));
      } catch (e) { 
        console.error("Failed to load progress", e); 
      }
    }

    const savedHistory = localStorage.getItem('rajquiz_history');
    if (savedHistory) {
      try {
        setTestHistory(JSON.parse(savedHistory));
      } catch (e) {
        console.error("Failed to load history", e);
      }
    }
  }, []);

  // --- Background Sync ---
  const downloadFullDatabase = async () => {
    if (isSyncing) return;
    setIsSyncing(true);
    setSyncProgress(10);
    try {
      const mixSet = await fetchPYQs({ count: 50, isMix: true, testNumber: 1 });
      localStorage.setItem('qcache_mix_default', JSON.stringify(mixSet));
      setSyncProgress(50);
      const topicSet = await fetchPYQs({ count: 50, subject: 'Rajasthan GK', topic: 'इतिहास' });
      localStorage.setItem('qcache_topic_hist_default', JSON.stringify(topicSet));
      setSyncProgress(100);
      setTimeout(() => setIsSyncing(false), 1500);
    } catch (e) {
      console.warn("Sync partially failed", e);
      setIsSyncing(false);
    }
  };

  useEffect(() => {
    if (isLoggedIn && !localStorage.getItem('qcache_mix_default')) {
      downloadFullDatabase();
    }
  }, [isLoggedIn]);

  // --- Auth Handlers ---
  const getUsers = () => {
    const users = localStorage.getItem('rajquiz_users');
    return users ? JSON.parse(users) : {};
  };

  const saveUser = (phone: string, pass: string) => {
    const users = getUsers();
    users[phone] = { password: pass };
    localStorage.setItem('rajquiz_users', JSON.stringify(users));
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const users = getUsers();
    const user = users[phone];
    if (!user) {
      alert("यह नंबर रजिस्टर्ड नहीं है।");
      setAuthStep(AuthSubView.SIGNUP);
      return;
    }
    if (user.password === password) {
      localStorage.setItem('rajquiz_currentUser', phone);
      setIsLoggedIn(true);
      setView(AppView.HOME);
      setPassword('');
    } else {
      alert("गलत पासवर्ड! कृपया पुनः प्रयास करें। (Wrong Password)");
    }
  };

  const handleSignup = (e: React.FormEvent) => {
    e.preventDefault();
    if (phone.length !== 10) return alert("कृपया 10 अंकों का नंबर डालें");
    const users = getUsers();
    if (users[phone]) {
      alert("यह नंबर पहले से ही रजिस्टर्ड है।");
      setAuthStep(AuthSubView.LOGIN);
      return;
    }
    if (password.length < 4) return alert("पासवर्ड कम से कम 4 अक्षरों का होना चाहिए");
    if (password !== confirmPassword) return alert("पासवर्ड मैच नहीं कर रहे हैं");
    saveUser(phone, password);
    alert("अकाउंट बन गया है! अब लॉगिन करें।");
    setAuthStep(AuthSubView.LOGIN);
    setPassword('');
    setConfirmPassword('');
  };

  const handleForgotPhone = (e: React.FormEvent) => {
    e.preventDefault();
    const users = getUsers();
    if (!users[phone]) return alert("यह मोबाइल नंबर रिकॉर्ड में नहीं है।");
    setAuthStep(AuthSubView.FORGOT_OTP);
    alert("OTP: 1234");
  };

  const handleVerifyOtp = (e: React.FormEvent) => {
    e.preventDefault();
    if (otp === '1234') {
      setAuthStep(AuthSubView.RESET_PASSWORD);
      setOtp('');
    } else {
      alert("गलत OTP! '1234' का उपयोग करें।");
    }
  };

  const handleResetPassword = (e: React.FormEvent) => {
    e.preventDefault();
    if (password.length < 4) return alert("पासवर्ड कम से कम 4 अक्षरों का होना चाहिए");
    if (password !== confirmPassword) return alert("पासवर्ड मैच नहीं कर रहे हैं");
    saveUser(phone, password);
    alert("पासवर्ड बदल दिया गया है!");
    setAuthStep(AuthSubView.LOGIN);
    setPassword('');
    setConfirmPassword('');
  };

  const handleLogout = () => {
    if (window.confirm("लॉगआउट करना चाहते हैं?")) {
      localStorage.removeItem('rajquiz_currentUser');
      setIsLoggedIn(false);
      setAuthStep(AuthSubView.CHOICE);
      setView(AppView.AUTH);
    }
  };

  const navigateTo = (newView: AppView) => {
    setView(newView);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const markTestCompleted = (testId: string, results: QuizResults) => {
    setCompletedTests(prev => {
      const newSet = new Set(prev);
      newSet.add(testId);
      localStorage.setItem('rajquiz_progress', JSON.stringify(Array.from(newSet)));
      return newSet;
    });
    const attempt: AttemptRecord = {
      id: `${Date.now()}`,
      title: results.session.title,
      score: results.score,
      maxScore: results.totalQuestions * 2,
      date: Date.now(),
      correct: results.correctCount,
      total: results.totalQuestions
    };
    setTestHistory(prev => {
      const newHist = [attempt, ...prev].slice(0, 100);
      localStorage.setItem('rajquiz_history', JSON.stringify(newHist));
      return newHist;
    });
  };

  const startQuiz = useCallback(async (type: QuizType, title: string, options: { 
    subject?: string; 
    topic?: string; 
    count?: number; 
    testId?: string;
    testNumber?: number;
    examContext?: string;
  } = {}) => {
    const finalTestId = options.testId || `${type}-${(options.topic || title).replace(/\s+/g, '_')}-${options.testNumber || 0}`;
    const cacheKey = `qcache_${finalTestId}`;
    const cached = localStorage.getItem(cacheKey);
    if (cached) {
      const questions = JSON.parse(cached);
      const session: QuizSession = {
        type, title: `${title} ${options.testNumber ? `- Test ${options.testNumber.toString().padStart(2, '0')}` : ''}`,
        questions, currentQuestionIndex: 0, userAnswers: {}, startTime: Date.now(),
        durationInMinutes: type === QuizType.AI ? 15 : (options.count && options.count > 50 ? 120 : 60),
        completed: false
      };
      (session as any).testId = finalTestId;
      setActiveSession(session);
      navigateTo(AppView.QUIZ_ACTIVE);
      return;
    }
    setLoading(true);
    try {
      const questions = await fetchPYQs({
        count: options.count || 25,
        subject: options.subject,
        topic: options.topic,
        isMix: type === QuizType.MIX || type === QuizType.AI,
        testNumber: options.testNumber,
        examContext: options.examContext
      });
      if (!questions || questions.length === 0) throw new Error("No questions returned");
      localStorage.setItem(cacheKey, JSON.stringify(questions));
      const session: QuizSession = {
        type, title: `${title} ${options.testNumber ? `- Test ${options.testNumber.toString().padStart(2, '0')}` : ''}`,
        questions, currentQuestionIndex: 0, userAnswers: {}, startTime: Date.now(),
        durationInMinutes: type === QuizType.AI ? 15 : (options.count && options.count > 50 ? 120 : 60),
        completed: false
      };
      (session as any).testId = finalTestId;
      setActiveSession(session);
      navigateTo(AppView.QUIZ_ACTIVE);
    } catch (error) {
      console.error("Quiz Start Error:", error);
      alert("कनेक्शन एरर।");
    } finally {
      setLoading(false);
    }
  }, []);

  const onQuizComplete = (session: QuizSession) => {
    let score = 0, correct = 0, incorrect = 0, skipped = 0, unattempted = 0;
    session.questions.forEach(q => {
      const ans = session.userAnswers[q.id];
      if (!ans) { score += MARKING_SCHEME.UNATTEMPTED; unattempted++; }
      else if (ans === 'E') skipped++;
      else if (ans === q.correctAnswer) { score += MARKING_SCHEME.CORRECT; correct++; }
      else { score += MARKING_SCHEME.WRONG; incorrect++; }
    });
    const results: QuizResults = { score, correctCount: correct, incorrectCount: incorrect, skippedCount: skipped, unattemptedCount: unattempted, totalQuestions: session.questions.length, timeTaken: 'N/A', session };
    setLastResults(results);
    const tId = (session as any).testId;
    if (tId) markTestCompleted(tId, results);
    navigateTo(AppView.SCORECARD);
  };

  const renderAuth = () => {
    const cardClass = "bg-white p-8 md:p-12 rounded-[3.5rem] shadow-2xl border border-slate-100 w-full max-w-lg animate-fadeIn";
    const labelClass = "text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1 mb-1 block";
    const inputClass = "w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-8 py-5 outline-none focus:border-blue-600 focus:bg-white transition-all font-bold text-xl";
    const authBtnBase = "w-full py-6 rounded-3xl font-black text-xl flex items-center justify-center gap-3 transition-all hover:scale-[1.02] active:scale-95 shadow-lg";

    return (
      <div className="min-h-[85vh] flex items-center justify-center px-4">
        {authStep === AuthSubView.CHOICE && (
          <div className={cardClass}>
            <div className="text-center mb-12">
              <h2 className="text-4xl font-black text-slate-900 mb-2 uppercase tracking-tighter italic">RAJ<span className="text-blue-600">QUIZER</span></h2>
              <p className="text-slate-400 font-bold tracking-[0.2em] text-[10px] uppercase opacity-70">Authentic Board PYQs</p>
            </div>
            <div className="space-y-4">
              <button onClick={() => setAuthStep(AuthSubView.LOGIN)} className={`${authBtnBase} bg-blue-600 text-white shadow-blue-100 hover:bg-blue-700`}>
                 LOGIN <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M11 16l-4-4m0 0l4-4m-4 4h14" /></svg>
              </button>
              <button onClick={() => setAuthStep(AuthSubView.SIGNUP)} className={`${authBtnBase} bg-slate-900 text-white shadow-slate-100 hover:bg-slate-800`}>
