import { GoogleGenAI, Type } from "@google/genai";
import { Question } from "../types.ts";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function fetchPYQs(params: {
  count: number;
  subject?: string;
  topic?: string;
  isMix?: boolean;
  testNumber?: number;
  examContext?: string;
}): Promise<Question[]> {
  const { count, subject, topic, isMix, testNumber, examContext } = params;

  const prompt = `ACT AS A RAJASTHAN EXAM DATABASE EXPERT.
  Task: Retrieve ${count} UNIQUE REAL PREVIOUS YEAR QUESTIONS (PYQs) from RSSB (rssb.rajasthan.gov.in) and RPSC (rpsc.rajasthan.gov.in) exam papers.

  ${examContext ? `SPECIFIC EXAM SOURCE: ${examContext}. You MUST provide the actual questions from this specific paper.` : `CONTEXT: This is for ${topic || subject || 'Rajasthan GK'} - PRACTICE SET #${testNumber || 1}.`}

  Strict Rules:
  1. ALL QUESTIONS MUST BE REAL AND VERIFIABLE. NO AI-GENERATED OR DUMMY CONTENT.
  2. Language: Questions and options A, B, C, D must be in Hindi.
  3. Option E must ALWAYS be "अनुत्तरित प्रश्न (Skip Question)".
  4. Marking: Correct=A/B/C/D.
  5. Ensure data accuracy as per official Rajasthan records.

  JSON Structure:
  {
    "id": "pyq_${examContext ? 'exam' : (testNumber || 1)}_[unique_hash]",
    "question": "[Hindi Text]",
    "options": {"A":"..","B":"..","C":"..","D":"..","E":"अनुत्तरित प्रश्न (Skip Question)"},
    "correctAnswer": "A/B/C/D",
    "examName": "${examContext || '[Real Exam Name like RSSB CET, LDC, REET, RAS, Patwar]'}",
    "examYear": ${examContext?.includes('2022') ? 2022 : '[Year between 2015-2026]'},
    "subject": "${subject || 'Rajasthan GK'}"
  }

  Topic/Context: ${topic ? `Focus on topic: ${topic}.` : (isMix ? 'Randomly mix different subjects' : 'Rajasthan GK subjects')}.
  Return exactly ${count} objects in a JSON array.`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              id: { type: Type.STRING },
              question: { type: Type.STRING },
              options: {
                type: Type.OBJECT,
                properties: {
                  A: { type: Type.STRING },
                  B: { type: Type.STRING },
                  C: { type: Type.STRING },
                  D: { type: Type.STRING },
                  E: { type: Type.STRING },
                },
                required: ['A', 'B', 'C', 'D', 'E']
              },
              correctAnswer: { type: Type.STRING, enum: ['A', 'B', 'C', 'D', 'E'] },
              examName: { type: Type.STRING },
              examYear: { type: Type.NUMBER },
              subject: { type: Type.STRING },
            },
            required: ['id', 'question', 'options', 'correctAnswer', 'examName', 'examYear', 'subject']
          }
        }
      }
    });

    let jsonStr = response.text.trim();
    // Clean up markdown if present
    if (jsonStr.startsWith("```json")) {
      jsonStr = jsonStr.replace(/^```json\s*/, "").replace(/\s*```$/, "");
    } else if (jsonStr.startsWith("```")) {
      jsonStr = jsonStr.replace(/^```\s*/, "").replace(/\s*```$/, "");
    }

    const parsed = JSON.parse(jsonStr);
    return parsed;
  } catch (error) {
    console.error("Gemini PYQ Fetch Error:", error);
    throw error; // Rethrow to handle in the component
  }
}

