            </div>
          </>
        )}
        {authStep === AuthSubView.SIGNUP && (
          <>
            <button onClick={() => setAuthStep(AuthSubView.CHOICE)} className="mb-6 text-slate-400 font-bold text-xs uppercase tracking-widest hover:text-blue-600">BACK</button>
            <h2 className="text-3xl font-black text-slate-900 mb-8 uppercase tracking-tighter">Sign Up</h2>
            <form onSubmit={handleSignup} className="space-y-4">
              <input type="tel" value={phone} onChange={e => setPhone(e.target.value.replace(/\D/g, '').slice(0, 10))} placeholder="10 Digit Number" className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-8 py-5 outline-none focus:border-blue-600 font-bold text-xl" required />
              <input type="password" value={password} onChange={e => setPassword(e.target.value)} placeholder="Password" className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-8 py-5 outline-none focus:border-blue-600 font-bold text-xl" required />
              <input type="password" value={confirmPassword} onChange={e => setConfirmPassword(e.target.value)} placeholder="Confirm Password" className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-8 py-5 outline-none focus:border-blue-600 font-bold text-xl" required />
              {password !== confirmPassword && confirmPassword !== '' && <p className="text-rose-500 text-[10px] font-black uppercase tracking-widest ml-1">Password not match</p>}
              <button type="submit" className="w-full bg-slate-900 text-white py-6 rounded-2xl font-black text-xl shadow-xl mt-4">Create Account</button>
            </form>
          </>
        )}
        {authStep === AuthSubView.LOGIN && (
          <>
            <button onClick={() => setAuthStep(AuthSubView.CHOICE)} className="mb-6 text-slate-400 font-bold text-xs uppercase tracking-widest hover:text-blue-600">BACK</button>
            <h2 className="text-3xl font-black text-slate-900 mb-8 uppercase tracking-tighter">Login</h2>
            <form onSubmit={handleLogin} className="space-y-4">
              <input type="tel" value={phone} onChange={e => setPhone(e.target.value.replace(/\D/g, '').slice(0, 10))} placeholder="Phone Number" className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-8 py-5 outline-none focus:border-blue-600 font-bold text-xl" required />
              <input type="password" value={password} onChange={e => setPassword(e.target.value)} placeholder="••••••••" className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-8 py-5 outline-none focus:border-blue-600 font-bold text-xl" required />
              {loginError && <p className="text-rose-500 text-[10px] font-black uppercase tracking-widest ml-1">{loginError}</p>}
              <button type="submit" className="w-full bg-blue-600 text-white py-6 rounded-2xl font-black text-xl mt-4 shadow-xl">Login Now</button>
            </form>
          </>
        )}
      </div>
    </div>
  );

  const renderHome = () => (
    <div className="animate-fadeIn max-w-6xl mx-auto space-y-12">
      <section className="text-center space-y-4">
        <h1 className="text-5xl md:text-7xl font-black text-slate-900 tracking-tight">Target <span className="text-blue-600 uppercase">RSSB</span> Exams</h1>
        <p className="text-slate-500 text-lg md:text-xl max-w-2xl mx-auto font-medium">Official PYQ portal for Rajasthan Board Exam preparation. Real Board questions from 2015-2026.</p>
      </section>
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        <div onClick={() => navigateTo(AppView.QUIZ_MIX_MENU)} className="group bg-gradient-to-br from-indigo-950 to-slate-900 p-10 rounded-[4rem] shadow-2xl hover:-translate-y-2 transition-all cursor-pointer text-white relative overflow-hidden">
          <h3 className="text-3xl font-black mb-3 uppercase tracking-tighter">Mixed Mock</h3>
          <p className="text-indigo-200/60 mb-8 leading-relaxed">Full Syllabus Mock Tests.</p>
          <div className="text-amber-400 font-black flex items-center gap-2 uppercase text-[10px] tracking-[0.2em]">Start Practice</div>
        </div>
        <div onClick={() => navigateTo(AppView.QUIZ_TOPIC_MENU)} className="group bg-gradient-to-br from-emerald-950 to-slate-900 p-10 rounded-[4rem] shadow-2xl hover:-translate-y-2 transition-all cursor-pointer text-white relative overflow-hidden">
          <h3 className="text-3xl font-black mb-3 uppercase tracking-tighter">Topic PYQs</h3>
          <p className="text-emerald-100/60 mb-8 leading-relaxed">Focus on specific units.</p>
          <div className="text-teal-400 font-black flex items-center gap-2 uppercase text-[10px] tracking-[0.2em]">Explore Units</div>
        </div>
        <div onClick={() => navigateTo(AppView.EXAM_MENU)} className="group bg-gradient-to-br from-blue-950 to-slate-900 p-10 rounded-[4rem] shadow-2xl hover:-translate-y-2 transition-all cursor-pointer text-white relative overflow-hidden">
          <h3 className="text-3xl font-black mb-3 uppercase tracking-tighter">Exam Portal</h3>
          <p className="text-blue-100/60 mb-8 leading-relaxed">Original Board papers.</p>
          <div className="text-sky-400 font-black flex items-center gap-2 uppercase text-[10px] tracking-[0.2em]">Full Papers</div>
        </div>
      </div>
    </div>
  );

  const renderExamMenu = () => {
    const gkExams = [
      { name: "Lab Assistant 2022 - Paper I (GK)", year: 2022, context: "RSSB Lab Assistant 2022 Paper 1 General Knowledge Official" },
      { name: "RSSB CET Graduate Level", year: 2024, context: "CET Graduate Level 2024 Official Paper" },
      { name: "RSSB LDC Exam", year: 2024, context: "LDC 2024 Official Exam" }
    ];

    const scienceExams = [
      { name: "Lab Assistant 2022 - Paper II (Science)", year: 2022, context: "RSSB Lab Assistant 2022 Paper 2 Science Official" }
    ];

    return (
      <div className="animate-fadeIn space-y-12">
        <section>
          <h3 className="text-2xl font-black text-slate-800 uppercase tracking-tight mb-8">Rajasthan GK (Paper-I)</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {gkExams.map((exam, i) => (
              <div key={i} className="bg-white rounded-[3.5rem] border border-slate-200 p-12 hover:shadow-2xl transition-all border-b-8 hover:border-b-blue-600">
                <div className="text-[10px] font-black uppercase tracking-[0.3em] text-slate-400 mb-2">{exam.year}</div>
                <h3 className="text-2xl font-black text-slate-900 mb-8 leading-tight">{exam.name}</h3>
                <button onClick={() => startQuiz(QuizType.EXAM, exam.name, { testId: `exam-gk-${exam.name.replace(/\s+/g, '_')}`, examContext: exam.context, count: 50 })} className="w-full py-6 rounded-3xl font-black bg-slate-900 text-white hover:bg-blue-600 transition-all">Start Paper</button>
              </div>
            ))}
          </div>
        </section>

        <section>
          <h3 className="text-2xl font-black text-slate-800 uppercase tracking-tight mb-8">Science (Paper-II)</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {scienceExams.map((exam, i) => (
              <div key={i} className="bg-white rounded-[3.5rem] border border-slate-200 p-12 hover:shadow-2xl transition-all border-b-8 hover:border-b-emerald-600">
                <div className="text-[10px] font-black uppercase tracking-[0.3em] text-slate-400 mb-2">{exam.year}</div>
                <h3 className="text-2xl font-black text-slate-900 mb-8 leading-tight">{exam.name}</h3>
                <button onClick={() => startQuiz(QuizType.EXAM, exam.name, { testId: `exam-subject-${exam.name.replace(/\s+/g, '_')}`, examContext: exam.context, count: 50 })} className="w-full py-6 rounded-3xl font-black bg-slate-900 text-white hover:bg-emerald-600 transition-all">Start Paper</button>
              </div>
            ))}
          </div>
        </section>
      </div>
    );
  };

  return (
    <Layout onHomeClick={() => navigateTo(AppView.HOME)} onProfileClick={() => navigateTo(AppView.PROFILE)} onLogout={handleLogout} isLoggedIn={isLoggedIn}>
      {loading ? (
        <div className="flex flex-col items-center justify-center min-h-[60vh]">
          <div className="w-24 h-24 border-[12px] border-blue-600 border-t-transparent rounded-full animate-spin mb-10"></div>
          <h2 className="text-3xl font-black text-slate-900 mb-2 uppercase tracking-tighter">Loading Questions...</h2>
        </div>
      ) : (
        <>
          {view === AppView.AUTH && renderAuth()}
          {view === AppView.HOME && renderHome()}
          {view === AppView.EXAM_MENU && renderExamMenu()}
          {view === AppView.QUIZ_ACTIVE && activeSession && (
            <QuizEngine session={activeSession} onComplete={onQuizComplete} onExit={() => navigateTo(AppView.HOME)} />
          )}
          {view === AppView.SCORECARD && lastResults && (
            <ScoreCard results={lastResults} onReview={() => navigateTo(AppView.REVIEW)} onNextTest={() => navigateTo(AppView.HOME)} onBackHome={() => navigateTo(AppView.HOME)} />
          )}
          {view === AppView.REVIEW && lastResults && (
            <QuizEngine session={lastResults.session} onComplete={() => {}} onExit={() => navigateTo(AppView.SCORECARD)} isReview={true} />
          )}
        </>
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect, useCallback } from 'react';
import Layout from './components/Layout.tsx';
import QuizEngine from './components/QuizEngine.tsx';
import ScoreCard from './components/ScoreCard.tsx';
import { 
  AppView, 
  AuthSubView,
  QuizSession, 
  QuizType, 
  QuizResults,
  AttemptRecord
} from './types.ts';
import { 
  TOPIC_GROUPS,
  TopicGroup,
  MARKING_SCHEME 
} from './constants.ts';
import { fetchPYQs } from './services/geminiService.ts';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.AUTH);
  const [authStep, setAuthStep] = useState<AuthSubView>(AuthSubView.CHOICE);
  const [isLoggedIn, setIsLoggedIn] = useState(false);

  const [phone, setPhone] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  const [activeSession, setActiveSession] = useState<QuizSession | null>(null);
  const [lastResults, setLastResults] = useState<QuizResults | null>(null);
  const [loading, setLoading] = useState(false);
  const [selectedGroup, setSelectedGroup] = useState<TopicGroup | null>(null);
  const [selectedSubtopic, setSelectedSubtopic] = useState<string | null>(null);
  const [completedTests, setCompletedTests] = useState<Set<string>>(new Set());
  const [testHistory, setTestHistory] = useState<AttemptRecord[]>([]);

  const testsPerPage = 200;

  // --- Persistence ---
  useEffect(() => {
    const savedUser = localStorage.getItem('rajquiz_currentUser');
    if (savedUser) {
      setIsLoggedIn(true);
      setView(AppView.HOME);
    }

    const savedProgress = localStorage.getItem('rajquiz_progress');
    if (savedProgress) {
      try {
        setCompletedTests(new Set(JSON.parse(savedProgress)));
      } catch (e) { console.error(e); }
    }

    const savedHistory = localStorage.getItem('rajquiz_history');
    if (savedHistory) {
      try {
        setTestHistory(JSON.parse(savedHistory));
      } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    setLoginError('');
  }, [authStep]);

  // --- Auth Handlers ---
  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const users = JSON.parse(localStorage.getItem('rajquiz_users') || '{}');
    const user = users[phone];
    if (!user) {
      setLoginError("यह नंबर रजिस्टर्ड नहीं है।");
      return;
    }
    if (user.password === password) {
      localStorage.setItem('rajquiz_currentUser', phone);
      setIsLoggedIn(true);
      setView(AppView.HOME);
      setPassword('');
    } else {
      setLoginError("गलत पासवर्ड! (Wrong password)");
    }
  };

  const handleSignup = (e: React.FormEvent) => {
    e.preventDefault();
    if (phone.length !== 10) return alert("10 अंकों का नंबर डालें");
    if (password !== confirmPassword) return; // UI shows error
    const users = JSON.parse(localStorage.getItem('rajquiz_users') || '{}');
    if (users[phone]) return alert("यह नंबर पहले से है।");
    users[phone] = { password };
    localStorage.setItem('rajquiz_users', JSON.stringify(users));
    alert("अकाउंट बन गया!");
    setAuthStep(AuthSubView.LOGIN);
  };

  const handleLogout = () => {
    if (window.confirm("लॉगआउट करना चाहते हैं?")) {
      localStorage.removeItem('rajquiz_currentUser');
      setIsLoggedIn(false);
      setView(AppView.AUTH);
      setAuthStep(AuthSubView.CHOICE);
    }
  };

  const navigateTo = (newView: AppView) => {
    setView(newView);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  // --- Quiz Engine ---
  const startQuiz = useCallback(async (type: QuizType, title: string, options: any = {}) => {
    const testId = options.testId || `${type}-${title.replace(/\s+/g, '_')}`;
    const cached = localStorage.getItem(`qcache_${testId}`);

    if (cached) {
      const q = JSON.parse(cached);
      setActiveSession({
        type, title, questions: q, currentQuestionIndex: 0, 
        userAnswers: {}, startTime: Date.now(), durationInMinutes: 60, completed: false
      } as any);
      navigateTo(AppView.QUIZ_ACTIVE);
      return;
    }

    setLoading(true);
    try {
      const questions = await fetchPYQs({ ...options, count: options.count || 25 });
      localStorage.setItem(`qcache_${testId}`, JSON.stringify(questions));
      setActiveSession({
        type, title, questions, currentQuestionIndex: 0,
        userAnswers: {}, startTime: Date.now(), durationInMinutes: 60, completed: false
      } as any);
      navigateTo(AppView.QUIZ_ACTIVE);
    } catch (err) {
      alert("नेटवर्क एरर। दोबारा कोशिश करें।");
    } finally {
      setLoading(false);
    }
  }, []);

  const onQuizComplete = (session: QuizSession) => {
    let score = 0, correct = 0, incorrect = 0, skipped = 0, unattempted = 0;
    session.questions.forEach(q => {
      const ans = session.userAnswers[q.id];
      if (!ans) { score += MARKING_SCHEME.UNATTEMPTED; unattempted++; }
      else if (ans === 'E') skipped++;
      else if (ans === q.correctAnswer) { score += MARKING_SCHEME.CORRECT; correct++; }
      else { score += MARKING_SCHEME.WRONG; incorrect++; }
    });
    const results = { score, correctCount: correct, incorrectCount: incorrect, skippedCount: skipped, unattemptedCount: unattempted, totalQuestions: session.questions.length, session };
    setLastResults(results as any);
    navigateTo(AppView.SCORECARD);
  };

  // --- Render Functions ---
  const renderAuth = () => (
    <div className="min-h-[70vh] flex items-center justify-center p-4">
      <div className="bg-white p-8 md:p-12 rounded-[3rem] shadow-2xl w-full max-w-md animate-fadeIn">
        {authStep === AuthSubView.CHOICE ? (
          <div className="text-center space-y-6">
