          <h3 className="text-2xl font-black mb-1 uppercase tracking-tighter">{g.name}</h3>
          <p className="text-slate-400 font-bold text-xs uppercase">{g.subtopics.length} Topics</p>
        </button>
      ))}
    </div>
  );

  const renderSubtopicMenu = () => (
    <div className="space-y-4 animate-fadeIn">
      <h2 className="text-2xl font-black uppercase mb-6">{selectedGroup?.name}</h2>
      <div className="grid gap-3">
        {selectedGroup?.subtopics.map(s => (
          <button key={s} onClick={() => startQuiz(QuizType.TOPIC, s, { topic: s })} className="p-5 bg-white border rounded-2xl text-left hover:bg-emerald-50 hindi-text font-bold">
            {s}
          </button>
        ))}
      </div>
    </div>
  );

