          <div><div className="text-2xl font-black">{testHistory.length}</div><div className="text-[10px] font-bold text-slate-400 uppercase">History</div></div>
          <button onClick={handleLogout} className="px-6 py-2 bg-rose-50 text-rose-600 rounded-xl font-bold text-xs">LOGOUT</button>
        </div>
      </div>
    </div>
  );

  // --- Main Router ---
  return (
    <Layout 
      onHomeClick={() => navigateTo(AppView.HOME)} 
      onProfileClick={() => navigateTo(AppView.PROFILE)} 
      onLogout={handleLogout} 
      isLoggedIn={isLoggedIn}
    >
      {loading ? (
        <div className="min-h-[50vh] flex flex-col items-center justify-center">
          <div className="w-16 h-16 border-8 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
          <p className="mt-6 font-black uppercase text-slate-400 tracking-widest animate-pulse">Fetching PYQs...</p>
        </div>
      ) : (
        <>
          {view === AppView.AUTH && renderAuth()}
          {view === AppView.HOME && renderHome()}
          {view === AppView.QUIZ_MIX_MENU && renderMixMenu()}
          {view === AppView.QUIZ_TOPIC_MENU && renderTopicMenu()}
          {view === AppView.QUIZ_SUBTOPIC_MENU && renderSubtopicMenu()}
          {view === AppView.PROFILE && renderProfile()}
          {view === AppView.EXAM_MENU && renderHome() /* Reusing home for now as simple papers list */}

          {view === AppView.QUIZ_ACTIVE && activeSession && (
            <QuizEngine session={activeSession} onComplete={onQuizComplete} onExit={() => navigateTo(AppView.HOME)} />
          )}
          {view === AppView.SCORECARD && lastResults && (
            <ScoreCard 
              results={lastResults} 
              onReview={() => navigateTo(AppView.REVIEW)} 
              onNextTest={() => navigateTo(AppView.HOME)} 
              onBackHome={() => navigateTo(AppView.HOME)} 
            />
          )}
          {view === AppView.REVIEW && lastResults && (
            <QuizEngine session={lastResults.session} onComplete={() => {}} onExit={() => navigateTo(AppView.SCORECARD)} isReview={true} />
          )}
        </>
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect, useCallback } from 'react';
import Layout from './components/Layout.tsx';
import QuizEngine from './components/QuizEngine.tsx';
import ScoreCard from './components/ScoreCard.tsx';
import { 
  AppView, 
  AuthSubView,
  QuizSession, 
  QuizType, 
  QuizResults,
  AttemptRecord
} from './types.ts';
import { 
  TOPIC_GROUPS,
  TopicGroup,
  MARKING_SCHEME 
} from './constants.ts';
import { fetchPYQs } from './services/geminiService.ts';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.AUTH);
  const [authStep, setAuthStep] = useState<AuthSubView>(AuthSubView.CHOICE);
  const [isLoggedIn, setIsLoggedIn] = useState(false);

  const [phone, setPhone] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  const [activeSession, setActiveSession] = useState<QuizSession | null>(null);
  const [lastResults, setLastResults] = useState<QuizResults | null>(null);
  const [loading, setLoading] = useState(false);
  const [selectedGroup, setSelectedGroup] = useState<TopicGroup | null>(null);
  const [selectedSubtopic, setSelectedSubtopic] = useState<string | null>(null);
  const [completedTests, setCompletedTests] = useState<Set<string>>(new Set());
  const [testHistory, setTestHistory] = useState<AttemptRecord[]>([]);

  const testsPerPage = 200;

  // --- Persistence ---
  useEffect(() => {
    const savedUser = localStorage.getItem('rajquiz_currentUser');
    if (savedUser) {
      setIsLoggedIn(true);
      setView(AppView.HOME);
    }

    const savedProgress = localStorage.getItem('rajquiz_progress');
    if (savedProgress) {
      try {
        setCompletedTests(new Set(JSON.parse(savedProgress)));
      } catch (e) { console.error(e); }
    }

    const savedHistory = localStorage.getItem('rajquiz_history');
    if (savedHistory) {
      try {
        setTestHistory(JSON.parse(savedHistory));
      } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    setLoginError('');
  }, [authStep]);

  // --- Auth Handlers ---
  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const users = JSON.parse(localStorage.getItem('rajquiz_users') || '{}');
    const user = users[phone];
    if (!user) {
      setLoginError("यह नंबर रजिस्टर्ड नहीं है।");
      return;
    }
    if (user.password === password) {
      localStorage.setItem('rajquiz_currentUser', phone);
      setIsLoggedIn(true);
      setView(AppView.HOME);
      setPassword('');
    } else {
      setLoginError("गलत पासवर्ड! (Wrong password)");
    }
  };

  const handleSignup = (e: React.FormEvent) => {
    e.preventDefault();
    if (phone.length !== 10) return alert("10 अंकों का नंबर डालें");
    if (password !== confirmPassword) return; 
    const users = JSON.parse(localStorage.getItem('rajquiz_users') || '{}');
    if (users[phone]) return alert("यह नंबर पहले से है।");
    users[phone] = { password };
    localStorage.setItem('rajquiz_users', JSON.stringify(users));
    alert("अकाउंट बन गया! अब लॉगिन करें।");
    setAuthStep(AuthSubView.LOGIN);
  };

  const handleLogout = () => {
    if (window.confirm("लॉगआउट करना चाहते हैं?")) {
      localStorage.removeItem('rajquiz_currentUser');
      setIsLoggedIn(false);
      setView(AppView.AUTH);
      setAuthStep(AuthSubView.CHOICE);
    }
  };

  const navigateTo = (newView: AppView) => {
    setView(newView);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  // --- Quiz Engine ---
  const startQuiz = useCallback(async (type: QuizType, title: string, options: any = {}) => {
    const testId = options.testId || `${type}-${title.replace(/\s+/g, '_')}`;
    const cached = localStorage.getItem(`qcache_${testId}`);

    if (cached) {
      const q = JSON.parse(cached);
      setActiveSession({
        type, title, questions: q, currentQuestionIndex: 0, 
        userAnswers: {}, startTime: Date.now(), durationInMinutes: 60, completed: false
      } as any);
      navigateTo(AppView.QUIZ_ACTIVE);
      return;
    }

    setLoading(true);
    try {
      const questions = await fetchPYQs({ ...options, count: options.count || 25 });
      localStorage.setItem(`qcache_${testId}`, JSON.stringify(questions));
      setActiveSession({
        type, title, questions, currentQuestionIndex: 0,
        userAnswers: {}, startTime: Date.now(), durationInMinutes: 60, completed: false
      } as any);
      navigateTo(AppView.QUIZ_ACTIVE);
    } catch (err) {
      alert("नेटवर्क एरर। दोबारा कोशिश करें।");
    } finally {
      setLoading(false);
    }
  }, []);

  const onQuizComplete = (session: QuizSession) => {
    let score = 0, correct = 0, incorrect = 0, skipped = 0, unattempted = 0;
    session.questions.forEach(q => {
      const ans = session.userAnswers[q.id];
      if (!ans) { score += MARKING_SCHEME.UNATTEMPTED; unattempted++; }
      else if (ans === 'E') skipped++;
      else if (ans === q.correctAnswer) { score += MARKING_SCHEME.CORRECT; correct++; }
      else { score += MARKING_SCHEME.WRONG; incorrect++; }
    });
    const results = { score, correctCount: correct, incorrectCount: incorrect, skippedCount: skipped, unattemptedCount: unattempted, totalQuestions: session.questions.length, session };
    setLastResults(results as any);
    navigateTo(AppView.SCORECARD);
  };

  // --- Render Functions ---
  const renderAuth = () => (
    <div className="min-h-[70vh] flex items-center justify-center p-4">
      <div className="bg-white p-8 md:p-12 rounded-[3rem] shadow-2xl w-full max-w-md animate-fadeIn border border-slate-50">
        {authStep === AuthSubView.CHOICE ? (
          <div className="text-center space-y-8">
            <div>
              <h2 className="text-4xl font-black text-slate-900 tracking-tighter">RAJ<span className="text-blue-600">QUIZER</span></h2>
