            </div>
            <div className="space-y-4">
              <button onClick={() => setAuthStep(AuthSubView.LOGIN)} className="w-full py-5 bg-blue-600 text-white rounded-2xl font-bold text-lg shadow-xl shadow-blue-100 transition-all hover:bg-blue-700 active:scale-95">LOGIN</button>
              <button onClick={() => setAuthStep(AuthSubView.SIGNUP)} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-bold text-lg transition-all hover:bg-slate-800 active:scale-95">SIGN UP</button>
            </div>
          </div>
        ) : authStep === AuthSubView.LOGIN ? (
          <form onSubmit={handleLogin} className="space-y-4">
            <h3 className="text-3xl font-black mb-2 tracking-tight">Login</h3>
            <p className="text-slate-400 text-sm mb-6">Enter your credentials to access tests.</p>
            <input type="tel" value={phone} onChange={e => setPhone(e.target.value)} placeholder="10 Digit Phone" className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-600 outline-none font-bold transition-all" required />
            <input type="password" value={password} onChange={e => setPassword(e.target.value)} placeholder="Password" className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-600 outline-none font-bold transition-all" required />
            {loginError && <p className="text-rose-500 text-[10px] font-black uppercase tracking-widest ml-1 animate-pulse">{loginError}</p>}
            <button type="submit" className="w-full py-5 bg-blue-600 text-white rounded-2xl font-bold text-lg shadow-xl shadow-blue-100 mt-4 transition-all hover:bg-blue-700 active:scale-95">Log In Now</button>

            <div className="pt-8 border-t border-slate-50 text-center space-y-3">
              <p className="text-slate-400 font-bold text-xs uppercase tracking-widest">New to RajQuizer?</p>
              <button type="button" onClick={() => setAuthStep(AuthSubView.SIGNUP)} className="text-blue-600 font-black text-sm hover:underline">CREATE AN ACCOUNT</button>
            </div>
          </form>
        ) : (
          <form onSubmit={handleSignup} className="space-y-4">
            <h3 className="text-3xl font-black mb-2 tracking-tight">Sign Up</h3>
            <p className="text-slate-400 text-sm mb-6">Create an account to track your scores.</p>
            <input type="tel" value={phone} onChange={e => setPhone(e.target.value)} placeholder="10 Digit Phone" className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-600 outline-none font-bold transition-all" required />
            <input type="password" value={password} onChange={e => setPassword(e.target.value)} placeholder="Create Password" className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-600 outline-none font-bold transition-all" required />
            <input type="password" value={confirmPassword} onChange={e => setConfirmPassword(e.target.value)} placeholder="Confirm Password" className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-600 outline-none font-bold transition-all" required />
            {password !== confirmPassword && confirmPassword !== '' && <p className="text-rose-500 text-[10px] font-black uppercase tracking-widest ml-1">Passwords do not match</p>}
            <button type="submit" className="w-full py-5 bg-slate-900 text-white rounded-2xl font-bold text-lg mt-4 shadow-xl transition-all hover:bg-slate-800 active:scale-95">Register Student</button>

            <div className="pt-8 border-t border-slate-50 text-center space-y-3">
              <p className="text-slate-400 font-bold text-xs uppercase tracking-widest">Already have an account?</p>
              <button type="button" onClick={() => setAuthStep(AuthSubView.LOGIN)} className="text-blue-600 font-black text-sm hover:underline">LOGIN HERE</button>
            </div>
          </form>
        )}
      </div>
    </div>
  );

  const renderHome = () => (
    <div className="space-y-12 animate-fadeIn max-w-6xl mx-auto">
      <div className="text-center space-y-4">
        <h1 className="text-5xl md:text-7xl font-black text-slate-900 tracking-tighter">Target <span className="text-blue-600">RSSB</span> Exams</h1>
        <p className="text-slate-500 font-medium text-lg md:text-xl max-w-2xl mx-auto">Authentic RPSC & RSSB Previous Year Questions from 2015 to 2026. Practice with real exam pattern.</p>
      </div>
      <div className="grid md:grid-cols-3 gap-8">
        {[
          { title: "Mixed Mocks", view: AppView.QUIZ_MIX_MENU, color: "blue", desc: "Full syllabus practice sets." },
          { title: "Topic Wise", view: AppView.QUIZ_TOPIC_MENU, color: "emerald", desc: "Focus on History, Geo, Culture." },
          { title: "Board Papers", view: AppView.EXAM_MENU, color: "indigo", desc: "Original RSSB exam papers." }
        ].map(card => (
          <button key={card.title} onClick={() => navigateTo(card.view)} className={`p-10 rounded-[4rem] text-left bg-white border-2 border-slate-100 hover:border-${card.color}-600 transition-all shadow-sm hover:shadow-2xl hover:-translate-y-2 group`}>
            <div className={`w-14 h-14 bg-${card.color}-50 rounded-2xl mb-8 flex items-center justify-center transition-all group-hover:scale-110`}>
              <div className={`w-6 h-6 bg-${card.color}-600 rounded-lg opacity-40`}></div>
            </div>
            <h3 className="text-3xl font-black mb-3 uppercase tracking-tighter">{card.title}</h3>
            <p className="text-slate-400 font-medium">{card.desc}</p>
            <div className={`mt-8 flex items-center gap-2 text-${card.color}-600 font-black uppercase text-[10px] tracking-widest opacity-0 group-hover:opacity-100 transition-all`}>Start Practice <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M13 7l5 5m0 0l-5 5m5-5H6" /></svg></div>
          </button>
        ))}
      </div>
    </div>
  );

  const renderMixMenu = () => (
    <div className="space-y-10 animate-fadeIn max-w-4xl mx-auto">
      <div className="flex items-center justify-between">
        <h2 className="text-4xl font-black uppercase tracking-tighter">Mixed Practice Sets</h2>
        <button onClick={() => navigateTo(AppView.HOME)} className="text-slate-400 font-black text-xs uppercase hover:text-blue-600 transition-all">Back</button>
      </div>
      <div className="grid gap-4">
        {[1, 2, 3, 4, 5].map(n => (
          <button key={n} onClick={() => startQuiz(QuizType.MIX, `Mixed Mock Set #${n}`, { testNumber: n })} className="p-8 bg-white border-2 border-slate-100 rounded-[2.5rem] flex items-center justify-between hover:border-blue-600 hover:shadow-xl transition-all group">
            <div className="flex items-center gap-6">
              <div className="w-16 h-16 bg-blue-600 text-white rounded-2xl flex items-center justify-center font-black text-2xl shadow-lg shadow-blue-100 transition-all group-hover:scale-110">{n}</div>
              <div className="text-left"><h4 className="font-black text-2xl tracking-tight">Mixed Set {n}</h4><p className="text-xs text-slate-400 font-bold uppercase tracking-widest">25 PYQs • 60 Mins • Marking: +2, -0.33</p></div>
            </div>
            <span className="font-black text-blue-600 text-sm tracking-widest uppercase">START TEST</span>
          </button>
        ))}
      </div>
