      </div>
      <div className="grid gap-3">
        {selectedGroup?.subtopics.map(s => (
          <button key={s} onClick={() => startQuiz(QuizType.TOPIC, s, { topic: s })} className="p-8 bg-white border-2 border-slate-100 rounded-[2rem] text-left hover:bg-emerald-50 hover:border-emerald-200 transition-all hindi-text font-bold text-xl leading-relaxed flex items-center justify-between group">
            {s}
            <svg className="w-6 h-6 text-emerald-300 opacity-0 group-hover:opacity-100 transition-all" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M13 7l5 5m0 0l-5 5m5-5H6" /></svg>
          </button>
        ))}
      </div>
    </div>
  );

  const renderProfile = () => (
    <div className="max-w-3xl mx-auto space-y-8 animate-fadeIn">
      <div className="bg-white p-12 rounded-[4rem] shadow-2xl border border-slate-100 relative overflow-hidden">
        <div className="absolute top-0 right-0 w-32 h-32 bg-blue-600/5 rounded-full -mr-16 -mt-16"></div>
        <div className="relative z-10">
          <div className="flex items-center gap-4 mb-8">
            <div className="w-16 h-16 bg-blue-600 rounded-3xl flex items-center justify-center text-white text-2xl font-black">R</div>
            <div>
              <h2 className="text-4xl font-black tracking-tight">{phone}</h2>
              <p className="text-slate-400 text-xs font-bold uppercase tracking-[0.2em] mt-1">Student Portal • Active</p>
            </div>
          </div>
          <div className="grid grid-cols-2 gap-6 pt-10 border-t border-slate-50">
            <div className="bg-slate-50 p-6 rounded-[2rem] text-center">
              <div className="text-3xl font-black text-slate-900">{completedTests.size}</div>
              <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-1">Topics Mastered</div>
            </div>
            <div className="bg-slate-50 p-6 rounded-[2rem] text-center">
              <div className="text-3xl font-black text-slate-900">{testHistory.length}</div>
              <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-1">Total Attempts</div>
            </div>
          </div>
          <button onClick={handleLogout} className="w-full mt-10 py-4 bg-rose-50 text-rose-600 rounded-2xl font-black text-xs uppercase tracking-widest transition-all hover:bg-rose-600 hover:text-white">Logout Account</button>
        </div>
      </div>
    </div>
  );

  // --- Main Router ---
  return (
    <Layout 
      onHomeClick={() => navigateTo(AppView.HOME)} 
      onProfileClick={() => navigateTo(AppView.PROFILE)} 
      onLogout={handleLogout} 
      isLoggedIn={isLoggedIn}
    >
      {loading ? (
        <div className="min-h-[50vh] flex flex-col items-center justify-center">
          <div className="w-20 h-20 border-[10px] border-blue-600 border-t-transparent rounded-full animate-spin"></div>
          <h2 className="mt-10 text-2xl font-black uppercase tracking-widest text-slate-400 animate-pulse">Loading Question Bank...</h2>
        </div>
      ) : (
        <>
          {view === AppView.AUTH && renderAuth()}
          {view === AppView.HOME && renderHome()}
          {view === AppView.QUIZ_MIX_MENU && renderMixMenu()}
          {view === AppView.QUIZ_TOPIC_MENU && renderTopicMenu()}
          {view === AppView.QUIZ_SUBTOPIC_MENU && renderSubtopicMenu()}
          {view === AppView.PROFILE && renderProfile()}
          {view === AppView.EXAM_MENU && renderHome()}

          {view === AppView.QUIZ_ACTIVE && activeSession && (
            <QuizEngine session={activeSession} onComplete={onQuizComplete} onExit={() => navigateTo(AppView.HOME)} />
          )}
          {view === AppView.SCORECARD && lastResults && (
            <ScoreCard 
              results={lastResults} 
              onReview={() => navigateTo(AppView.REVIEW)} 
              onNextTest={() => navigateTo(AppView.HOME)} 
              onBackHome={() => navigateTo(AppView.HOME)} 
            />
          )}
          {view === AppView.REVIEW && lastResults && (
            <QuizEngine session={lastResults.session} onComplete={() => {}} onExit={() => navigateTo(AppView.SCORECARD)} isReview={true} />
          )}
        </>
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect, useCallback } from 'react';
import Layout from './components/Layout.tsx';
import QuizEngine from './components/QuizEngine.tsx';
import ScoreCard from './components/ScoreCard.tsx';
import { 
  AppView, 
  AuthSubView,
  QuizSession, 
  QuizType, 
  QuizResults,
  AttemptRecord
} from './types.ts';
import { 
  TOPIC_GROUPS,
  TopicGroup,
  MARKING_SCHEME 
} from './constants.ts';
import { fetchPYQs } from './services/geminiService.ts';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.AUTH);
  const [authStep, setAuthStep] = useState<AuthSubView>(AuthSubView.CHOICE);
  const [isLoggedIn, setIsLoggedIn] = useState(false);

  const [phone, setPhone] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  const [activeSession, setActiveSession] = useState<QuizSession | null>(null);
  const [lastResults, setLastResults] = useState<QuizResults | null>(null);
  const [loading, setLoading] = useState(false);
  const [selectedGroup, setSelectedGroup] = useState<TopicGroup | null>(null);
  const [selectedSubtopic, setSelectedSubtopic] = useState<string | null>(null);
  const [completedTests, setCompletedTests] = useState<Set<string>>(new Set());
  const [testHistory, setTestHistory] = useState<AttemptRecord[]>([]);

  // --- Persistence ---
  useEffect(() => {
    const savedUser = localStorage.getItem('rajquiz_currentUser');
    if (savedUser) {
      setIsLoggedIn(true);
      setView(AppView.HOME);
    }

    const savedProgress = localStorage.getItem('rajquiz_progress');
    if (savedProgress) {
      try {
        setCompletedTests(new Set(JSON.parse(savedProgress)));
      } catch (e) { console.error(e); }
    }

    const savedHistory = localStorage.getItem('rajquiz_history');
    if (savedHistory) {
      try {
        setTestHistory(JSON.parse(savedHistory));
      } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    setLoginError('');
  }, [authStep]);

  // --- Auth Handlers ---
  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const users = JSON.parse(localStorage.getItem('rajquiz_users') || '{}');
    const user = users[phone];
    if (!user) {
      setLoginError("यह नंबर रजिस्टर्ड नहीं है।");
      return;
    }
    if (user.password === password) {
      localStorage.setItem('rajquiz_currentUser', phone);
      setIsLoggedIn(true);
      setView(AppView.HOME);
      setPassword('');
    } else {
      setLoginError("गलत पासवर्ड! (Wrong password)");
    }
  };

  const handleSignup = (e: React.FormEvent) => {
    e.preventDefault();
    if (phone.length !== 10) return alert("10 अंकों का नंबर डालें");
    if (password !== confirmPassword) return; 
    const users = JSON.parse(localStorage.getItem('rajquiz_users') || '{}');
    if (users[phone]) return alert("यह नंबर पहले से है।");
    users[phone] = { password };
    localStorage.setItem('rajquiz_users', JSON.stringify(users));
    alert("अकाउंट बन गया! अब लॉगिन करें।");
    setAuthStep(AuthSubView.LOGIN);
  };

  const handleLogout = () => {
    if (window.confirm("लॉगआउट करना चाहते हैं?")) {
      localStorage.removeItem('rajquiz_currentUser');
      setIsLoggedIn(false);
      setView(AppView.AUTH);
      setAuthStep(AuthSubView.CHOICE);
    }
  };

  const navigateTo = (newView: AppView) => {
    setView(newView);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  // --- Quiz Engine ---
  const startQuiz = useCallback(async (type: QuizType, title: string, options: any = {}) => {
    const testId = options.testId || `${type}-${title.replace(/\s+/g, '_')}`;
    const cached = localStorage.getItem(`qcache_${testId}`);

    if (cached) {
      const q = JSON.parse(cached);
      setActiveSession({
        type, title, questions: q, currentQuestionIndex: 0, 
        userAnswers: {}, startTime: Date.now(), durationInMinutes: 60, completed: false
      } as any);
      navigateTo(AppView.QUIZ_ACTIVE);
      return;
    }

    setLoading(true);
    try {
      const questions = await fetchPYQs({ ...options, count: options.count || 25 });
      localStorage.setItem(`qcache_${testId}`, JSON.stringify(questions));
      setActiveSession({
        type, title, questions, currentQuestionIndex: 0,
        userAnswers: {}, startTime: Date.now(), durationInMinutes: 60, completed: false
      } as any);
      navigateTo(AppView.QUIZ_ACTIVE);
    } catch (err) {
      alert("नेटवर्क एरर। दोबारा कोशिश करें।");
    } finally {
      setLoading(false);
    }
  }, []);

  const onQuizComplete = (session: QuizSession) => {
    let score = 0, correct = 0, incorrect = 0, skipped = 0, unattempted = 0;
    session.questions.forEach(q => {
      const ans = session.userAnswers[q.id];
      if (!ans) { score += MARKING_SCHEME.UNATTEMPTED; unattempted++; }
      else if (ans === 'E') skipped++;
      else if (ans === q.correctAnswer) { score += MARKING_SCHEME.CORRECT; correct++; }
      else { score += MARKING_SCHEME.WRONG; incorrect++; }
    });
    const results = { score, correctCount: correct, incorrectCount: incorrect, skippedCount: skipped, unattemptedCount: unattempted, totalQuestions: session.questions.length, session };
    setLastResults(results as any);
    navigateTo(AppView.SCORECARD);
  };

  // --- Render Functions ---
  const renderAuth = () => (
    <div className="min-h-[70vh] flex items-center justify-center p-4">
      <div className="bg-white p-8 md:p-12 rounded-[3rem] shadow-2xl w-full max-w-md animate-fadeIn border border-slate-50">
        {authStep === AuthSubView.CHOICE ? (
          <div className="text-center space-y-8">
            <div>
              <h2 className="text-4xl font-black text-slate-900 tracking-tighter text-blue-600">RAJQUIZER.</h2>
              <p className="text-slate-400 font-bold text-[10px] uppercase tracking-widest mt-2">Premium PYQ Portal</p>
            </div>
            <div className="space-y-4">
              <button onClick={() => setAuthStep(AuthSubView.LOGIN)} className="w-full py-5 bg-blue-600 text-white rounded-2xl font-bold text-lg shadow-xl shadow-blue-100 transition-all hover:bg-blue-700 active:scale-95">LOGIN</button>
              <button onClick={() => setAuthStep(AuthSubView.SIGNUP)} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-bold text-lg transition-all hover:bg-slate-800 active:scale-95">SIGN UP</button>
            </div>
          </div>
        ) : authStep === AuthSubView.LOGIN ? (
          <form onSubmit={handleLogin} className="space-y-4">
            <h3 className="text-3xl font-black mb-2 tracking-tight">Login</h3>
            <p className="text-slate-400 text-sm mb-6">Enter your credentials to access tests.</p>
            <input type="tel" value={phone} onChange={e => setPhone(e.target.value)} placeholder="10 Digit Phone" className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-600 outline-none font-bold transition-all" required />
            <input type="password" value={password} onChange={e => setPassword(e.target.value)} placeholder="Password" className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-600 outline-none font-bold transition-all" required />
            {loginError && <p className="text-rose-500 text-[10px] font-black uppercase tracking-widest ml-1 animate-pulse">{loginError}</p>}
            <button type="submit" className="w-full py-5 bg-blue-600 text-white rounded-2xl font-bold text-lg shadow-xl shadow-blue-100 mt-4 transition-all hover:bg-blue-700 active:scale-95">Log In Now</button>

            <div className="pt-8 border-t border-slate-50 text-center space-y-3">
              <p className="text-slate-400 font-bold text-xs uppercase tracking-widest">New to RajQuizer?</p>
              <button type="button" onClick={() => setAuthStep(AuthSubView.SIGNUP)} className="text-blue-600 font-black text-sm hover:underline">CREATE AN ACCOUNT</button>
            </div>
          </form>
        ) : (
          <form onSubmit={handleSignup} className="space-y-4">
            <h3 className="text-3xl font-black mb-2 tracking-tight">Sign Up</h3>
            <p className="text-slate-400 text-sm mb-6">Create an account to track your scores.</p>
            <input type="tel" value={phone} onChange={e => setPhone(e.target.value)} placeholder="10 Digit Phone" className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-600 outline-none font-bold transition-all" required />
            <input type="password" value={password} onChange={e => setPassword(e.target.value)} placeholder="Create Password" className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-600 outline-none font-bold transition-all" required />
            <input type="password" value={confirmPassword} onChange={e => setConfirmPassword(e.target.value)} placeholder="Confirm Password" className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-600 outline-none font-bold transition-all" required />
            {password !== confirmPassword && confirmPassword !== '' && <p className="text-rose-500 text-[10px] font-black uppercase tracking-widest ml-1">Passwords do not match</p>}
            <button type="submit" className="w-full py-5 bg-slate-900 text-white rounded-2xl font-bold text-lg mt-4 shadow-xl transition-all hover:bg-slate-800 active:scale-95">Register Student</button>

            <div className="pt-8 border-t border-slate-50 text-center space-y-3">
              <p className="text-slate-400 font-bold text-xs uppercase tracking-widest">Already have an account?</p>
              <button type="button" onClick={() => setAuthStep(AuthSubView.LOGIN)} className="text-blue-600 font-black text-sm hover:underline">LOGIN HERE</button>
            </div>
          </form>
        )}
      </div>
    </div>
  );

  const renderHome = () => (
    <div className="space-y-12 animate-fadeIn max-w-6xl mx-auto">
      <div className="text-center space-y-4">
        <h1 className="text-5xl md:text-7xl font-black text-slate-900 tracking-tighter uppercase italic">GO <span className="text-blue-600">PREMIUM</span></h1>
        <p className="text-slate-500 font-medium text-lg md:text-xl max-w-2xl mx-auto">Authentic RSSB & RPSC Question Banks. Experience the smoothest exam preparation portal.</p>
      </div>
      <div className="grid md:grid-cols-3 gap-8">
        {[
          { title: "Mixed Mocks", view: AppView.QUIZ_MIX_MENU, gradient: "from-blue-600 to-indigo-900", desc: "Full syllabus practice sets." },
          { title: "Topic Wise", view: AppView.QUIZ_TOPIC_MENU, gradient: "from-emerald-500 to-teal-900", desc: "Focus on History, Geo, Culture." },
          { title: "Board Papers", view: AppView.EXAM_MENU, gradient: "from-slate-800 to-slate-950", desc: "Original Board papers." }
        ].map(card => (
          <button key={card.title} onClick={() => navigateTo(card.view)} className={`p-10 rounded-[4rem] text-left bg-gradient-to-br ${card.gradient} text-white transition-all shadow-xl hover:shadow-2xl hover:-translate-y-2 group relative overflow-hidden`}>
            <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full -mr-16 -mt-16 transition-transform group-hover:scale-150 duration-700"></div>
            <div className="relative z-10">
              <div className="w-14 h-14 bg-white/20 rounded-2xl mb-8 flex items-center justify-center backdrop-blur-md">
                <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
              </div>
              <h3 className="text-3xl font-black mb-3 uppercase tracking-tighter">{card.title}</h3>
              <p className="text-white/70 font-medium text-sm leading-relaxed">{card.desc}</p>
              <div className="mt-8 flex items-center gap-2 text-white font-black uppercase text-[10px] tracking-widest opacity-80">Start Practice <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M13 7l5 5m0 0l-5 5m5-5H6" /></svg></div>
            </div>
          </button>
        ))}
      </div>
    </div>
  );

  const renderExamMenu = () => {
    const exams = [
      { name: "Lab Assistant 2022 (GK)", year: 2022, context: "Lab Assistant 2022 Official Paper", color: "blue" },
      { name: "CET Graduate Level 2024", year: 2024, context: "CET Graduate Level Official Paper", color: "emerald" },
      { name: "LDC Exam 2024", year: 2024, context: "LDC 2024 Exam Official", color: "indigo" }
    ];

    return (
      <div className="space-y-10 animate-fadeIn max-w-6xl mx-auto">
        <div className="flex items-center justify-between">
          <h2 className="text-4xl font-black uppercase tracking-tighter">Official Papers</h2>
          <button onClick={() => navigateTo(AppView.HOME)} className="text-slate-400 font-black text-xs uppercase hover:text-blue-600">Back</button>
        </div>
        <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-8">
          {exams.map((exam, i) => (
            <button 
              key={i} 
              onClick={() => startQuiz(QuizType.EXAM, exam.name, { examContext: exam.context, count: 50 })}
              className="bg-white p-10 rounded-[3.5rem] border-2 border-slate-100 hover:border-blue-600 hover:shadow-2xl transition-all text-left group"
            >
              <div className="text-[10px] font-black uppercase tracking-[0.3em] text-slate-400 mb-4">{exam.year} BOARD EXAM</div>
              <h3 className="text-2xl font-black text-slate-900 mb-8 leading-tight group-hover:text-blue-600 transition-colors">{exam.name}</h3>
              <div className="w-full py-4 bg-slate-50 rounded-2xl text-center font-black text-xs uppercase tracking-widest text-slate-400 group-hover:bg-blue-600 group-hover:text-white transition-all">Start Exam</div>
            </button>
          ))}
        </div>
      </div>
    );
  };

  const renderMixMenu = () => (
    <div className="space-y-10 animate-fadeIn max-w-4xl mx-auto">
      <div className="flex items-center justify-between">
        <h2 className="text-4xl font-black uppercase tracking-tighter">Mixed Practice Sets</h2>
        <button onClick={() => navigateTo(AppView.HOME)} className="text-slate-400 font-black text-xs uppercase hover:text-blue-600 transition-all">Back</button>
      </div>
      <div className="grid gap-4">
        {[1, 2, 3, 4, 5].map(n => (
          <button key={n} onClick={() => startQuiz(QuizType.MIX, `Mixed Mock Set #${n}`, { testNumber: n })} className="p-8 bg-white border-2 border-slate-100 rounded-[2.5rem] flex items-center justify-between hover:border-blue-600 hover:shadow-xl transition-all group">
            <div className="flex items-center gap-6">
              <div className="w-16 h-16 bg-blue-600 text-white rounded-2xl flex items-center justify-center font-black text-2xl shadow-lg shadow-blue-100 transition-all group-hover:scale-110">{n}</div>
              <div className="text-left"><h4 className="font-black text-2xl tracking-tight">Mixed Set {n}</h4><p className="text-xs text-slate-400 font-bold uppercase tracking-widest">25 PYQs • 60 Mins • Marking: +2, -0.33</p></div>
            </div>
            <span className="font-black text-blue-600 text-sm tracking-widest uppercase">START TEST</span>
          </button>
        ))}
      </div>
    </div>
  );

  const renderTopicMenu = () => (
    <div className="space-y-10 animate-fadeIn max-w-5xl mx-auto">
      <div className="flex items-center justify-between">
        <h2 className="text-4xl font-black uppercase tracking-tighter">Topic Wise PYQs</h2>
        <button onClick={() => navigateTo(AppView.HOME)} className="text-slate-400 font-black text-xs uppercase hover:text-blue-600 transition-all">Back</button>
      </div>
      <div className="grid md:grid-cols-2 gap-8">
        {TOPIC_GROUPS.map(g => (
          <button key={g.id} onClick={() => { setSelectedGroup(g); navigateTo(AppView.QUIZ_SUBTOPIC_MENU); }} className="p-12 bg-white border-2 border-slate-100 rounded-[4rem] text-left hover:border-emerald-500 hover:shadow-2xl transition-all group">
            <h3 className="text-3xl font-black mb-2 uppercase tracking-tighter">{g.name}</h3>
            <p className="text-slate-400 font-bold text-xs uppercase tracking-widest">{g.subtopics.length} Key Subtopics Available</p>
            <div className="mt-10 flex items-center gap-2 text-emerald-600 font-black uppercase text-[10px] tracking-widest transition-all">Explore Topics <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M17 8l4 4m0 0l-4 4m4-4H3" /></svg></div>
          </button>
        ))}
      </div>
    </div>
  );

  const renderSubtopicMenu = () => (
    <div className="space-y-8 animate-fadeIn max-w-4xl mx-auto">
      <div className="flex items-center justify-between">
        <h2 className="text-3xl font-black uppercase tracking-tighter">{selectedGroup?.name}</h2>
        <button onClick={() => navigateTo(AppView.QUIZ_TOPIC_MENU)} className="text-slate-400 font-black text-xs uppercase hover:text-blue-600 transition-all">Back</button>
      </div>
      <div className="grid gap-3">
        {selectedGroup?.subtopics.map(s => (
          <button key={s} onClick={() => startQuiz(QuizType.TOPIC, s, { topic: s })} className="p-8 bg-white border-2 border-slate-100 rounded-[2rem] text-left hover:bg-emerald-50 hover:border-emerald-200 transition-all hindi-text font-bold text-xl leading-relaxed flex items-center justify-between group">
            {s}
            <svg className="w-6 h-6 text-emerald-300 opacity-0 group-hover:opacity-100 transition-all" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M13 7l5 5m0 0l-5 5m5-5H6" /></svg>
          </button>
        ))}
      </div>
    </div>
  );

  const renderProfile = () => (
    <div className="max-w-3xl mx-auto space-y-8 animate-fadeIn">
      <div className="bg-white p-12 rounded-[4rem] shadow-2xl border border-slate-100 relative overflow-hidden">
        <div className="absolute top-0 right-0 w-32 h-32 bg-blue-600/5 rounded-full -mr-16 -mt-16"></div>
        <div className="relative z-10">
          <div className="flex items-center gap-4 mb-8">
            <div className="w-16 h-16 bg-blue-600 rounded-3xl flex items-center justify-center text-white text-2xl font-black">R</div>
            <div>
              <h2 className="text-4xl font-black tracking-tight">{phone}</h2>
              <p className="text-slate-400 text-xs font-bold uppercase tracking-[0.2em] mt-1">Student Portal • Active</p>
            </div>
          </div>
          <div className="grid grid-cols-2 gap-6 pt-10 border-t border-slate-50">
            <div className="bg-slate-50 p-6 rounded-[2rem] text-center">
              <div className="text-3xl font-black text-slate-900">{completedTests.size}</div>
              <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-1">Topics Mastered</div>
            </div>
            <div className="bg-slate-50 p-6 rounded-[2rem] text-center">
              <div className="text-3xl font-black text-slate-900">{testHistory.length}</div>
              <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-1">Total Attempts</div>
